use std::fs::File;
use std::path::Path;

use symphonia::core::audio::SampleBuffer;
use symphonia::core::codecs::DecoderOptions;
use symphonia::core::formats::FormatOptions;
use symphonia::core::io::MediaSourceStream;
use symphonia::core::meta::MetadataOptions;
use symphonia::core::probe::Hint;

use crate::buffer::AudioBuffer;
use crate::format::AudioFormat;

/// Read an audio file (WAV, FLAC) into an AudioBuffer.
pub fn read_audio_file(
    path: &Path,
) -> Result<(AudioBuffer, AudioFormat), Box<dyn std::error::Error>> {
    let file = File::open(path)?;
    let mss = MediaSourceStream::new(Box::new(file), Default::default());

    let mut hint = Hint::new();
    if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
        hint.with_extension(ext);
    }

    let probed = symphonia::default::get_probe().format(
        &hint,
        mss,
        &FormatOptions::default(),
        &MetadataOptions::default(),
    )?;

    let mut format = probed.format;
    let track = format.tracks().first().ok_or("no audio tracks found")?;

    let channels = track
        .codec_params
        .channels
        .map(|c| c.count() as u16)
        .unwrap_or(2);
    let sample_rate = track.codec_params.sample_rate.unwrap_or(48000);

    let mut decoder =
        symphonia::default::get_codecs().make(&track.codec_params, &DecoderOptions::default())?;

    let track_id = track.id;
    let mut all_samples: Vec<f32> = Vec::new();

    loop {
        let packet = match format.next_packet() {
            Ok(p) => p,
            Err(symphonia::core::errors::Error::IoError(ref e))
                if e.kind() == std::io::ErrorKind::UnexpectedEof =>
            {
                break;
            }
            Err(e) => return Err(e.into()),
        };

        if packet.track_id() != track_id {
            continue;
        }

        let decoded = decoder.decode(&packet)?;
        let spec = *decoded.spec();
        let duration = decoded.capacity();

        let mut sample_buf = SampleBuffer::<f32>::new(duration as u64, spec);
        sample_buf.copy_interleaved_ref(decoded);
        all_samples.extend_from_slice(sample_buf.samples());
    }

    let audio_format = AudioFormat::new(sample_rate, channels, 0);
    let buffer = AudioBuffer::from_interleaved(all_samples, channels);

    Ok((buffer, audio_format))
}

use std::path::Path;

use hound::{SampleFormat, WavSpec, WavWriter};
use serde::{Deserialize, Serialize};

use crate::buffer::AudioBuffer;
use crate::format::AudioFormat;

/// Supported export audio formats.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum ExportFormat {
    Wav,
    Flac,
}

/// Bit depth options for export.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum BitDepth {
    Int16,
    Int24,
    Float32,
}

/// Export configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExportConfig {
    pub format: ExportFormat,
    pub bit_depth: BitDepth,
    pub sample_rate: u32,
    pub channels: u16,
}

impl Default for ExportConfig {
    fn default() -> Self {
        Self {
            format: ExportFormat::Wav,
            bit_depth: BitDepth::Float32,
            sample_rate: 48000,
            channels: 2,
        }
    }
}

/// Write an AudioBuffer to a WAV file.
pub fn write_wav_file(
    path: &Path,
    buffer: &AudioBuffer,
    format: &AudioFormat,
) -> Result<(), Box<dyn std::error::Error>> {
    let spec = WavSpec {
        channels: buffer.channels(),
        sample_rate: format.sample_rate,
        bits_per_sample: 32,
        sample_format: SampleFormat::Float,
    };

    let mut writer = WavWriter::create(path, spec)?;

    for &sample in buffer.as_interleaved() {
        writer.write_sample(sample)?;
    }

    writer.finalize()?;
    Ok(())
}

/// Write an AudioBuffer to an audio file using the given export configuration.
///
/// Currently supports WAV format with Int16, Int24, and Float32 bit depths.
/// FLAC export is planned for a future release and currently falls back to WAV.
pub fn write_audio_file(
    path: &Path,
    buffer: &AudioBuffer,
    config: &ExportConfig,
) -> Result<(), Box<dyn std::error::Error>> {
    match config.format {
        ExportFormat::Wav | ExportFormat::Flac => {
            // FLAC writing is not supported by hound; fall back to WAV encoding.
            // A future release will add native FLAC export.
            write_wav_with_depth(path, buffer, config)
        }
    }
}

fn write_wav_with_depth(
    path: &Path,
    buffer: &AudioBuffer,
    config: &ExportConfig,
) -> Result<(), Box<dyn std::error::Error>> {
    let (bits_per_sample, sample_format) = match config.bit_depth {
        BitDepth::Int16 => (16, SampleFormat::Int),
        BitDepth::Int24 => (24, SampleFormat::Int),
        BitDepth::Float32 => (32, SampleFormat::Float),
    };

    let spec = WavSpec {
        channels: config.channels,
        sample_rate: config.sample_rate,
        bits_per_sample,
        sample_format,
    };

    let mut writer = WavWriter::create(path, spec)?;

    match config.bit_depth {
        BitDepth::Int16 => {
            for &sample in buffer.as_interleaved() {
                let clamped = sample.clamp(-1.0, 1.0);
                let int_sample = (clamped * 32767.0) as i16;
                writer.write_sample(int_sample)?;
            }
        }
        BitDepth::Int24 => {
            for &sample in buffer.as_interleaved() {
                let clamped = sample.clamp(-1.0, 1.0);
                let int_sample = (clamped * 8_388_607.0) as i32;
                writer.write_sample(int_sample)?;
            }
        }
        BitDepth::Float32 => {
            for &sample in buffer.as_interleaved() {
                writer.write_sample(sample)?;
            }
        }
    }

    writer.finalize()?;
    Ok(())
}

