use rtrb::{Consumer, Producer, RingBuffer};
use shruti_dsp::io::write_wav_file;
use shruti_dsp::{AudioBuffer, AudioFormat};

use std::path::Path;
use std::thread;

/// Manages recording from the RT thread to disk.
///
/// Uses a lock-free ring buffer: the RT callback pushes samples
/// into the producer, and a background thread drains the consumer
/// and writes to a WAV file when recording stops.
pub struct RecordManager {
    producer: Producer<f32>,
    accumulator_handle: Option<thread::JoinHandle<Vec<f32>>>,
}

impl RecordManager {
    /// Create a new RecordManager with the given ring buffer capacity (in samples).
    pub fn new(capacity: usize) -> Self {
        let (producer, consumer) = RingBuffer::new(capacity);

        let handle = thread::spawn(move || accumulate_samples(consumer));

        Self {
            producer,
            accumulator_handle: Some(handle),
        }
    }

    /// Push interleaved samples from the RT callback. Non-blocking.
    /// Drops samples if the ring buffer is full (preferable to blocking the RT thread).
    pub fn push_samples(&mut self, data: &[f32]) {
        for &sample in data {
            let _ = self.producer.push(sample);
        }
    }

    /// Stop recording and write the accumulated audio to a WAV file.
    pub fn finish(
        mut self,
        path: &Path,
        format: &AudioFormat,
    ) -> Result<(), Box<dyn std::error::Error>> {
        // Drop the producer to signal the consumer thread to finish
        drop(std::mem::replace(&mut self.producer, RingBuffer::new(1).0));

        let handle = self.accumulator_handle.take().unwrap();
        let samples = handle.join().map_err(|_| "recording thread panicked")?;

        let buffer = AudioBuffer::from_interleaved(samples, format.channels);
        write_wav_file(path, &buffer, format)?;

        Ok(())
    }
}

fn accumulate_samples(mut consumer: Consumer<f32>) -> Vec<f32> {
    let mut samples = Vec::new();

    loop {
        match consumer.pop() {
            Ok(sample) => samples.push(sample),
            Err(_) => {
                // Buffer empty — if the producer is gone, we're done
                if consumer.is_abandoned() {
                    // Drain any remaining
                    while let Ok(sample) = consumer.pop() {
                        samples.push(sample);
                    }
                    break;
                }
                thread::yield_now();
            }
        }
    }

    samples
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_record_manager_creation() {
        // Should not panic with various capacities
        let _rm = RecordManager::new(1024);
        let _rm = RecordManager::new(1);
    }

    #[test]
    fn test_push_samples() {
        let mut rm = RecordManager::new(1024);
        let data = vec![0.1, 0.2, 0.3, 0.4];
        rm.push_samples(&data);
        // Push more
        rm.push_samples(&[0.5, 0.6]);
        // No panic is the success condition; actual data verified via finish()
    }

    #[test]
    fn test_push_samples_empty() {
        let mut rm = RecordManager::new(1024);
        rm.push_samples(&[]);
        // No panic
    }

    #[test]
    fn test_accumulate_samples_basic() {
        let (mut producer, consumer) = rtrb::RingBuffer::new(64);

        let handle = thread::spawn(move || accumulate_samples(consumer));

        // Push some data then drop the producer to signal completion
        for &s in &[1.0f32, 2.0, 3.0, 4.0] {
            let _ = producer.push(s);
        }
        drop(producer);

        let result = handle.join().unwrap();
        assert_eq!(result, vec![1.0, 2.0, 3.0, 4.0]);
    }

    #[test]
    fn test_accumulate_samples_empty() {
        let (producer, consumer) = rtrb::RingBuffer::new(64);
        let handle = thread::spawn(move || accumulate_samples(consumer));
        drop(producer);

        let result = handle.join().unwrap();
        assert!(result.is_empty());
    }

    #[test]
    fn test_finish_writes_wav() {
        let mut rm = RecordManager::new(1024);
        let samples = vec![0.1f32, -0.1, 0.2, -0.2, 0.3, -0.3, 0.4, -0.4];
        rm.push_samples(&samples);

        let dir = std::env::temp_dir();
        let path = dir.join("shruti_test_record.wav");

        let format = AudioFormat {
            sample_rate: 44100,
            channels: 2,
            buffer_frames: 256,
        };

        rm.finish(&path, &format).unwrap();

        // Verify file was created
        assert!(path.exists());
        // Clean up
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn test_finish_empty_recording() {
        let rm = RecordManager::new(1024);

        let dir = std::env::temp_dir();
        let path = dir.join("shruti_test_empty_record.wav");

        let format = AudioFormat {
            sample_rate: 44100,
            channels: 1,
            buffer_frames: 256,
        };

        rm.finish(&path, &format).unwrap();
        assert!(path.exists());
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn test_push_samples_overflow_does_not_panic() {
        // Ring buffer of capacity 4, push 10 samples
        let mut rm = RecordManager::new(4);
        let data = vec![1.0; 10];
        rm.push_samples(&data);
        // Should not panic — overflow samples are silently dropped
    }
}

use serde::{Deserialize, Serialize};
use shruti_dsp::AudioBuffer;
use shruti_session::midi::{ControlChange, NoteEvent};

use crate::instrument::{InstrumentInfo, InstrumentNode, InstrumentParam};

pub const NUM_PADS: usize = 16;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum PlayMode {
    OneShot,
    Looped,
}

/// A single drum pad with a sample buffer and settings.
pub struct DrumPad {
    pub name: String,
    pub samples: Vec<f32>,
    pub sample_rate: u32,
    pub pitch: f32,
    pub gain: f32,
    pub pan: f32,
    pub decay: f32,
    pub play_mode: PlayMode,
    pub midi_note: u8,
    play_pos: f64,
    playing: bool,
    velocity: f32,
    envelope: f32,
}

impl DrumPad {
    pub fn new(name: &str, midi_note: u8) -> Self {
        Self {
            name: name.to_string(),
            samples: Vec::new(),
            sample_rate: 44100,
            pitch: 1.0,
            gain: 1.0,
            pan: 0.0,
            decay: 0.0,
            play_mode: PlayMode::OneShot,
            midi_note,
            play_pos: 0.0,
            playing: false,
            velocity: 0.0,
            envelope: 0.0,
        }
    }

    pub fn load_sample(&mut self, samples: Vec<f32>, sample_rate: u32) {
        self.samples = samples;
        self.sample_rate = sample_rate;
    }

    pub fn trigger(&mut self, velocity: u8) {
        self.play_pos = 0.0;
        self.playing = true;
        self.velocity = velocity as f32 / 127.0;
        self.envelope = 1.0;
    }

    pub fn stop(&mut self) {
        self.playing = false;
    }

    /// Generate one frame of audio. Returns (left, right) incorporating pan.
    pub fn tick(&mut self) -> (f32, f32) {
        if !self.playing || self.samples.is_empty() {
            return (0.0, 0.0);
        }

        let len = self.samples.len();
        let pos = self.play_pos;
        let idx = pos as usize;

        // Check bounds
        if idx >= len {
            match self.play_mode {
                PlayMode::OneShot => {
                    self.playing = false;
                    return (0.0, 0.0);
                }
                PlayMode::Looped => {
                    self.play_pos %= len as f64;
                    // Recalculate after wrapping
                    let idx = self.play_pos as usize;
                    if idx >= len {
                        return (0.0, 0.0);
                    }
                }
            }
        }

        // Linear interpolation
        let idx = self.play_pos as usize;
        let frac = (self.play_pos - idx as f64) as f32;
        let s0 = self.samples[idx];
        let s1 = if idx + 1 < len {
            self.samples[idx + 1]
        } else {
            match self.play_mode {
                PlayMode::Looped => self.samples[0],
                PlayMode::OneShot => 0.0,
            }
        };
        let sample = s0 + frac * (s1 - s0);

        // Apply envelope, velocity, gain
        let out = sample * self.envelope * self.velocity * self.gain;

        // Advance position
        self.play_pos += self.pitch as f64;

        // Apply decay envelope
        // decay_rate: decay=0 means no decay (envelope stays at 1), decay=1 means fast decay
        let decay_rate = 1.0 - self.decay * 0.001;
        self.envelope *= decay_rate;

        // Check if we've gone past end after advancing
        if self.play_pos as usize >= len {
            match self.play_mode {
                PlayMode::OneShot => {
                    self.playing = false;
                }
                PlayMode::Looped => {
                    self.play_pos %= len as f64;
                }
            }
        }

        // Equal-power pan law
        // pan: -1.0 = full left, 0.0 = center, 1.0 = full right
        let pan_normalized = (self.pan + 1.0) * 0.5; // 0.0 to 1.0
        let angle = pan_normalized * std::f32::consts::FRAC_PI_2;
        let left_gain = angle.cos();
        let right_gain = angle.sin();

        (out * left_gain, out * right_gain)
    }

    pub fn is_playing(&self) -> bool {
        self.playing
    }
}

const GM_DRUM_NAMES: [&str; NUM_PADS] = [
    "Bass Drum",
    "Rim Shot",
    "Snare",
    "Clap",
    "Snare 2",
    "Low Tom",
    "Closed HH",
    "Mid Tom",
    "Open HH",
    "High Tom",
    "Crash",
    "Ride",
    "Tambourine",
    "Cowbell",
    "Shaker",
    "Claves",
];

/// 16-pad drum machine implementing InstrumentNode.
pub struct DrumMachine {
    info: InstrumentInfo,
    params: Vec<InstrumentParam>,
    pub pads: Vec<DrumPad>,
    sample_rate: f32,
}

impl DrumMachine {
    pub fn new(sample_rate: f32) -> Self {
        let info = InstrumentInfo {
            name: "Drum Machine".to_string(),
            category: "Drums".to_string(),
            author: "Shruti".to_string(),
            description: "16-pad drum machine with sample playback".to_string(),
        };

        let params = vec![InstrumentParam::new("Volume", 0.0, 1.0, 0.8, "")];

        let pads = (0..NUM_PADS)
            .map(|i| DrumPad::new(GM_DRUM_NAMES[i], 36 + i as u8))
            .collect();

        Self {
            info,
            params,
            pads,
            sample_rate,
        }
    }

    fn find_pad_by_note(&self, note: u8) -> Option<usize> {
        self.pads.iter().position(|p| p.midi_note == note)
    }
}

impl InstrumentNode for DrumMachine {
    fn info(&self) -> &InstrumentInfo {
        &self.info
    }

    fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
    }

    fn process(
        &mut self,
        note_events: &[NoteEvent],
        _control_changes: &[ControlChange],
        output: &mut AudioBuffer,
    ) {
        let frames = output.frames();
        let volume = self.params[0].value;

        // Process note events at the start of the block
        for event in note_events {
            self.note_on(event.note, event.velocity, event.channel);
        }

        // Render each frame
        for frame in 0..frames {
            let mut left = 0.0_f32;
            let mut right = 0.0_f32;

            for pad in &mut self.pads {
                if pad.is_playing() {
                    let (l, r) = pad.tick();
                    left += l;
                    right += r;
                }
            }

            left *= volume;
            right *= volume;

            if output.channels() >= 2 {
                let cur_l = output.get(frame, 0);
                let cur_r = output.get(frame, 1);
                output.set(frame, 0, cur_l + left);
                output.set(frame, 1, cur_r + right);
            } else if output.channels() == 1 {
                let cur = output.get(frame, 0);
                output.set(frame, 0, cur + (left + right) * 0.5);
            }
        }
    }

    fn note_on(&mut self, note: u8, velocity: u8, _channel: u8) {
        if let Some(idx) = self.find_pad_by_note(note) {
            self.pads[idx].trigger(velocity);
        }
    }

    fn note_off(&mut self, note: u8, _channel: u8) {
        if let Some(idx) = self.find_pad_by_note(note)
            && self.pads[idx].play_mode == PlayMode::Looped
        {
            self.pads[idx].stop();
        }
    }

    fn params(&self) -> &[InstrumentParam] {
        &self.params
    }

    fn params_mut(&mut self) -> &mut [InstrumentParam] {
        &mut self.params
    }

    fn reset(&mut self) {
        for pad in &mut self.pads {
            pad.stop();
        }
    }

    fn active_voices(&self) -> usize {
        self.pads.iter().filter(|p| p.is_playing()).count()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_sine_sample(len: usize) -> Vec<f32> {
        (0..len)
            .map(|i| (2.0 * std::f32::consts::PI * i as f32 / len as f32).sin())
            .collect()
    }

    #[test]
    fn pad_trigger_and_stop() {
        let mut pad = DrumPad::new("Kick", 36);
        pad.load_sample(vec![1.0; 100], 44100);

        assert!(!pad.is_playing());
        pad.trigger(127);
        assert!(pad.is_playing());
        pad.stop();
        assert!(!pad.is_playing());
    }

    #[test]
    fn pad_oneshot_completes_and_stops() {
        let mut pad = DrumPad::new("Kick", 36);
        pad.load_sample(vec![0.5; 10], 44100);
        pad.play_mode = PlayMode::OneShot;
        pad.trigger(127);

        // Tick through the entire sample
        for _ in 0..20 {
            pad.tick();
        }
        assert!(!pad.is_playing());
    }

    #[test]
    fn pad_pitch_shifting_faster() {
        let mut pad = DrumPad::new("Kick", 36);
        pad.load_sample(vec![1.0; 100], 44100);
        pad.decay = 0.0;
        pad.play_mode = PlayMode::OneShot;
        pad.pitch = 2.0;
        pad.trigger(127);

        let mut ticks = 0;
        while pad.is_playing() {
            pad.tick();
            ticks += 1;
            if ticks > 200 {
                break;
            }
        }
        // At pitch 2.0, should finish in ~50 ticks instead of 100
        assert!(
            ticks <= 55,
            "pitch=2.0 should halve playback time, got {ticks}"
        );
        assert!(!pad.is_playing());
    }

    #[test]
    fn pad_pan_left() {
        let mut pad = DrumPad::new("Kick", 36);
        pad.load_sample(vec![1.0; 100], 44100);
        pad.decay = 0.0;
        pad.pan = -1.0; // full left
        pad.trigger(127);

        let (l, r) = pad.tick();
        assert!(l.abs() > 0.01, "left channel should have signal");
        assert!(
            r.abs() < 0.001,
            "right channel should be near zero for full left pan"
        );
    }

    #[test]
    fn pad_pan_right() {
        let mut pad = DrumPad::new("HH", 42);
        pad.load_sample(vec![1.0; 100], 44100);
        pad.decay = 0.0;
        pad.pan = 1.0; // full right
        pad.trigger(127);

        let (l, r) = pad.tick();
        assert!(
            l.abs() < 0.001,
            "left channel should be near zero for full right pan"
        );
        assert!(r.abs() > 0.01, "right channel should have signal");
    }

    #[test]
    fn pad_pan_center() {
        let mut pad = DrumPad::new("Snare", 38);
        pad.load_sample(vec![1.0; 100], 44100);
        pad.decay = 0.0;
        pad.pan = 0.0;
        pad.trigger(127);

        let (l, r) = pad.tick();
        assert!(
            (l - r).abs() < 0.01,
            "center pan should produce equal L/R, got l={l} r={r}"
        );
    }

    #[test]
    fn drum_machine_routes_midi_to_pads() {
        let mut dm = DrumMachine::new(44100.0);
        dm.pads[0].load_sample(vec![1.0; 100], 44100);
        dm.pads[1].load_sample(vec![1.0; 100], 44100);

        // Trigger pad 0 (note 36) and pad 1 (note 37)
        dm.note_on(36, 100, 0);
        assert!(dm.pads[0].is_playing());
        assert!(!dm.pads[1].is_playing());

        dm.note_on(37, 100, 0);
        assert!(dm.pads[1].is_playing());
    }

    #[test]
    fn drum_machine_silence_without_triggers() {
        let mut dm = DrumMachine::new(44100.0);
        let mut buf = AudioBuffer::new(2, 128);
        dm.process(&[], &[], &mut buf);

        for i in 0..128 {
            assert_eq!(buf.get(i, 0), 0.0);
            assert_eq!(buf.get(i, 1), 0.0);
        }
    }

    #[test]
    fn drum_machine_produces_audio_after_trigger() {
        let mut dm = DrumMachine::new(44100.0);
        dm.pads[0].load_sample(make_sine_sample(1000), 44100);
        dm.note_on(36, 127, 0);

        let mut buf = AudioBuffer::new(2, 256);
        dm.process(&[], &[], &mut buf);

        let mut has_nonzero = false;
        for i in 0..256 {
            if buf.get(i, 0).abs() > 0.001 {
                has_nonzero = true;
                break;
            }
        }
        assert!(
            has_nonzero,
            "drum machine should produce audio after trigger"
        );
    }

    #[test]
    fn drum_machine_multiple_simultaneous_pads() {
        let mut dm = DrumMachine::new(44100.0);
        dm.pads[0].load_sample(vec![0.5; 100], 44100);
        dm.pads[1].load_sample(vec![0.3; 100], 44100);

        dm.note_on(36, 127, 0);
        dm.note_on(37, 127, 0);

        assert_eq!(dm.active_voices(), 2);

        let mut buf = AudioBuffer::new(2, 10);
        dm.process(&[], &[], &mut buf);

        // Should have combined output from both pads
        let val = buf.get(0, 0);
        assert!(val.abs() > 0.3, "multiple pads should combine: got {val}");
    }

    #[test]
    fn velocity_affects_volume() {
        let mut pad_loud = DrumPad::new("Kick", 36);
        pad_loud.load_sample(vec![1.0; 100], 44100);
        pad_loud.decay = 0.0;
        pad_loud.trigger(127);
        let (loud_l, _) = pad_loud.tick();

        let mut pad_soft = DrumPad::new("Kick", 36);
        pad_soft.load_sample(vec![1.0; 100], 44100);
        pad_soft.decay = 0.0;
        pad_soft.trigger(32);
        let (soft_l, _) = pad_soft.tick();

        assert!(
            loud_l > soft_l,
            "higher velocity should be louder: loud={loud_l}, soft={soft_l}"
        );
    }

    #[test]
    fn load_sample_works() {
        let mut pad = DrumPad::new("Test", 36);
        assert!(pad.samples.is_empty());

        pad.load_sample(vec![0.1, 0.2, 0.3], 48000);
        assert_eq!(pad.samples.len(), 3);
        assert_eq!(pad.sample_rate, 48000);
    }

    #[test]
    fn pad_looped_mode_wraps() {
        let mut pad = DrumPad::new("Loop", 36);
        pad.load_sample(vec![1.0; 10], 44100);
        pad.play_mode = PlayMode::Looped;
        pad.decay = 0.0;
        pad.trigger(127);

        // Tick well past the sample length
        for _ in 0..30 {
            pad.tick();
        }
        // Should still be playing because it loops
        assert!(pad.is_playing());
    }

    #[test]
    fn drum_machine_process_with_note_events() {
        let mut dm = DrumMachine::new(44100.0);
        dm.pads[0].load_sample(make_sine_sample(1000), 44100);

        let events = vec![NoteEvent {
            position: 0,
            duration: 1000,
            note: 36,
            velocity: 100,
            channel: 0,
        }];

        let mut buf = AudioBuffer::new(2, 128);
        dm.process(&events, &[], &mut buf);

        let mut has_nonzero = false;
        for i in 0..128 {
            if buf.get(i, 0).abs() > 0.001 {
                has_nonzero = true;
                break;
            }
        }
        assert!(has_nonzero, "process should handle NoteEvent triggers");
    }

    #[test]
    fn drum_machine_reset_stops_all_pads() {
        let mut dm = DrumMachine::new(44100.0);
        dm.pads[0].load_sample(vec![1.0; 100], 44100);
        dm.pads[1].load_sample(vec![1.0; 100], 44100);
        dm.note_on(36, 100, 0);
        dm.note_on(37, 100, 0);
        assert_eq!(dm.active_voices(), 2);

        dm.reset();
        assert_eq!(dm.active_voices(), 0);
    }
}

use serde::{Deserialize, Serialize};

/// ADSR envelope parameters.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AdsrParams {
    /// Attack time in seconds.
    pub attack: f32,
    /// Decay time in seconds.
    pub decay: f32,
    /// Sustain level (0.0 to 1.0).
    pub sustain: f32,
    /// Release time in seconds.
    pub release: f32,
}

impl Default for AdsrParams {
    fn default() -> Self {
        Self {
            attack: 0.01,
            decay: 0.1,
            sustain: 0.7,
            release: 0.3,
        }
    }
}

/// Current state of an ADSR envelope.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EnvelopeState {
    Idle,
    Attack,
    Decay,
    Sustain,
    Release,
}

/// ADSR envelope generator.
pub struct Envelope {
    pub state: EnvelopeState,
    pub params: AdsrParams,
    pub level: f32,
    sample_rate: f32,
    /// Position within the current stage (in samples).
    stage_pos: u64,
    /// Level at the start of release (for smooth release from any level).
    release_start_level: f32,
}

impl Envelope {
    pub fn new(params: AdsrParams, sample_rate: f32) -> Self {
        Self {
            state: EnvelopeState::Idle,
            params,
            level: 0.0,
            sample_rate,
            stage_pos: 0,
            release_start_level: 0.0,
        }
    }

    pub fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
    }

    /// Trigger the envelope (note on).
    pub fn trigger(&mut self) {
        self.state = EnvelopeState::Attack;
        self.stage_pos = 0;
    }

    /// Release the envelope (note off).
    pub fn release(&mut self) {
        if self.state != EnvelopeState::Idle {
            self.release_start_level = self.level;
            self.state = EnvelopeState::Release;
            self.stage_pos = 0;
        }
    }

    /// Process one sample. Returns the current envelope level.
    pub fn tick(&mut self) -> f32 {
        match self.state {
            EnvelopeState::Idle => {
                self.level = 0.0;
            }
            EnvelopeState::Attack => {
                let attack_samples = (self.params.attack * self.sample_rate).max(1.0) as u64;
                self.level = self.stage_pos as f32 / attack_samples as f32;
                self.stage_pos += 1;
                if self.stage_pos >= attack_samples {
                    self.level = 1.0;
                    self.state = EnvelopeState::Decay;
                    self.stage_pos = 0;
                }
            }
            EnvelopeState::Decay => {
                let decay_samples = (self.params.decay * self.sample_rate).max(1.0) as u64;
                let progress = self.stage_pos as f32 / decay_samples as f32;
                self.level = 1.0 + (self.params.sustain - 1.0) * progress;
                self.stage_pos += 1;
                if self.stage_pos >= decay_samples {
                    self.level = self.params.sustain;
                    self.state = EnvelopeState::Sustain;
                }
            }
            EnvelopeState::Sustain => {
                self.level = self.params.sustain;
            }
            EnvelopeState::Release => {
                let release_samples = (self.params.release * self.sample_rate).max(1.0) as u64;
                let progress = self.stage_pos as f32 / release_samples as f32;
                self.level = self.release_start_level * (1.0 - progress);
                self.stage_pos += 1;
                if self.stage_pos >= release_samples {
                    self.level = 0.0;
                    self.state = EnvelopeState::Idle;
                }
            }
        }
        self.level
    }

    /// Whether the envelope has finished (returned to idle after release).
    pub fn is_finished(&self) -> bool {
        self.state == EnvelopeState::Idle
    }

    /// Reset to idle state.
    pub fn reset(&mut self) {
        self.state = EnvelopeState::Idle;
        self.level = 0.0;
        self.stage_pos = 0;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn default_params() {
        let p = AdsrParams::default();
        assert_eq!(p.attack, 0.01);
        assert_eq!(p.sustain, 0.7);
    }

    #[test]
    fn envelope_starts_idle() {
        let env = Envelope::new(AdsrParams::default(), 48000.0);
        assert_eq!(env.state, EnvelopeState::Idle);
        assert_eq!(env.level, 0.0);
    }

    #[test]
    fn envelope_attack_ramps_up() {
        let params = AdsrParams {
            attack: 0.01,
            decay: 0.01,
            sustain: 0.5,
            release: 0.01,
        };
        let mut env = Envelope::new(params, 1000.0); // 1kHz for easy math
        env.trigger();
        // 0.01s * 1000 = 10 samples for attack
        let mut levels = Vec::new();
        for _ in 0..10 {
            levels.push(env.tick());
        }
        // Should ramp from 0 to 1
        assert!(levels[0] < 0.2);
        assert!(levels.last().unwrap() >= &0.9);
    }

    #[test]
    fn envelope_reaches_sustain() {
        let params = AdsrParams {
            attack: 0.001,
            decay: 0.001,
            sustain: 0.6,
            release: 0.01,
        };
        let mut env = Envelope::new(params, 48000.0);
        env.trigger();
        // Run through attack + decay
        for _ in 0..500 {
            env.tick();
        }
        assert_eq!(env.state, EnvelopeState::Sustain);
        assert!((env.level - 0.6).abs() < 0.01);
    }

    #[test]
    fn envelope_release_to_idle() {
        let params = AdsrParams {
            attack: 0.001,
            decay: 0.001,
            sustain: 0.5,
            release: 0.01,
        };
        let mut env = Envelope::new(params, 48000.0);
        env.trigger();
        for _ in 0..500 {
            env.tick();
        }
        env.release();
        assert_eq!(env.state, EnvelopeState::Release);
        for _ in 0..1000 {
            env.tick();
        }
        assert_eq!(env.state, EnvelopeState::Idle);
        assert_eq!(env.level, 0.0);
    }

    #[test]
    fn envelope_is_finished() {
        let params = AdsrParams {
            attack: 0.001,
            decay: 0.001,
            sustain: 0.5,
            release: 0.001,
        };
        let mut env = Envelope::new(params, 48000.0);
        assert!(env.is_finished()); // idle = finished
        env.trigger();
        assert!(!env.is_finished());
        for _ in 0..500 {
            env.tick();
        }
        env.release();
        for _ in 0..500 {
            env.tick();
        }
        assert!(env.is_finished());
    }

    #[test]
    fn envelope_reset() {
        let mut env = Envelope::new(AdsrParams::default(), 48000.0);
        env.trigger();
        for _ in 0..100 {
            env.tick();
        }
        env.reset();
        assert_eq!(env.state, EnvelopeState::Idle);
        assert_eq!(env.level, 0.0);
    }
}

use serde::{Deserialize, Serialize};

/// Filter mode for the state-variable filter.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum FilterMode {
    LowPass,
    HighPass,
    BandPass,
    Notch,
}

/// A state-variable filter (SVF) based on the Cytomic/Andrew Simper topology.
///
/// Supports low-pass, high-pass, band-pass, and notch modes with
/// adjustable cutoff frequency and resonance.
pub struct Filter {
    pub mode: FilterMode,
    pub cutoff: f32,
    pub resonance: f32,
    sample_rate: f32,
    // SVF state variables
    ic1eq: f32,
    ic2eq: f32,
    // Cached coefficients (recomputed when cutoff/resonance change)
    cached_cutoff: f32,
    cached_resonance: f32,
    cached_g: f32,
    cached_k: f32,
    cached_a1: f32,
    cached_a2: f32,
    cached_a3: f32,
}

impl Filter {
    pub fn new(mode: FilterMode, cutoff: f32, resonance: f32, sample_rate: f32) -> Self {
        let cutoff = cutoff.clamp(20.0, 20000.0);
        let resonance = resonance.clamp(0.0, 1.0);
        let g = (std::f32::consts::PI * cutoff / sample_rate).tan();
        let k = 2.0 - 2.0 * resonance;
        let a1 = 1.0 / (1.0 + g * (g + k));
        let a2 = g * a1;
        let a3 = g * a2;
        Self {
            mode,
            cutoff,
            resonance,
            sample_rate,
            ic1eq: 0.0,
            ic2eq: 0.0,
            cached_cutoff: cutoff,
            cached_resonance: resonance,
            cached_g: g,
            cached_k: k,
            cached_a1: a1,
            cached_a2: a2,
            cached_a3: a3,
        }
    }

    pub fn set_sample_rate(&mut self, sr: f32) {
        self.sample_rate = sr;
        self.update_coefficients();
    }

    /// Recompute coefficients when cutoff or resonance have changed.
    #[inline]
    fn update_coefficients(&mut self) {
        let clamped_res = self.resonance.clamp(0.0, 1.0);
        self.cached_g = (std::f32::consts::PI * self.cutoff.clamp(20.0, self.sample_rate * 0.49)
            / self.sample_rate)
            .tan();
        self.cached_k = 2.0 - 2.0 * clamped_res;
        self.cached_a1 = 1.0 / (1.0 + self.cached_g * (self.cached_g + self.cached_k));
        self.cached_a2 = self.cached_g * self.cached_a1;
        self.cached_a3 = self.cached_g * self.cached_a2;
        self.cached_cutoff = self.cutoff;
        self.cached_resonance = self.resonance;
    }

    /// Process a single sample through the SVF.
    #[inline]
    pub fn process_sample(&mut self, input: f32) -> f32 {
        // Only recompute coefficients if cutoff or resonance changed
        if self.cutoff != self.cached_cutoff || self.resonance != self.cached_resonance {
            self.update_coefficients();
        }

        let v3 = input - self.ic2eq;
        let v1 = self.cached_a1 * self.ic1eq + self.cached_a2 * v3;
        let v2 = self.ic2eq + self.cached_a2 * self.ic1eq + self.cached_a3 * v3;

        self.ic1eq = 2.0 * v1 - self.ic1eq;
        self.ic2eq = 2.0 * v2 - self.ic2eq;

        match self.mode {
            FilterMode::LowPass => v2,
            FilterMode::HighPass => input - self.cached_k * v1 - v2,
            FilterMode::BandPass => v1,
            FilterMode::Notch => input - self.cached_k * v1,
        }
    }

    /// Reset internal state variables to zero.
    pub fn reset(&mut self) {
        self.ic1eq = 0.0;
        self.ic2eq = 0.0;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    const SR: f32 = 48000.0;

    /// Generate a sine wave and measure RMS after filtering.
    fn measure_filtered_rms(mode: FilterMode, cutoff: f32, resonance: f32, freq: f32) -> f32 {
        let mut filter = Filter::new(mode, cutoff, resonance, SR);
        let num_samples = SR as usize; // 1 second
        let mut sum_sq = 0.0f64;
        // Skip initial transient
        let skip = (SR * 0.1) as usize;
        for i in 0..num_samples {
            let phase = 2.0 * std::f32::consts::PI * freq * i as f32 / SR;
            let input = phase.sin();
            let output = filter.process_sample(input);
            if i >= skip {
                sum_sq += (output as f64) * (output as f64);
            }
        }
        ((sum_sq / (num_samples - skip) as f64).sqrt()) as f32
    }

    #[test]
    fn lowpass_passes_low_frequencies() {
        let rms = measure_filtered_rms(FilterMode::LowPass, 5000.0, 0.0, 100.0);
        // 100 Hz through a 5000 Hz lowpass should pass mostly unattenuated
        assert!(rms > 0.5, "LP should pass 100Hz, got rms={rms}");
    }

    #[test]
    fn lowpass_attenuates_high_frequencies() {
        let rms = measure_filtered_rms(FilterMode::LowPass, 200.0, 0.0, 10000.0);
        // 10000 Hz through a 200 Hz lowpass should be heavily attenuated
        assert!(rms < 0.1, "LP should attenuate 10kHz, got rms={rms}");
    }

    #[test]
    fn highpass_passes_high_frequencies() {
        let rms = measure_filtered_rms(FilterMode::HighPass, 200.0, 0.0, 5000.0);
        assert!(rms > 0.4, "HP should pass 5kHz, got rms={rms}");
    }

    #[test]
    fn highpass_attenuates_low_frequencies() {
        let rms = measure_filtered_rms(FilterMode::HighPass, 5000.0, 0.0, 100.0);
        assert!(rms < 0.1, "HP should attenuate 100Hz, got rms={rms}");
    }

    #[test]
    fn bandpass_passes_center_frequency() {
        let rms = measure_filtered_rms(FilterMode::BandPass, 1000.0, 0.5, 1000.0);
        assert!(rms > 0.2, "BP should pass center freq, got rms={rms}");
    }

    #[test]
    fn bandpass_attenuates_far_frequency() {
        let rms_low = measure_filtered_rms(FilterMode::BandPass, 1000.0, 0.5, 50.0);
        let rms_high = measure_filtered_rms(FilterMode::BandPass, 1000.0, 0.5, 15000.0);
        assert!(
            rms_low < 0.15,
            "BP should attenuate 50Hz with cutoff 1kHz, got rms={rms_low}"
        );
        assert!(
            rms_high < 0.15,
            "BP should attenuate 15kHz with cutoff 1kHz, got rms={rms_high}"
        );
    }

    #[test]
    fn notch_attenuates_center_frequency() {
        let rms_center = measure_filtered_rms(FilterMode::Notch, 1000.0, 0.95, 1000.0);
        let rms_away = measure_filtered_rms(FilterMode::Notch, 1000.0, 0.95, 100.0);
        assert!(
            rms_center < rms_away,
            "Notch should attenuate center more than away: center={rms_center}, away={rms_away}"
        );
    }

    #[test]
    fn resonance_boosts_near_cutoff() {
        let rms_no_res = measure_filtered_rms(FilterMode::LowPass, 1000.0, 0.0, 900.0);
        let rms_high_res = measure_filtered_rms(FilterMode::LowPass, 1000.0, 0.95, 900.0);
        assert!(
            rms_high_res > rms_no_res,
            "High resonance should boost near cutoff: no_res={rms_no_res}, high_res={rms_high_res}"
        );
    }

    #[test]
    fn reset_clears_state() {
        let mut filter = Filter::new(FilterMode::LowPass, 1000.0, 0.5, SR);
        // Feed some signal
        for i in 0..1000 {
            let phase = 2.0 * std::f32::consts::PI * 440.0 * i as f32 / SR;
            filter.process_sample(phase.sin());
        }
        filter.reset();
        // After reset, the filter state should be zero, so output of 0 input = 0
        let out = filter.process_sample(0.0);
        assert!(
            out.abs() < f32::EPSILON,
            "After reset, 0 input should give 0 output, got {out}"
        );
    }
}

use serde::{Deserialize, Serialize};
use shruti_dsp::AudioBuffer;
use shruti_session::midi::{ControlChange, NoteEvent};

/// Information about an instrument.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct InstrumentInfo {
    pub name: String,
    pub category: String,
    pub author: String,
    pub description: String,
}

/// A named parameter of an instrument.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct InstrumentParam {
    pub name: String,
    pub min: f32,
    pub max: f32,
    pub default: f32,
    pub value: f32,
    pub unit: String,
}

impl InstrumentParam {
    pub fn new(name: &str, min: f32, max: f32, default: f32, unit: &str) -> Self {
        Self {
            name: name.to_string(),
            min,
            max,
            default,
            value: default,
            unit: unit.to_string(),
        }
    }

    /// Set value, clamped to [min, max].
    pub fn set(&mut self, value: f32) {
        self.value = value.clamp(self.min, self.max);
    }

    /// Get normalized value (0.0 to 1.0).
    pub fn normalized(&self) -> f32 {
        if (self.max - self.min).abs() < f32::EPSILON {
            return 0.0;
        }
        (self.value - self.min) / (self.max - self.min)
    }

    /// Set from normalized value (0.0 to 1.0).
    pub fn set_normalized(&mut self, n: f32) {
        self.value =
            (self.min + n.clamp(0.0, 1.0) * (self.max - self.min)).clamp(self.min, self.max);
    }
}

/// Trait for all virtual instruments.
pub trait InstrumentNode: Send {
    /// Get instrument info.
    fn info(&self) -> &InstrumentInfo;

    /// Set the sample rate. Called when the audio engine starts or sample rate changes.
    fn set_sample_rate(&mut self, sample_rate: f32);

    /// Process a block of audio. The instrument reads MIDI events and writes audio output.
    /// `note_events` are sorted by position within this block.
    /// `output` is the buffer to write into (instrument should ADD to existing content, not overwrite).
    fn process(
        &mut self,
        note_events: &[NoteEvent],
        control_changes: &[ControlChange],
        output: &mut AudioBuffer,
    );

    /// Handle a single note-on event (for real-time MIDI input).
    fn note_on(&mut self, note: u8, velocity: u8, channel: u8);

    /// Handle a single note-off event.
    fn note_off(&mut self, note: u8, channel: u8);

    /// Get all parameters.
    fn params(&self) -> &[InstrumentParam];

    /// Get a mutable reference to all parameters.
    fn params_mut(&mut self) -> &mut [InstrumentParam];

    /// Reset all internal state (voices, oscillators, etc.).
    fn reset(&mut self);

    /// Number of currently active voices.
    fn active_voices(&self) -> usize;
}

use serde::{Deserialize, Serialize};

/// LFO waveform shape.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum LfoShape {
    Sine,
    Triangle,
    Square,
    SawUp,
    SawDown,
    SampleAndHold,
}

/// Low-frequency oscillator for modulation.
///
/// Outputs values in the range `-depth..+depth`.
pub struct Lfo {
    pub shape: LfoShape,
    pub rate: f32,
    pub depth: f32,
    phase: f64,
    sample_rate: f32,
    sh_value: f32,
    rng_state: u32,
}

impl Lfo {
    pub fn new(shape: LfoShape, rate: f32, depth: f32, sample_rate: f32) -> Self {
        Self {
            shape,
            rate,
            depth: depth.clamp(0.0, 1.0),
            phase: 0.0,
            sample_rate,
            sh_value: 0.0,
            rng_state: 0x1234_5678,
        }
    }

    pub fn set_sample_rate(&mut self, sr: f32) {
        self.sample_rate = sr;
    }

    /// Advance the LFO by one sample and return the current value in `-depth..+depth`.
    pub fn tick(&mut self) -> f32 {
        let raw = match self.shape {
            LfoShape::Sine => (self.phase * std::f64::consts::TAU).sin() as f32,
            LfoShape::Triangle => {
                let p = self.phase as f32;
                if p < 0.25 {
                    p * 4.0
                } else if p < 0.75 {
                    2.0 - p * 4.0
                } else {
                    p * 4.0 - 4.0
                }
            }
            LfoShape::Square => {
                if self.phase < 0.5 {
                    1.0
                } else {
                    -1.0
                }
            }
            LfoShape::SawUp => (self.phase as f32) * 2.0 - 1.0,
            LfoShape::SawDown => 1.0 - (self.phase as f32) * 2.0,
            LfoShape::SampleAndHold => {
                // Update S&H value at each cycle start (phase wrap)
                let next_phase = self.phase + self.rate as f64 / self.sample_rate as f64;
                if next_phase >= 1.0 || self.phase == 0.0 {
                    // xorshift32
                    self.rng_state ^= self.rng_state << 13;
                    self.rng_state ^= self.rng_state >> 17;
                    self.rng_state ^= self.rng_state << 5;
                    self.sh_value = (self.rng_state as f32 / u32::MAX as f32) * 2.0 - 1.0;
                }
                self.sh_value
            }
        };

        // Advance phase
        self.phase += self.rate as f64 / self.sample_rate as f64;
        self.phase -= self.phase.floor();

        raw * self.depth
    }

    /// Reset LFO phase and S&H state.
    pub fn reset(&mut self) {
        self.phase = 0.0;
        self.sh_value = 0.0;
        self.rng_state = 0x1234_5678;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    const SR: f32 = 48000.0;

    #[test]
    fn sine_range() {
