//! MIDI routing from MIDI tracks to instrument nodes.

use shruti_session::midi::NoteEvent;
use uuid::Uuid;

/// How velocity values are transformed before reaching the instrument.
#[derive(Debug, Clone, PartialEq)]
pub enum VelocityCurve {
    /// Linear passthrough (identity).
    Linear,
    /// Gentler response — compresses high velocities.
    Soft,
    /// More aggressive response — expands high velocities.
    Hard,
    /// Always emit a fixed velocity regardless of input.
    Fixed(u8),
}

impl VelocityCurve {
    /// Apply the velocity curve to a raw MIDI velocity value.
    pub fn apply(&self, velocity: u8) -> u8 {
        match self {
            VelocityCurve::Linear => velocity,
            VelocityCurve::Soft => {
                // sqrt curve: compress dynamics
                let normalized = velocity as f64 / 127.0;
                let curved = normalized.sqrt();
                (curved * 127.0).round() as u8
            }
            VelocityCurve::Hard => {
                // square curve: expand dynamics
                let normalized = velocity as f64 / 127.0;
                let curved = normalized * normalized;
                (curved * 127.0).round() as u8
            }
            VelocityCurve::Fixed(v) => *v,
        }
    }
}

/// A route from a MIDI source track to an instrument.
#[derive(Debug, Clone)]
pub struct MidiRoute {
    /// The track that produces MIDI events.
    pub source_track_id: Uuid,
    /// If set, only events on this MIDI channel pass through (0-15). `None` = all channels.
    pub channel_filter: Option<u8>,
    /// Velocity transformation applied to passing events.
    pub velocity_curve: VelocityCurve,
    /// Inclusive note range `(min, max)` — notes outside are filtered out.
    pub note_range: (u8, u8),
}

impl MidiRoute {
    /// Create a new MIDI route that passes all events unmodified.
    pub fn new(source_track_id: Uuid) -> Self {
        Self {
            source_track_id,
            channel_filter: None,
            velocity_curve: VelocityCurve::Linear,
            note_range: (0, 127),
        }
    }

    /// Filter and transform a [`NoteEvent`].
    ///
    /// Returns `None` if the event is rejected by channel or note-range filters.
    /// Otherwise returns a (possibly modified) copy with the velocity curve applied.
    pub fn filter_event(&self, event: &NoteEvent) -> Option<NoteEvent> {
        // Channel filter
        if let Some(ch) = self.channel_filter
            && event.channel != ch
        {
            return None;
        }

        // Note range filter
        if event.note < self.note_range.0 || event.note > self.note_range.1 {
            return None;
        }

        // Apply velocity curve
        let mut out = event.clone();
        out.velocity = self.velocity_curve.apply(event.velocity);
        Some(out)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_event(note: u8, velocity: u8, channel: u8) -> NoteEvent {
        NoteEvent {
            position: 0,
            duration: 100,
            note,
            velocity,
            channel,
        }
    }

    #[test]
    fn passthrough_all_events() {
        let route = MidiRoute::new(Uuid::new_v4());
        let event = make_event(60, 100, 0);
        let result = route.filter_event(&event).unwrap();
        assert_eq!(result.note, 60);
        assert_eq!(result.velocity, 100);
        assert_eq!(result.channel, 0);
    }

    #[test]
    fn channel_filter_passes_matching() {
        let mut route = MidiRoute::new(Uuid::new_v4());
        route.channel_filter = Some(5);
        let event = make_event(60, 100, 5);
        assert!(route.filter_event(&event).is_some());
    }

    #[test]
    fn channel_filter_rejects_non_matching() {
        let mut route = MidiRoute::new(Uuid::new_v4());
        route.channel_filter = Some(5);
        let event = make_event(60, 100, 3);
        assert!(route.filter_event(&event).is_none());
    }

    #[test]
    fn note_range_passes_within() {
        let mut route = MidiRoute::new(Uuid::new_v4());
        route.note_range = (36, 72);
        assert!(route.filter_event(&make_event(36, 100, 0)).is_some());
        assert!(route.filter_event(&make_event(72, 100, 0)).is_some());
        assert!(route.filter_event(&make_event(54, 100, 0)).is_some());
    }

    #[test]
    fn note_range_rejects_outside() {
        let mut route = MidiRoute::new(Uuid::new_v4());
        route.note_range = (36, 72);
        assert!(route.filter_event(&make_event(35, 100, 0)).is_none());
        assert!(route.filter_event(&make_event(73, 100, 0)).is_none());
        assert!(route.filter_event(&make_event(0, 100, 0)).is_none());
        assert!(route.filter_event(&make_event(127, 100, 0)).is_none());
    }

    #[test]
    fn velocity_curve_linear() {
        let curve = VelocityCurve::Linear;
        assert_eq!(curve.apply(0), 0);
        assert_eq!(curve.apply(64), 64);
        assert_eq!(curve.apply(127), 127);
    }

    #[test]
    fn velocity_curve_soft() {
        let curve = VelocityCurve::Soft;
        // Soft curve: output >= input for sub-max values (sqrt expands low values)
        assert_eq!(curve.apply(0), 0);
        assert_eq!(curve.apply(127), 127);
        // A mid-range value should be boosted
        let mid = curve.apply(32);
        assert!(
            mid > 32,
            "soft curve should boost low velocities: got {mid}"
        );
    }

    #[test]
    fn velocity_curve_hard() {
        let curve = VelocityCurve::Hard;
        assert_eq!(curve.apply(0), 0);
        assert_eq!(curve.apply(127), 127);
        // A mid-range value should be reduced
        let mid = curve.apply(90);
        assert!(
            mid < 90,
            "hard curve should reduce mid velocities: got {mid}"
        );
    }

    #[test]
    fn velocity_curve_fixed() {
        let curve = VelocityCurve::Fixed(100);
        assert_eq!(curve.apply(0), 100);
        assert_eq!(curve.apply(50), 100);
        assert_eq!(curve.apply(127), 100);
    }

    #[test]
    fn combined_channel_and_note_range_filter() {
        let mut route = MidiRoute::new(Uuid::new_v4());
        route.channel_filter = Some(0);
        route.note_range = (48, 72);
        route.velocity_curve = VelocityCurve::Fixed(80);

        // Passes: right channel, right note range
        let result = route.filter_event(&make_event(60, 127, 0)).unwrap();
        assert_eq!(result.velocity, 80); // fixed velocity

        // Fails: wrong channel
        assert!(route.filter_event(&make_event(60, 127, 1)).is_none());

        // Fails: note out of range
        assert!(route.filter_event(&make_event(47, 127, 0)).is_none());
    }
}

use shruti_dsp::AudioBuffer;
use shruti_session::midi::{ControlChange, NoteEvent};

use crate::envelope::{AdsrParams, Envelope};
use crate::instrument::{InstrumentInfo, InstrumentNode, InstrumentParam};
use serde::{Deserialize, Serialize};

/// A zone maps a range of MIDI notes and velocities to a sample.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SampleZone {
    pub name: String,
    pub root_key: u8,
    pub key_low: u8,
    pub key_high: u8,
    pub velocity_low: u8,
    pub velocity_high: u8,
    #[serde(skip)]
    pub samples: Vec<f32>,
    pub sample_rate: u32,
    pub loop_start: Option<usize>,
    pub loop_end: Option<usize>,
    pub loop_mode: LoopMode,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum LoopMode {
    NoLoop,
    Forward,
    PingPong,
}

impl SampleZone {
    pub fn new(name: &str, root_key: u8, samples: Vec<f32>, sample_rate: u32) -> Self {
        Self {
            name: name.to_string(),
            root_key,
            key_low: 0,
            key_high: 127,
            velocity_low: 0,
            velocity_high: 127,
            samples,
            sample_rate,
            loop_start: None,
            loop_end: None,
            loop_mode: LoopMode::NoLoop,
        }
    }

    /// Returns true if the given note and velocity fall within this zone's ranges.
    pub fn matches(&self, note: u8, velocity: u8) -> bool {
        note >= self.key_low
            && note <= self.key_high
            && velocity >= self.velocity_low
            && velocity <= self.velocity_high
    }

    /// Pitch ratio to play this sample at the given MIDI note.
    pub fn pitch_ratio(&self, note: u8) -> f64 {
        let semitones = f64::from(note) - f64::from(self.root_key);
        2.0_f64.powf(semitones / 12.0)
    }
}

/// A voice playing a sample zone.
struct SamplerVoice {
    zone_index: usize,
    note: u8,
    velocity: u8,
    channel: u8,
    play_pos: f64,
    pitch_ratio: f64,
    envelope: Envelope,
    active: bool,
    direction: i8,
}

impl SamplerVoice {
    fn new(sample_rate: f32) -> Self {
        Self {
            zone_index: 0,
            note: 0,
            velocity: 0,
            channel: 0,
            play_pos: 0.0,
            pitch_ratio: 1.0,
            envelope: Envelope::new(AdsrParams::default(), sample_rate),
            active: false,
            direction: 1,
        }
    }
}

// Parameter indices
const PARAM_VOLUME: usize = 0;
const PARAM_ATTACK: usize = 1;
const PARAM_DECAY: usize = 2;
const PARAM_SUSTAIN: usize = 3;
const PARAM_RELEASE: usize = 4;

const MAX_VOICES: usize = 16;

/// Multi-sample instrument: maps zones across keyboard and velocity.
pub struct Sampler {
    info: InstrumentInfo,
    params: Vec<InstrumentParam>,
    pub zones: Vec<SampleZone>,
    voices: Vec<SamplerVoice>,
    max_voices: usize,
    sample_rate: f32,
}

impl Sampler {
    pub fn new(sample_rate: f32) -> Self {
        let info = InstrumentInfo {
            name: "Sampler".to_string(),
            category: "Sampler".to_string(),
            author: "Shruti".to_string(),
            description: "Multi-sample instrument with zone mapping".to_string(),
        };

        let params = vec![
            InstrumentParam::new("Volume", 0.0, 1.0, 0.8, ""),
            InstrumentParam::new("Attack", 0.001, 5.0, 0.01, "s"),
            InstrumentParam::new("Decay", 0.001, 5.0, 0.1, "s"),
            InstrumentParam::new("Sustain", 0.0, 1.0, 0.7, ""),
            InstrumentParam::new("Release", 0.001, 10.0, 0.3, "s"),
        ];

        let voices = (0..MAX_VOICES)
            .map(|_| SamplerVoice::new(sample_rate))
            .collect();

        Self {
            info,
            params,
            zones: Vec::new(),
            voices,
            max_voices: MAX_VOICES,
            sample_rate,
        }
    }

    pub fn add_zone(&mut self, zone: SampleZone) {
        self.zones.push(zone);
    }

    pub fn remove_zone(&mut self, index: usize) {
        self.zones.remove(index);
    }

    /// Find the best matching zone for a note+velocity.
    fn find_zone(&self, note: u8, velocity: u8) -> Option<usize> {
        self.zones.iter().position(|z| z.matches(note, velocity))
    }

    fn current_adsr(&self) -> AdsrParams {
        AdsrParams {
            attack: self.params[PARAM_ATTACK].value,
            decay: self.params[PARAM_DECAY].value,
            sustain: self.params[PARAM_SUSTAIN].value,
            release: self.params[PARAM_RELEASE].value,
        }
    }

    /// Allocate a voice, stealing the oldest finished voice if necessary.
    fn allocate_voice(&mut self) -> Option<usize> {
        // First: find an inactive voice
        if let Some(idx) = self.voices.iter().position(|v| !v.active) {
            return Some(idx);
        }
        // If all voices active, steal the first one (oldest)
        if self.max_voices > 0 { Some(0) } else { None }
    }

    /// Read a sample from a zone with linear interpolation.
    fn read_sample(zone: &SampleZone, pos: f64) -> f32 {
        let len = zone.samples.len();
        if len == 0 {
            return 0.0;
        }
        let idx = pos.floor() as usize;
        if idx >= len {
            return 0.0;
        }
        let frac = (pos - pos.floor()) as f32;
        let s0 = zone.samples[idx];
        let s1 = if idx + 1 < len {
            zone.samples[idx + 1]
        } else {
            s0
        };
        s0 * (1.0 - frac) + s1 * frac
    }
}

impl InstrumentNode for Sampler {
    fn info(&self) -> &InstrumentInfo {
        &self.info
    }

    fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
        for voice in &mut self.voices {
            voice.envelope.set_sample_rate(sample_rate);
        }
    }

    fn process(
        &mut self,
        note_events: &[NoteEvent],
        _control_changes: &[ControlChange],
        output: &mut AudioBuffer,
    ) {
        let frames = output.frames() as usize;
        let channels = output.channels();
        let volume = self.params[PARAM_VOLUME].value;

        // Process note events at the start of the block
        for event in note_events {
            self.note_on(event.note, event.velocity, event.channel);
        }

        // Render each active voice
        for i in 0..self.max_voices {
            if !self.voices[i].active {
                continue;
            }

            let zone_index = self.voices[i].zone_index;
            if zone_index >= self.zones.len() {
                self.voices[i].active = false;
                continue;
            }

            let vel_gain = self.voices[i].velocity as f32 / 127.0;
            let pitch_ratio = self.voices[i].pitch_ratio;

            for frame in 0..frames {
                let env_level = self.voices[i].envelope.tick();

                if self.voices[i].envelope.is_finished() {
                    self.voices[i].active = false;
                    break;
                }

                let sample = Self::read_sample(&self.zones[zone_index], self.voices[i].play_pos);
                let out = sample * env_level * vel_gain * volume;

                for ch in 0..channels {
                    let current = output.get(frame as u32, ch);
                    output.set(frame as u32, ch, current + out);
                }

                // Advance play position
                let zone = &self.zones[zone_index];
                match zone.loop_mode {
                    LoopMode::NoLoop => {
                        self.voices[i].play_pos += pitch_ratio;
                        if self.voices[i].play_pos >= zone.samples.len() as f64 {
                            // Sample finished, trigger release if not already releasing
                            self.voices[i].active = false;
                            break;
                        }
                    }
                    LoopMode::Forward => {
                        self.voices[i].play_pos += pitch_ratio;
                        let loop_start = zone.loop_start.unwrap_or(0) as f64;
                        let loop_end = zone.loop_end.unwrap_or(zone.samples.len()) as f64;
                        if self.voices[i].play_pos >= loop_end {
                            self.voices[i].play_pos =
                                loop_start + (self.voices[i].play_pos - loop_end);
                        }
                    }
                    LoopMode::PingPong => {
                        let step = pitch_ratio * f64::from(self.voices[i].direction);
                        self.voices[i].play_pos += step;
                        let loop_start = zone.loop_start.unwrap_or(0) as f64;
                        let loop_end = zone.loop_end.unwrap_or(zone.samples.len()) as f64;
                        if self.voices[i].play_pos >= loop_end {
                            self.voices[i].direction = -1;
                            self.voices[i].play_pos =
                                loop_end - (self.voices[i].play_pos - loop_end);
                        } else if self.voices[i].play_pos <= loop_start {
                            self.voices[i].direction = 1;
                            self.voices[i].play_pos =
                                loop_start + (loop_start - self.voices[i].play_pos);
                        }
                    }
                }
            }
        }
    }

    fn note_on(&mut self, note: u8, velocity: u8, channel: u8) {
        let zone_index = match self.find_zone(note, velocity) {
            Some(idx) => idx,
            None => return,
        };

        let voice_idx = match self.allocate_voice() {
            Some(idx) => idx,
            None => return,
        };

        let zone = &self.zones[zone_index];
        let pitch_ratio = zone.pitch_ratio(note) * f64::from(zone.sample_rate)
            / f64::from(self.sample_rate.max(1.0));

        let adsr = self.current_adsr();
        let voice = &mut self.voices[voice_idx];
        voice.zone_index = zone_index;
        voice.note = note;
        voice.velocity = velocity;
        voice.channel = channel;
        voice.play_pos = 0.0;
        voice.pitch_ratio = pitch_ratio;
        voice.active = true;
        voice.direction = 1;
        voice.envelope.params = adsr;
        voice.envelope.trigger();
    }

    fn note_off(&mut self, note: u8, channel: u8) {
        for voice in &mut self.voices {
            if voice.active && voice.note == note && voice.channel == channel {
                voice.envelope.release();
            }
        }
    }

    fn params(&self) -> &[InstrumentParam] {
        &self.params
    }

    fn params_mut(&mut self) -> &mut [InstrumentParam] {
        &mut self.params
    }

    fn reset(&mut self) {
        for voice in &mut self.voices {
            voice.active = false;
            voice.envelope.reset();
        }
    }

    fn active_voices(&self) -> usize {
        self.voices.iter().filter(|v| v.active).count()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Create a simple test sample: a sine wave at 1kHz, 1 second, 44100 Hz.
    fn make_test_samples(num_samples: usize) -> Vec<f32> {
        (0..num_samples)
            .map(|i| (2.0 * std::f32::consts::PI * 440.0 * i as f32 / 44100.0).sin())
            .collect()
    }

    fn make_test_zone(root_key: u8) -> SampleZone {
        let mut zone = SampleZone::new("Test", root_key, make_test_samples(4410), 44100);
        zone.key_low = 0;
        zone.key_high = 127;
        zone
    }

    #[test]
    fn zone_matches_note_in_range() {
        let mut zone = SampleZone::new("Piano C4", 60, vec![], 44100);
        zone.key_low = 48;
        zone.key_high = 72;
        zone.velocity_low = 1;
        zone.velocity_high = 127;

        assert!(zone.matches(60, 100));
        assert!(zone.matches(48, 1));
        assert!(zone.matches(72, 127));
    }

    #[test]
    fn zone_rejects_note_outside_range() {
        let mut zone = SampleZone::new("Piano C4", 60, vec![], 44100);
        zone.key_low = 48;
        zone.key_high = 72;
        zone.velocity_low = 1;
        zone.velocity_high = 127;

        assert!(!zone.matches(47, 100));
        assert!(!zone.matches(73, 100));
        assert!(!zone.matches(60, 0)); // velocity 0 below velocity_low=1
    }

    #[test]
    fn zone_pitch_ratio_root_key_is_one() {
        let zone = SampleZone::new("Test", 60, vec![], 44100);
        let ratio = zone.pitch_ratio(60);
        assert!((ratio - 1.0).abs() < 1e-10);
    }

    #[test]
    fn zone_pitch_ratio_octave_up_is_double() {
        let zone = SampleZone::new("Test", 60, vec![], 44100);
        let ratio = zone.pitch_ratio(72);
        assert!((ratio - 2.0).abs() < 1e-10);
    }

    #[test]
    fn zone_pitch_ratio_octave_down_is_half() {
        let zone = SampleZone::new("Test", 60, vec![], 44100);
        let ratio = zone.pitch_ratio(48);
        assert!((ratio - 0.5).abs() < 1e-10);
    }

    #[test]
    fn sampler_produces_audio_for_matching_zone() {
        let mut sampler = Sampler::new(44100.0);
        sampler.add_zone(make_test_zone(60));
        sampler.note_on(60, 100, 0);

        let mut buf = AudioBuffer::new(2, 256);
        sampler.process(&[], &[], &mut buf);

        let has_nonzero = (0..256).any(|i| buf.get(i, 0).abs() > 0.001);
        assert!(has_nonzero, "sampler should produce audio output");
    }

    #[test]
    fn sampler_silence_for_note_outside_zones() {
        let mut sampler = Sampler::new(44100.0);
        let mut zone = make_test_zone(60);
        zone.key_low = 48;
        zone.key_high = 72;
        sampler.add_zone(zone);

        // Note 80 is outside [48, 72]
        sampler.note_on(80, 100, 0);

        let mut buf = AudioBuffer::new(2, 256);
        sampler.process(&[], &[], &mut buf);

        for i in 0..256 {
            assert_eq!(buf.get(i, 0), 0.0);
        }
    }

    #[test]
    fn multiple_zones_different_key_ranges() {
        let mut sampler = Sampler::new(44100.0);

        let mut zone_low = SampleZone::new("Low", 36, make_test_samples(4410), 44100);
        zone_low.key_low = 0;
        zone_low.key_high = 59;

        let mut zone_high = SampleZone::new("High", 72, make_test_samples(4410), 44100);
        zone_high.key_low = 60;
        zone_high.key_high = 127;

        sampler.add_zone(zone_low);
        sampler.add_zone(zone_high);

        // Note 50 should match zone 0 (Low)
        assert_eq!(sampler.find_zone(50, 100), Some(0));
        // Note 70 should match zone 1 (High)
        assert_eq!(sampler.find_zone(70, 100), Some(1));
    }

    #[test]
    fn velocity_zone_selection() {
        let mut sampler = Sampler::new(44100.0);

        let mut zone_soft = SampleZone::new("Soft", 60, make_test_samples(4410), 44100);
        zone_soft.velocity_low = 1;
        zone_soft.velocity_high = 64;

        let mut zone_loud = SampleZone::new("Loud", 60, make_test_samples(4410), 44100);
        zone_loud.velocity_low = 65;
        zone_loud.velocity_high = 127;

        sampler.add_zone(zone_soft);
        sampler.add_zone(zone_loud);

        assert_eq!(sampler.find_zone(60, 50), Some(0));
        assert_eq!(sampler.find_zone(60, 100), Some(1));
        assert_eq!(sampler.find_zone(60, 0), None); // velocity 0 matches neither
    }

    #[test]
    fn oneshot_playback_completes_and_stops() {
        let mut sampler = Sampler::new(44100.0);
        // Very short sample: 100 samples
        let zone = SampleZone::new("Short", 60, vec![0.5; 100], 44100);
        sampler.add_zone(zone);
        sampler.note_on(60, 100, 0);
        assert_eq!(sampler.active_voices(), 1);

        // Process enough frames to exhaust the sample (100 samples at ratio 1.0)
        let mut buf = AudioBuffer::new(2, 256);
        sampler.process(&[], &[], &mut buf);

        // Voice should have deactivated since sample ended (NoLoop mode)
        assert_eq!(sampler.active_voices(), 0);
    }

    #[test]
    fn forward_loop_wraps_correctly() {
        let mut sampler = Sampler::new(44100.0);
        let mut zone = SampleZone::new("Loop", 60, vec![1.0; 200], 44100);
        zone.loop_mode = LoopMode::Forward;
        zone.loop_start = Some(50);
        zone.loop_end = Some(150);
        sampler.add_zone(zone);
        sampler.note_on(60, 100, 0);

        // Process 256 frames — the voice should still be active because it loops
        let mut buf = AudioBuffer::new(2, 256);
        sampler.process(&[], &[], &mut buf);

        assert_eq!(
            sampler.active_voices(),
            1,
            "looping voice should stay active"
        );

        // The play position should have wrapped around and still be in [50, 150)
        let pos = sampler.voices[0].play_pos;
        assert!(
            (50.0..150.0).contains(&pos),
            "play_pos should be in loop range, got {pos}"
        );
    }

    #[test]
    fn pingpong_loop_reverses_direction() {
        let mut sampler = Sampler::new(44100.0);
        let mut zone = SampleZone::new("PingPong", 60, vec![1.0; 200], 44100);
        zone.loop_mode = LoopMode::PingPong;
        zone.loop_start = Some(50);
        zone.loop_end = Some(150);
        sampler.add_zone(zone);
        sampler.note_on(60, 100, 0);

        // Process enough frames to go past loop_end and back
        let mut buf = AudioBuffer::new(2, 256);
        sampler.process(&[], &[], &mut buf);

        assert_eq!(
            sampler.active_voices(),
            1,
            "ping-pong voice should stay active"
        );
        // After 256 frames at ratio ~1.0, direction should have changed at least once
        // The voice should have reversed direction
        let dir = sampler.voices[0].direction;
        // At frame 150, direction reverses to -1, at frame ~50 reverses to 1 again,
        // at frame ~150 reverses to -1 again, etc. After 256 frames it depends on exact pos.
        // Just verify the voice is still active and position is within bounds.
        let pos = sampler.voices[0].play_pos;
        assert!(
            (50.0..=150.0).contains(&pos),
            "play_pos should be in loop range, got {pos}, dir={dir}"
        );
    }

    #[test]
    fn multiple_simultaneous_voices() {
        let mut sampler = Sampler::new(44100.0);
        sampler.add_zone(make_test_zone(60));

        sampler.note_on(60, 100, 0);
        sampler.note_on(64, 100, 0);
        sampler.note_on(67, 100, 0);

        assert_eq!(sampler.active_voices(), 3);

        let mut buf = AudioBuffer::new(2, 256);
        sampler.process(&[], &[], &mut buf);

        let has_nonzero = (0..256).any(|i| buf.get(i, 0).abs() > 0.001);
        assert!(has_nonzero, "multiple voices should produce audio");
    }

    #[test]
    fn note_off_triggers_release() {
        let mut sampler = Sampler::new(44100.0);
        let zone = SampleZone::new("Test", 60, vec![0.5; 44100], 44100);
        sampler.add_zone(zone);
        sampler.note_on(60, 100, 0);
        assert_eq!(sampler.active_voices(), 1);

        sampler.note_off(60, 0);

        // Voice should still be active (in release phase)
        assert_eq!(sampler.active_voices(), 1);

        // Process enough frames for release to complete
        // Default release is 0.3s = 13230 frames at 44100
        for _ in 0..60 {
            let mut buf = AudioBuffer::new(2, 256);
            sampler.process(&[], &[], &mut buf);
        }

        assert_eq!(
            sampler.active_voices(),
            0,
            "voice should finish after release"
        );
    }

    #[test]
    fn reset_clears_all_voices() {
        let mut sampler = Sampler::new(44100.0);
        sampler.add_zone(make_test_zone(60));

        sampler.note_on(60, 100, 0);
        sampler.note_on(64, 100, 0);
        assert_eq!(sampler.active_voices(), 2);

        sampler.reset();
        assert_eq!(sampler.active_voices(), 0);
    }
}

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Step {
    pub active: bool,
    pub velocity: u8,
    pub probability: f32,
    pub accent: bool,
}

impl Default for Step {
    fn default() -> Self {
        Self {
            active: false,
            velocity: 100,
            probability: 1.0,
            accent: false,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PadSequence {
    pub steps: Vec<Step>,
    pub pad_index: usize,
}

impl PadSequence {
    pub fn new(pad_index: usize, step_count: usize) -> Self {
        Self {
            steps: (0..step_count).map(|_| Step::default()).collect(),
            pad_index,
        }
    }
}

pub struct StepSequencer {
    pub sequences: Vec<PadSequence>,
    pub step_count: usize,
    pub swing: f32,
    current_step: usize,
    samples_per_step: f64,
    sample_counter: f64,
    sample_rate: f32,
    bpm: f64,
    // Simple xorshift RNG state
    rng_state: u32,
}

impl StepSequencer {
    pub fn new(step_count: usize, sample_rate: f32, bpm: f64) -> Self {
        let sequences = (0..crate::drum_machine::NUM_PADS)
            .map(|i| PadSequence::new(i, step_count))
            .collect();

        let samples_per_step = sample_rate as f64 * 60.0 / bpm / 4.0;

        Self {
            sequences,
            step_count,
            swing: 0.0,
            current_step: 0,
            samples_per_step,
            sample_counter: 0.0,
            sample_rate,
            bpm,
            rng_state: 12345,
        }
    }

    pub fn set_bpm(&mut self, bpm: f64) {
        self.bpm = bpm;
        self.samples_per_step = self.sample_rate as f64 * 60.0 / bpm / 4.0;
    }

    pub fn set_sample_rate(&mut self, sr: f32) {
        self.sample_rate = sr;
        self.samples_per_step = sr as f64 * 60.0 / self.bpm / 4.0;
    }

    /// Advance by one sample. Returns list of (pad_index, velocity) triggers.
    pub fn tick(&mut self) -> Vec<(usize, u8)> {
        let mut triggers = Vec::new();

        // Calculate the threshold for this step, accounting for swing
        let threshold = if self.current_step % 2 == 1 {
            // Odd steps (even-indexed in musical terms: the "off-beats") get swing delay
            self.samples_per_step + self.swing as f64 * self.samples_per_step * 0.5
        } else {
            self.samples_per_step
        };

        self.sample_counter += 1.0;

        if self.sample_counter >= threshold {
            self.sample_counter -= threshold;

            let current_step = self.current_step;

            // Check each pad's sequence for this step
            for seq in &self.sequences {
                if current_step < seq.steps.len() {
                    let step = &seq.steps[current_step];
                    if step.active && check_probability(&mut self.rng_state, step.probability) {
                        let vel = if step.accent { 127 } else { step.velocity };
                        triggers.push((seq.pad_index, vel));
                    }
                }
            }

            self.current_step = (current_step + 1) % self.step_count;
        }

        triggers
    }

    pub fn reset(&mut self) {
        self.current_step = 0;
        self.sample_counter = 0.0;
    }

    pub fn set_step(&mut self, pad: usize, step: usize, active: bool, velocity: u8) {
        if pad < self.sequences.len() && step < self.sequences[pad].steps.len() {
            self.sequences[pad].steps[step].active = active;
            self.sequences[pad].steps[step].velocity = velocity;
        }
    }

    pub fn current_step(&self) -> usize {
        self.current_step
    }
}

/// Simple xorshift-based probability check.
fn check_probability(rng_state: &mut u32, probability: f32) -> bool {
    if probability >= 1.0 {
        return true;
    }
    if probability <= 0.0 {
        return false;
    }
    // xorshift32
    let mut x = *rng_state;
    x ^= x << 13;
    x ^= x >> 17;
    x ^= x << 5;
    *rng_state = x;
    let random = (x as f32) / (u32::MAX as f32);
    random < probability
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn step_triggers_at_correct_timing() {
        let sample_rate = 44100.0;
        let bpm = 120.0;
        let mut seq = StepSequencer::new(16, sample_rate, bpm);
        // samples_per_step = 44100 * 60 / 120 / 4 = 5512.5

        // Activate step 0 on pad 0
        seq.set_step(0, 0, true, 100);
        // Activate step 1 on pad 0
        seq.set_step(0, 1, true, 80);

        let mut step0_triggered = false;
        let mut step1_triggered = false;
        let mut step0_frame = 0;
        let mut step1_frame = 0;

        // Run through enough samples for 2 steps
        for i in 0..12000 {
            let triggers = seq.tick();
            for &(pad, vel) in &triggers {
                if pad == 0 && vel == 100 && !step0_triggered {
                    step0_triggered = true;
                    step0_frame = i;
                } else if pad == 0 && vel == 80 && !step1_triggered {
                    step1_triggered = true;
                    step1_frame = i;
                }
            }
        }

        assert!(step0_triggered, "step 0 should trigger");
        assert!(step1_triggered, "step 1 should trigger");
        // Step 0 triggers at ~5512 samples, step 1 at ~11025
        let diff = step1_frame - step0_frame;
        assert!(
            (diff as f64 - 5512.5).abs() < 2.0,
            "steps should be ~5512.5 samples apart, got {diff}"
        );
    }

    #[test]
    fn swing_offsets_odd_steps() {
        let sample_rate = 44100.0;
        let bpm = 120.0;

        // Without swing
        let mut seq_no_swing = StepSequencer::new(16, sample_rate, bpm);
        seq_no_swing.set_step(0, 0, true, 100);
        seq_no_swing.set_step(0, 1, true, 100);

        let mut no_swing_frames = Vec::new();
        for i in 0..15000 {
            let triggers = seq_no_swing.tick();
            if triggers.iter().any(|&(p, _)| p == 0) {
                no_swing_frames.push(i);
            }
        }

        // With swing
        let mut seq_swing = StepSequencer::new(16, sample_rate, bpm);
        seq_swing.swing = 0.5;
        seq_swing.set_step(0, 0, true, 100);
        seq_swing.set_step(0, 1, true, 100);

        let mut swing_frames = Vec::new();
        for i in 0..15000 {
            let triggers = seq_swing.tick();
            if triggers.iter().any(|&(p, _)| p == 0) {
                swing_frames.push(i);
            }
        }

        assert!(
            no_swing_frames.len() >= 2,
            "should have at least 2 triggers without swing"
        );
        assert!(
            swing_frames.len() >= 2,
            "should have at least 2 triggers with swing"
        );

        // The second trigger (odd step) should be delayed with swing
        if swing_frames.len() >= 2 && no_swing_frames.len() >= 2 {
            let swing_gap = swing_frames[1] - swing_frames[0];
            let no_swing_gap = no_swing_frames[1] - no_swing_frames[0];
            assert!(
                swing_gap > no_swing_gap,
                "swing should delay the odd step: swing_gap={swing_gap}, no_swing_gap={no_swing_gap}"
            );
        }
    }

    #[test]
    fn probability_zero_never_triggers() {
        let mut seq = StepSequencer::new(16, 44100.0, 120.0);
        seq.set_step(0, 0, true, 100);
        seq.sequences[0].steps[0].probability = 0.0;

        let mut triggered = false;
        for _ in 0..50000 {
            let triggers = seq.tick();
            if triggers.iter().any(|&(p, _)| p == 0) {
                triggered = true;
                break;
            }
        }
        assert!(!triggered, "probability=0 should never trigger");
    }

    #[test]
    fn probability_one_always_triggers() {
        let mut seq = StepSequencer::new(16, 44100.0, 120.0);
        seq.set_step(0, 0, true, 100);
        seq.sequences[0].steps[0].probability = 1.0;

        let mut trigger_count = 0;
        // Run for enough samples to hit step 0 multiple times (16 steps per cycle)
        // At 120 BPM, 16 steps = ~88200 samples
        for _ in 0..200000 {
            let triggers = seq.tick();
            if triggers.iter().any(|&(p, _)| p == 0) {
                trigger_count += 1;
            }
        }
        // Should trigger at least twice (going through the sequence multiple times)
        assert!(
            trigger_count >= 2,
            "probability=1 should always trigger, got {trigger_count} triggers"
        );
    }

    #[test]
    fn set_step_works() {
        let mut seq = StepSequencer::new(16, 44100.0, 120.0);
        assert!(!seq.sequences[0].steps[3].active);
        seq.set_step(0, 3, true, 90);
        assert!(seq.sequences[0].steps[3].active);
        assert_eq!(seq.sequences[0].steps[3].velocity, 90);
    }

    #[test]
    fn reset_goes_to_step_zero() {
        let mut seq = StepSequencer::new(16, 44100.0, 120.0);
        seq.set_step(0, 0, true, 100);

        // Advance past step 0
        for _ in 0..10000 {
            seq.tick();
        }
        assert!(seq.current_step() > 0, "should have advanced past step 0");

        seq.reset();
        assert_eq!(seq.current_step(), 0);
    }

    #[test]
    fn bpm_change_updates_timing() {
        let sample_rate = 44100.0;

        // At 120 BPM
        let mut seq_slow = StepSequencer::new(16, sample_rate, 120.0);
        seq_slow.set_step(0, 0, true, 100);
        seq_slow.set_step(0, 1, true, 100);

        let mut slow_frames = Vec::new();
        for i in 0..20000 {
            let triggers = seq_slow.tick();
            if triggers.iter().any(|&(p, _)| p == 0) {
                slow_frames.push(i);
            }
        }

        // At 240 BPM (double tempo)
        let mut seq_fast = StepSequencer::new(16, sample_rate, 120.0);
        seq_fast.set_bpm(240.0);
        seq_fast.set_step(0, 0, true, 100);
        seq_fast.set_step(0, 1, true, 100);

        let mut fast_frames = Vec::new();
        for i in 0..20000 {
            let triggers = seq_fast.tick();
            if triggers.iter().any(|&(p, _)| p == 0) {
                fast_frames.push(i);
            }
        }

        assert!(slow_frames.len() >= 2);
        assert!(fast_frames.len() >= 2);

        let slow_gap = slow_frames[1] - slow_frames[0];
        let fast_gap = fast_frames[1] - fast_frames[0];

        // Double BPM should halve the gap
        let ratio = slow_gap as f64 / fast_gap as f64;
        assert!(
            (ratio - 2.0).abs() < 0.1,
            "double BPM should halve step gap: ratio={ratio}"
        );
    }

    #[test]
    fn step_count_32_works() {
        let mut seq = StepSequencer::new(32, 44100.0, 120.0);
        assert_eq!(seq.step_count, 32);
        assert_eq!(seq.sequences[0].steps.len(), 32);

        seq.set_step(0, 31, true, 100);
        assert!(seq.sequences[0].steps[31].active);
    }

    #[test]
    fn step_count_64_works() {
        let mut seq = StepSequencer::new(64, 44100.0, 120.0);
        assert_eq!(seq.step_count, 64);
        assert_eq!(seq.sequences[0].steps.len(), 64);

        seq.set_step(0, 63, true, 100);
        assert!(seq.sequences[0].steps[63].active);
    }

    #[test]
    fn step_default_values() {
        let step = Step::default();
        assert!(!step.active);
        assert_eq!(step.velocity, 100);
        assert!((step.probability - 1.0).abs() < f32::EPSILON);
        assert!(!step.accent);
    }

    #[test]
    fn accent_overrides_velocity() {
        let mut seq = StepSequencer::new(16, 44100.0, 120.0);
        seq.set_step(0, 0, true, 50);
        seq.sequences[0].steps[0].accent = true;

        let mut triggered_velocity = None;
        for _ in 0..10000 {
            let triggers = seq.tick();
            for &(pad, vel) in &triggers {
                if pad == 0 {
                    triggered_velocity = Some(vel);
                    break;
                }
            }
            if triggered_velocity.is_some() {
                break;
            }
        }
        assert_eq!(
            triggered_velocity,
            Some(127),
            "accent should override velocity to 127"
        );
    }
}

use shruti_dsp::AudioBuffer;
use shruti_session::midi::{ControlChange, NoteEvent};

use crate::envelope::{AdsrParams, Envelope};
use crate::filter::{Filter, FilterMode};
use crate::instrument::{InstrumentInfo, InstrumentNode, InstrumentParam};
use crate::lfo::{Lfo, LfoShape};
use crate::oscillator::{Oscillator, Waveform};
use crate::voice::{VoiceManager, VoiceStealMode};

/// A subtractive synthesizer.
///
/// Features:
/// - Selectable waveform (sine, saw, square, triangle, noise)
/// - Amp ADSR envelope per voice
/// - Filter ADSR envelope per voice (modulates filter cutoff)
/// - 16-voice polyphony with configurable voice stealing
/// - Detune control
/// - Multi-mode state-variable filter per voice (LP, HP, BP, Notch)
/// - Two global LFOs with configurable targets (none, filter cutoff, pitch, volume)
/// - LFO shape selection (sine, triangle, square, saw up, saw down, S&H)
pub struct SubtractiveSynth {
    info: InstrumentInfo,
    params: Vec<InstrumentParam>,
    voice_manager: VoiceManager,
    oscillators: Vec<Oscillator>,
    envelopes: Vec<Envelope>,
    filter_envelopes: Vec<Envelope>,
    filters: Vec<Filter>,
    lfo1: Lfo,
    lfo2: Lfo,
    sample_rate: f32,
}

// Parameter indices
const PARAM_WAVEFORM: usize = 0;
const PARAM_ATTACK: usize = 1;
const PARAM_DECAY: usize = 2;
const PARAM_SUSTAIN: usize = 3;
const PARAM_RELEASE: usize = 4;
const PARAM_VOLUME: usize = 5;
const PARAM_DETUNE: usize = 6;
const PARAM_FILTER_CUTOFF: usize = 7;
const PARAM_FILTER_RESONANCE: usize = 8;
const PARAM_FILTER_MODE: usize = 9;
// Filter envelope
const PARAM_FILTER_ENV_ATTACK: usize = 10;
const PARAM_FILTER_ENV_DECAY: usize = 11;
const PARAM_FILTER_ENV_SUSTAIN: usize = 12;
const PARAM_FILTER_ENV_RELEASE: usize = 13;
const PARAM_FILTER_ENV_DEPTH: usize = 14;
// LFO 1
const PARAM_LFO1_RATE: usize = 15;
const PARAM_LFO1_DEPTH: usize = 16;
const PARAM_LFO1_TARGET: usize = 17;
const PARAM_LFO1_SHAPE: usize = 18;
// LFO 2
const PARAM_LFO2_RATE: usize = 19;
const PARAM_LFO2_DEPTH: usize = 20;
const PARAM_LFO2_TARGET: usize = 21;
const PARAM_LFO2_SHAPE: usize = 22;

const MAX_VOICES: usize = 16;

impl SubtractiveSynth {
    pub fn new(sample_rate: f32) -> Self {
        let info = InstrumentInfo {
            name: "Subtractive Synth".to_string(),
            category: "Synthesizer".to_string(),
            author: "Shruti".to_string(),
            description: "Subtractive synthesizer with dual ADSR, PolyBLEP oscillators, SVF filter, and dual LFO"
                .to_string(),
        };

        let params = vec![
            // Oscillator
            InstrumentParam::new("Waveform", 0.0, 4.0, 1.0, ""), // 0=Sine,1=Saw,2=Square,3=Tri,4=Noise
            // Amp envelope
            InstrumentParam::new("Attack", 0.001, 5.0, 0.01, "s"),
            InstrumentParam::new("Decay", 0.001, 5.0, 0.1, "s"),
            InstrumentParam::new("Sustain", 0.0, 1.0, 0.7, ""),
            InstrumentParam::new("Release", 0.001, 10.0, 0.3, "s"),
            InstrumentParam::new("Volume", 0.0, 1.0, 0.8, ""),
            InstrumentParam::new("Detune", -100.0, 100.0, 0.0, "cents"),
            // Filter
            InstrumentParam::new("FilterCutoff", 20.0, 20000.0, 20000.0, "Hz"),
            InstrumentParam::new("FilterResonance", 0.0, 1.0, 0.0, ""),
            InstrumentParam::new("FilterMode", 0.0, 3.0, 0.0, ""), // 0=LP,1=HP,2=BP,3=Notch
            // Filter envelope
            InstrumentParam::new("FilterEnvAttack", 0.001, 5.0, 0.01, "s"),
            InstrumentParam::new("FilterEnvDecay", 0.001, 5.0, 0.3, "s"),
            InstrumentParam::new("FilterEnvSustain", 0.0, 1.0, 0.0, ""),
            InstrumentParam::new("FilterEnvRelease", 0.001, 10.0, 0.5, "s"),
            InstrumentParam::new("FilterEnvDepth", -1.0, 1.0, 0.0, ""), // bipolar: -1..+1 scales cutoff modulation
            // LFO 1
            InstrumentParam::new("Lfo1Rate", 0.1, 20.0, 1.0, "Hz"),
            InstrumentParam::new("Lfo1Depth", 0.0, 1.0, 0.0, ""),
            InstrumentParam::new("Lfo1Target", 0.0, 3.0, 0.0, ""), // 0=None,1=Cutoff,2=Pitch,3=Volume
            InstrumentParam::new("Lfo1Shape", 0.0, 5.0, 0.0, ""), // 0=Sine,1=Tri,2=Square,3=SawUp,4=SawDown,5=S&H
            // LFO 2
            InstrumentParam::new("Lfo2Rate", 0.1, 20.0, 1.0, "Hz"),
            InstrumentParam::new("Lfo2Depth", 0.0, 1.0, 0.0, ""),
            InstrumentParam::new("Lfo2Target", 0.0, 3.0, 0.0, ""), // 0=None,1=Cutoff,2=Pitch,3=Volume
            InstrumentParam::new("Lfo2Shape", 0.0, 5.0, 0.0, ""), // 0=Sine,1=Tri,2=Square,3=SawUp,4=SawDown,5=S&H
        ];

        let oscillators = (0..MAX_VOICES)
            .map(|_| Oscillator::new(Waveform::Saw, sample_rate as f64))
            .collect();
        let envelopes = (0..MAX_VOICES)
            .map(|_| Envelope::new(AdsrParams::default(), sample_rate))
            .collect();
        let filter_envelopes = (0..MAX_VOICES)
            .map(|_| {
                Envelope::new(
                    AdsrParams {
                        attack: 0.01,
                        decay: 0.3,
                        sustain: 0.0,
                        release: 0.5,
                    },
                    sample_rate,
                )
            })
            .collect();
        let filters = (0..MAX_VOICES)
            .map(|_| Filter::new(FilterMode::LowPass, 20000.0, 0.0, sample_rate))
            .collect();
        let lfo1 = Lfo::new(LfoShape::Sine, 1.0, 0.0, sample_rate);
        let lfo2 = Lfo::new(LfoShape::Sine, 1.0, 0.0, sample_rate);

        Self {
            info,
            params,
            voice_manager: VoiceManager::new(MAX_VOICES, VoiceStealMode::Oldest),
            oscillators,
            envelopes,
            filter_envelopes,
            filters,
            lfo1,
            lfo2,
            sample_rate,
        }
    }

    fn current_waveform(&self) -> Waveform {
        match self.params[PARAM_WAVEFORM].value.round() as u8 {
            0 => Waveform::Sine,
            1 => Waveform::Saw,
            2 => Waveform::Square,
            3 => Waveform::Triangle,
            _ => Waveform::Noise,
        }
    }

    fn current_adsr(&self) -> AdsrParams {
        AdsrParams {
            attack: self.params[PARAM_ATTACK].value,
            decay: self.params[PARAM_DECAY].value,
            sustain: self.params[PARAM_SUSTAIN].value,
            release: self.params[PARAM_RELEASE].value,
        }
    }

    fn current_filter_adsr(&self) -> AdsrParams {
        AdsrParams {
            attack: self.params[PARAM_FILTER_ENV_ATTACK].value,
            decay: self.params[PARAM_FILTER_ENV_DECAY].value,
            sustain: self.params[PARAM_FILTER_ENV_SUSTAIN].value,
            release: self.params[PARAM_FILTER_ENV_RELEASE].value,
        }
    }

    fn current_filter_mode(&self) -> FilterMode {
        match self.params[PARAM_FILTER_MODE].value.round() as u8 {
            0 => FilterMode::LowPass,
            1 => FilterMode::HighPass,
            2 => FilterMode::BandPass,
            _ => FilterMode::Notch,
        }
    }

    fn lfo_shape_from_param(value: f32) -> LfoShape {
        match value.round() as u8 {
            0 => LfoShape::Sine,
            1 => LfoShape::Triangle,
            2 => LfoShape::Square,
            3 => LfoShape::SawUp,
            4 => LfoShape::SawDown,
            _ => LfoShape::SampleAndHold,
        }
    }

    /// Apply LFO modulation to a target value. Returns (cutoff_mod, pitch_mod, volume_mod).
    fn apply_lfo(lfo_val: f32, target: u8) -> (f32, f32, f32) {
        match target {
            1 => (lfo_val, 0.0, 0.0), // cutoff
            2 => (0.0, lfo_val, 0.0), // pitch
            3 => (0.0, 0.0, lfo_val), // volume
            _ => (0.0, 0.0, 0.0),     // none
        }
    }
}

impl InstrumentNode for SubtractiveSynth {
    fn info(&self) -> &InstrumentInfo {
        &self.info
    }

    fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
        for osc in &mut self.oscillators {
            osc.set_sample_rate(sample_rate as f64);
        }
        for env in &mut self.envelopes {
            env.set_sample_rate(sample_rate);
        }
        for env in &mut self.filter_envelopes {
            env.set_sample_rate(sample_rate);
        }
        for filt in &mut self.filters {
            filt.set_sample_rate(sample_rate);
        }
        self.lfo1.set_sample_rate(sample_rate);
        self.lfo2.set_sample_rate(sample_rate);
    }

    fn process(
        &mut self,
        note_events: &[NoteEvent],
        _control_changes: &[ControlChange],
        output: &mut AudioBuffer,
    ) {
        let frames = output.frames() as usize;
        let channels = output.channels();
        let volume = self.params[PARAM_VOLUME].value;
        let waveform = self.current_waveform();
        let detune = self.params[PARAM_DETUNE].value as f64;
        let filter_cutoff = self.params[PARAM_FILTER_CUTOFF].value;
        let filter_resonance = self.params[PARAM_FILTER_RESONANCE].value;
        let filter_mode = self.current_filter_mode();
        let filter_env_depth = self.params[PARAM_FILTER_ENV_DEPTH].value;

        let lfo1_target = self.params[PARAM_LFO1_TARGET].value.round() as u8;
        let lfo2_target = self.params[PARAM_LFO2_TARGET].value.round() as u8;

        // Update oscillator settings
        for osc in &mut self.oscillators {
            osc.waveform = waveform;
            osc.detune = detune;
        }

        // Update filter settings
        for filt in &mut self.filters {
            filt.mode = filter_mode;
            filt.resonance = filter_resonance;
        }

        // Update LFO settings
        self.lfo1.rate = self.params[PARAM_LFO1_RATE].value;
        self.lfo1.depth = self.params[PARAM_LFO1_DEPTH].value;
        self.lfo1.shape = Self::lfo_shape_from_param(self.params[PARAM_LFO1_SHAPE].value);
        self.lfo2.rate = self.params[PARAM_LFO2_RATE].value;
        self.lfo2.depth = self.params[PARAM_LFO2_DEPTH].value;
        self.lfo2.shape = Self::lfo_shape_from_param(self.params[PARAM_LFO2_SHAPE].value);

        // Process note events at the start of the block
        for event in note_events {
            self.note_on(event.note, event.velocity, event.channel);
        }

        // Pre-compute per-frame LFO values into stack-allocated buffer.
        // Max buffer size for audio is typically 1024-4096 frames; 8192 is generous.
        const MAX_LFO_FRAMES: usize = 8192;
        let clamped_frames = frames.min(MAX_LFO_FRAMES);
        let mut lfo1_values = [0.0f32; MAX_LFO_FRAMES];
        let mut lfo2_values = [0.0f32; MAX_LFO_FRAMES];
        for i in 0..clamped_frames {
            lfo1_values[i] = self.lfo1.tick();
            lfo2_values[i] = self.lfo2.tick();
        }

        // Render each active voice
        let adsr = self.current_adsr();
        let filter_adsr = self.current_filter_adsr();
        for i in 0..MAX_VOICES {
            let voice = &self.voice_manager.voices[i];
            if voice.is_idle() {
                continue;
            }

            self.envelopes[i].params = adsr.clone();
            self.filter_envelopes[i].params = filter_adsr.clone();
            let freq = voice.frequency();
            let vel_gain = voice.velocity as f32 / 127.0;
            let mut phase = voice.phase;

            for frame in 0..clamped_frames {
                let env_level = self.envelopes[i].tick();
                let filter_env_level = self.filter_envelopes[i].tick();

                if self.envelopes[i].is_finished() {
                    self.voice_manager.free_voice(i);
                    break;
                }

                // Sum LFO contributions from both LFOs
                let (c1, p1, v1) = Self::apply_lfo(lfo1_values[frame], lfo1_target);
                let (c2, p2, v2) = Self::apply_lfo(lfo2_values[frame], lfo2_target);
                let cutoff_lfo_mod = c1 + c2;
                let pitch_lfo_mod = p1 + p2;
                let volume_lfo_mod = (v1 + v2).clamp(-1.0, 1.0);

                // Apply LFO pitch modulation (in semitones, depth * 12 max)
                let effective_freq = if pitch_lfo_mod.abs() > 0.0001 {
                    let semitones = pitch_lfo_mod * 12.0;
                    freq * 2.0f64.powf(semitones as f64 / 12.0)
                } else {
                    freq
                };

                let sample = self.oscillators[i].sample(phase, effective_freq);

                // Apply amp envelope
                let after_env = sample * env_level;

                // Compute filter cutoff: base + filter envelope + LFO
                let env_mod_octaves = filter_env_level * filter_env_depth * 4.0;
                let lfo_mod_octaves = cutoff_lfo_mod * 4.0;
                let modulated_cutoff = (filter_cutoff
                    * 2.0f32.powf(env_mod_octaves + lfo_mod_octaves))
                .clamp(20.0, 20000.0);
                self.filters[i].cutoff = modulated_cutoff;

                let filtered = self.filters[i].process_sample(after_env);

                // Apply volume LFO (bipolar mod mapped to 0..1 range)
                let vol_mod = (1.0 + volume_lfo_mod).clamp(0.0, 2.0) * 0.5;
                let out = filtered * vel_gain * volume * vol_mod;

                for ch in 0..channels {
                    let current = output.get(frame as u32, ch);
                    output.set(frame as u32, ch, current + out);
                }

                phase = Oscillator::advance_phase(phase, effective_freq, self.sample_rate as f64);
            }

            self.voice_manager.voices[i].phase = phase;
            self.voice_manager.voices[i].envelope_level = self.envelopes[i].level;
        }

        self.voice_manager.tick_age();
    }

    fn note_on(&mut self, note: u8, velocity: u8, channel: u8) {
        if let Some(idx) = self.voice_manager.note_on(note, velocity, channel) {
            self.envelopes[idx].params = self.current_adsr();
            self.envelopes[idx].trigger();
            self.filter_envelopes[idx].params = self.current_filter_adsr();
            self.filter_envelopes[idx].trigger();
            self.filters[idx].reset();
        }
    }

    fn note_off(&mut self, note: u8, channel: u8) {
        for (i, voice) in self.voice_manager.voices.iter().enumerate() {
            if voice.note == note && voice.channel == channel && !voice.is_idle() {
                self.envelopes[i].release();
                self.filter_envelopes[i].release();
            }
        }
        self.voice_manager.note_off(note, channel);
    }

    fn params(&self) -> &[InstrumentParam] {
        &self.params
    }

    fn params_mut(&mut self) -> &mut [InstrumentParam] {
        &mut self.params
    }

    fn reset(&mut self) {
        self.voice_manager.reset();
        for env in &mut self.envelopes {
            env.reset();
        }
        for env in &mut self.filter_envelopes {
            env.reset();
        }
        for filt in &mut self.filters {
            filt.reset();
        }
        self.lfo1.reset();
        self.lfo2.reset();
    }

    fn active_voices(&self) -> usize {
        self.voice_manager.active_count()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn synth_creates_with_defaults() {
        let synth = SubtractiveSynth::new(48000.0);
        assert_eq!(synth.info().name, "Subtractive Synth");
        assert_eq!(synth.params().len(), 23);
        assert_eq!(synth.active_voices(), 0);
    }

    #[test]
    fn synth_note_on_activates_voice() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.note_on(60, 100, 0);
        assert_eq!(synth.active_voices(), 1);
    }

    #[test]
    fn synth_note_off_releases() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.note_on(60, 100, 0);
        synth.note_off(60, 0);
        assert_eq!(synth.active_voices(), 1);
    }

    #[test]
    fn synth_produces_audio() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.note_on(69, 127, 0);

        let mut buf = AudioBuffer::new(2, 256);
        synth.process(&[], &[], &mut buf);

        let mut has_nonzero = false;
        for i in 0..256 {
            if buf.get(i, 0).abs() > 0.001 {
                has_nonzero = true;
                break;
            }
        }
        assert!(has_nonzero, "synth should produce audio output");
    }

    #[test]
    fn synth_silence_without_notes() {
        let mut synth = SubtractiveSynth::new(48000.0);
        let mut buf = AudioBuffer::new(2, 256);
        synth.process(&[], &[], &mut buf);

        for i in 0..256 {
            assert_eq!(buf.get(i, 0), 0.0);
        }
    }

    #[test]
    fn synth_reset_clears_voices() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.note_on(60, 100, 0);
        synth.note_on(64, 100, 0);
        assert_eq!(synth.active_voices(), 2);
        synth.reset();
        assert_eq!(synth.active_voices(), 0);
    }

    #[test]
    fn synth_params_are_settable() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.params_mut()[PARAM_VOLUME].set(0.5);
        assert!((synth.params()[PARAM_VOLUME].value - 0.5).abs() < 0.001);
    }

    // --- New tests for filter and LFO ---

    /// Helper: render a synth playing a saw wave at A4 and return RMS of output.
    fn render_rms(synth: &mut SubtractiveSynth, num_frames: usize) -> f32 {
        let mut buf = AudioBuffer::new(2, num_frames as u32);
        synth.process(&[], &[], &mut buf);
        let mut sum_sq = 0.0f64;
        for i in 0..num_frames {
            let s = buf.get(i as u32, 0) as f64;
            sum_sq += s * s;
        }
        (sum_sq / num_frames as f64).sqrt() as f32
    }

    #[test]
    fn filter_lowpass_attenuates_bright_content() {
        let mut synth_open = SubtractiveSynth::new(48000.0);
        synth_open.params_mut()[PARAM_WAVEFORM].set(1.0);
        synth_open.params_mut()[PARAM_FILTER_CUTOFF].set(20000.0);
        synth_open.note_on(69, 127, 0);
        let rms_open = render_rms(&mut synth_open, 4096);

        let mut synth_filtered = SubtractiveSynth::new(48000.0);
        synth_filtered.params_mut()[PARAM_WAVEFORM].set(1.0);
        synth_filtered.params_mut()[PARAM_FILTER_CUTOFF].set(200.0);
        synth_filtered.note_on(69, 127, 0);
        let rms_filtered = render_rms(&mut synth_filtered, 4096);

        assert!(
            rms_filtered < rms_open,
            "Filtered saw should have lower RMS: open={rms_open}, filtered={rms_filtered}"
        );
    }

    #[test]
    fn filter_highpass_removes_low_content() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.params_mut()[PARAM_WAVEFORM].set(0.0);
        synth.params_mut()[PARAM_FILTER_MODE].set(1.0);
        synth.params_mut()[PARAM_FILTER_CUTOFF].set(5000.0);
        synth.note_on(48, 127, 0);

        let mut buf = AudioBuffer::new(2, 8192);
        synth.process(&[], &[], &mut buf);

        let mut sum_sq = 0.0f64;
        for i in 4096..8192 {
            let s = buf.get(i as u32, 0) as f64;
            sum_sq += s * s;
        }
        let rms = (sum_sq / 4096.0).sqrt() as f32;
        assert!(
            rms < 0.05,
            "HP filter at 5kHz should attenuate 130Hz sine, got rms={rms}"
        );
    }

    #[test]
    fn lfo1_modulates_filter_cutoff() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.params_mut()[PARAM_WAVEFORM].set(1.0);
        synth.params_mut()[PARAM_FILTER_CUTOFF].set(500.0);
        synth.params_mut()[PARAM_LFO1_TARGET].set(1.0); // Cutoff
        synth.params_mut()[PARAM_LFO1_RATE].set(5.0);
        synth.params_mut()[PARAM_LFO1_DEPTH].set(1.0);
        synth.note_on(69, 127, 0);

        let rms1 = render_rms(&mut synth, 2048);
        let rms2 = render_rms(&mut synth, 2048);

        assert!(
            rms1 > 0.001 || rms2 > 0.001,
            "Synth should produce output with LFO modulation"
        );
    }

    #[test]
    fn lfo1_modulates_pitch() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.params_mut()[PARAM_WAVEFORM].set(0.0);
        synth.params_mut()[PARAM_LFO1_TARGET].set(2.0); // Pitch
        synth.params_mut()[PARAM_LFO1_RATE].set(5.0);
        synth.params_mut()[PARAM_LFO1_DEPTH].set(0.5);
        synth.note_on(69, 127, 0);

        let mut buf = AudioBuffer::new(2, 4096);
        synth.process(&[], &[], &mut buf);

        let mut has_nonzero = false;
        for i in 0..4096 {
            if buf.get(i, 0).abs() > 0.001 {
                has_nonzero = true;
                break;
            }
        }
        assert!(
            has_nonzero,
            "Synth with LFO pitch modulation should produce output"
        );
    }

    #[test]
    fn lfo2_modulates_volume() {
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.params_mut()[PARAM_WAVEFORM].set(0.0);
        synth.params_mut()[PARAM_LFO2_TARGET].set(3.0); // Volume (tremolo)
        synth.params_mut()[PARAM_LFO2_RATE].set(5.0);
        synth.params_mut()[PARAM_LFO2_DEPTH].set(1.0);
        synth.params_mut()[PARAM_LFO2_SHAPE].set(2.0); // Square LFO
        synth.note_on(69, 127, 0);

        let mut buf = AudioBuffer::new(2, 4096);
        synth.process(&[], &[], &mut buf);

        let mut has_nonzero = false;
        for i in 0..4096 {
            if buf.get(i, 0).abs() > 0.001 {
                has_nonzero = true;
                break;
            }
        }
        assert!(
            has_nonzero,
            "Synth with LFO2 volume modulation should produce output"
        );
    }

    #[test]
    fn filter_envelope_modulates_cutoff() {
        // With filter env depth > 0 and low base cutoff, the filter envelope
        // should open the filter on note-on then close it during decay.
        let mut synth_no_env = SubtractiveSynth::new(48000.0);
        synth_no_env.params_mut()[PARAM_WAVEFORM].set(1.0);
        synth_no_env.params_mut()[PARAM_FILTER_CUTOFF].set(200.0);
        synth_no_env.params_mut()[PARAM_FILTER_ENV_DEPTH].set(0.0);
        synth_no_env.note_on(69, 127, 0);
        let rms_no_env = render_rms(&mut synth_no_env, 4096);

        let mut synth_env = SubtractiveSynth::new(48000.0);
        synth_env.params_mut()[PARAM_WAVEFORM].set(1.0);
        synth_env.params_mut()[PARAM_FILTER_CUTOFF].set(200.0);
        synth_env.params_mut()[PARAM_FILTER_ENV_DEPTH].set(1.0);
        synth_env.params_mut()[PARAM_FILTER_ENV_ATTACK].set(0.001);
        synth_env.params_mut()[PARAM_FILTER_ENV_DECAY].set(0.5);
        synth_env.note_on(69, 127, 0);
        let rms_env = render_rms(&mut synth_env, 4096);

        // Filter envelope opening the cutoff should increase RMS
        assert!(
            rms_env > rms_no_env,
            "Filter envelope should open cutoff: with_env={rms_env}, without={rms_no_env}"
        );
    }

    #[test]
    fn dual_lfo_both_active() {
        // LFO1 on cutoff + LFO2 on pitch simultaneously
        let mut synth = SubtractiveSynth::new(48000.0);
        synth.params_mut()[PARAM_WAVEFORM].set(1.0);
        synth.params_mut()[PARAM_FILTER_CUTOFF].set(1000.0);
        synth.params_mut()[PARAM_LFO1_TARGET].set(1.0); // Cutoff
        synth.params_mut()[PARAM_LFO1_RATE].set(3.0);
        synth.params_mut()[PARAM_LFO1_DEPTH].set(0.5);
        synth.params_mut()[PARAM_LFO2_TARGET].set(2.0); // Pitch
        synth.params_mut()[PARAM_LFO2_RATE].set(7.0);
        synth.params_mut()[PARAM_LFO2_DEPTH].set(0.3);
        synth.note_on(69, 127, 0);

        let rms = render_rms(&mut synth, 4096);
        assert!(rms > 0.001, "Dual LFO synth should produce output");
    }

    #[test]
    fn different_filter_modes_produce_different_output() {
        fn render_with_mode(mode: f32) -> Vec<f32> {
            let mut synth = SubtractiveSynth::new(48000.0);
            synth.params_mut()[PARAM_WAVEFORM].set(1.0);
            synth.params_mut()[PARAM_FILTER_CUTOFF].set(1000.0);
            synth.params_mut()[PARAM_FILTER_RESONANCE].set(0.5);
            synth.params_mut()[PARAM_FILTER_MODE].set(mode);
            synth.note_on(69, 127, 0);

            let mut buf = AudioBuffer::new(2, 2048);
            synth.process(&[], &[], &mut buf);

            (0..2048).map(|i| buf.get(i, 0)).collect()
        }

        let lp = render_with_mode(0.0);
        let hp = render_with_mode(1.0);
        let bp = render_with_mode(2.0);

        let diff_lp_hp: f32 = lp.iter().zip(hp.iter()).map(|(a, b)| (a - b).abs()).sum();
        let diff_lp_bp: f32 = lp.iter().zip(bp.iter()).map(|(a, b)| (a - b).abs()).sum();

        assert!(
            diff_lp_hp > 1.0,
            "LP and HP should produce different output, diff={diff_lp_hp}"
        );
        assert!(
            diff_lp_bp > 1.0,
            "LP and BP should produce different output, diff={diff_lp_bp}"
        );
    }
}

use serde::{Deserialize, Serialize};

/// Voice state.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum VoiceState {
    /// Voice is not producing sound.
    Idle,
    /// Voice is actively playing.
    Active,
    /// Voice is in its release phase.
    Releasing,
}

/// How to steal voices when max polyphony is reached.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum VoiceStealMode {
    /// Steal the oldest voice.
    Oldest,
    /// Steal the quietest voice.
    Quietest,
    /// Steal the lowest-pitched voice.
    Lowest,
    /// Don't steal — ignore new notes.
    None,
}

/// A single voice slot.
#[derive(Debug, Clone)]
pub struct Voice {
    pub state: VoiceState,
    pub note: u8,
    pub velocity: u8,
    pub channel: u8,
    /// Phase accumulator (for oscillators).
    pub phase: f64,
    /// Per-voice amplitude envelope level.
    pub envelope_level: f32,
    /// Age counter — increments each process block while active.
    pub age: u64,
}

impl Voice {
    pub fn new() -> Self {
        Self {
            state: VoiceState::Idle,
            note: 0,
            velocity: 0,
            channel: 0,
            phase: 0.0,
            envelope_level: 0.0,
            age: 0,
        }
    }

    pub fn is_idle(&self) -> bool {
        self.state == VoiceState::Idle
    }

    pub fn is_active(&self) -> bool {
        self.state == VoiceState::Active || self.state == VoiceState::Releasing
    }

    /// Frequency in Hz for this voice's MIDI note.
    pub fn frequency(&self) -> f64 {
        440.0 * 2.0f64.powf((self.note as f64 - 69.0) / 12.0)
    }
}

impl Default for Voice {
    fn default() -> Self {
        Self::new()
    }
}

/// Manages a pool of voices with configurable polyphony and voice stealing.
pub struct VoiceManager {
    pub voices: Vec<Voice>,
    pub max_voices: usize,
    pub steal_mode: VoiceStealMode,
}

impl VoiceManager {
    pub fn new(max_voices: usize, steal_mode: VoiceStealMode) -> Self {
        let voices = (0..max_voices).map(|_| Voice::new()).collect();
        Self {
            voices,
            max_voices,
            steal_mode,
        }
    }

    /// Allocate a voice for a note-on. Returns the voice index, or None if no voice available.
    pub fn note_on(&mut self, note: u8, velocity: u8, channel: u8) -> Option<usize> {
        // First: look for an idle voice
        if let Some(idx) = self.voices.iter().position(|v| v.is_idle()) {
            self.activate_voice(idx, note, velocity, channel);
            return Some(idx);
        }

        // Second: try voice stealing
        let steal_idx = match self.steal_mode {
            VoiceStealMode::Oldest => self
                .voices
                .iter()
                .enumerate()
                .max_by_key(|(_, v)| v.age)
                .map(|(i, _)| i),
            VoiceStealMode::Quietest => self
                .voices
                .iter()
                .enumerate()
                .min_by(|(_, a), (_, b)| {
                    a.envelope_level
                        .partial_cmp(&b.envelope_level)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
                .map(|(i, _)| i),
            VoiceStealMode::Lowest => self
                .voices
                .iter()
                .enumerate()
                .min_by_key(|(_, v)| v.note)
                .map(|(i, _)| i),
            VoiceStealMode::None => None,
        };

        if let Some(idx) = steal_idx {
            self.activate_voice(idx, note, velocity, channel);
            Some(idx)
        } else {
            None
        }
    }

    /// Release voice(s) playing a specific note.
    pub fn note_off(&mut self, note: u8, channel: u8) {
        for voice in &mut self.voices {
            if voice.note == note && voice.channel == channel && voice.state == VoiceState::Active {
                voice.state = VoiceState::Releasing;
            }
        }
    }

    /// Mark a voice as idle (called when envelope finishes release).
    pub fn free_voice(&mut self, index: usize) {
        if index < self.voices.len() {
            self.voices[index].state = VoiceState::Idle;
            self.voices[index].age = 0;
        }
    }

    /// Number of active (non-idle) voices.
    pub fn active_count(&self) -> usize {
        self.voices.iter().filter(|v| !v.is_idle()).count()
    }

    /// Increment age of all active voices. Call once per process block.
    pub fn tick_age(&mut self) {
        for voice in &mut self.voices {
            if voice.is_active() {
                voice.age += 1;
            }
        }
    }

    /// Reset all voices to idle.
    pub fn reset(&mut self) {
        for voice in &mut self.voices {
            *voice = Voice::new();
        }
    }

    fn activate_voice(&mut self, idx: usize, note: u8, velocity: u8, channel: u8) {
        let voice = &mut self.voices[idx];
        voice.state = VoiceState::Active;
        voice.note = note;
        voice.velocity = velocity;
        voice.channel = channel;
        voice.phase = 0.0;
        voice.envelope_level = 1.0;
        voice.age = 0;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn voice_frequency_a4() {
        let mut v = Voice::new();
        v.note = 69;
        assert!((v.frequency() - 440.0).abs() < 0.01);
    }

    #[test]
    fn voice_frequency_middle_c() {
        let mut v = Voice::new();
        v.note = 60;
        assert!((v.frequency() - 261.63).abs() < 0.1);
    }

    #[test]
    fn voice_manager_allocates_voices() {
        let mut vm = VoiceManager::new(4, VoiceStealMode::Oldest);
        assert_eq!(vm.active_count(), 0);
        vm.note_on(60, 100, 0);
        assert_eq!(vm.active_count(), 1);
        vm.note_on(64, 100, 0);
        assert_eq!(vm.active_count(), 2);
    }

    #[test]
    fn voice_manager_note_off_releases() {
        let mut vm = VoiceManager::new(4, VoiceStealMode::Oldest);
        vm.note_on(60, 100, 0);
        vm.note_off(60, 0);
        // Voice should be Releasing, not Idle
        assert_eq!(vm.voices[0].state, VoiceState::Releasing);
        assert_eq!(vm.active_count(), 1); // Still active (releasing)
    }

    #[test]
    fn voice_manager_free_voice() {
        let mut vm = VoiceManager::new(4, VoiceStealMode::Oldest);
        vm.note_on(60, 100, 0);
        vm.free_voice(0);
        assert_eq!(vm.active_count(), 0);
    }

    #[test]
    fn voice_manager_steal_oldest() {
        let mut vm = VoiceManager::new(2, VoiceStealMode::Oldest);
        vm.note_on(60, 100, 0);
        vm.tick_age(); // voice 0 age = 1
        vm.note_on(64, 100, 0);
        vm.tick_age(); // voice 0 age = 2, voice 1 age = 1
        // All voices full, steal oldest (voice 0)
        let idx = vm.note_on(67, 100, 0);
        assert_eq!(idx, Some(0));
        assert_eq!(vm.voices[0].note, 67);
    }

    #[test]
    fn voice_manager_steal_none_rejects() {
        let mut vm = VoiceManager::new(2, VoiceStealMode::None);
        vm.note_on(60, 100, 0);
        vm.note_on(64, 100, 0);
        let idx = vm.note_on(67, 100, 0);
        assert_eq!(idx, None);
    }

    #[test]
    fn voice_manager_reset() {
        let mut vm = VoiceManager::new(4, VoiceStealMode::Oldest);
        vm.note_on(60, 100, 0);
        vm.note_on(64, 100, 0);
        vm.reset();
        assert_eq!(vm.active_count(), 0);
    }

    #[test]
    fn voice_manager_steal_lowest() {
        let mut vm = VoiceManager::new(2, VoiceStealMode::Lowest);
        vm.note_on(60, 100, 0); // C4
        vm.note_on(72, 100, 0); // C5
        // Steal lowest (note 60)
        let idx = vm.note_on(64, 100, 0);
        assert_eq!(idx, Some(0));
        assert_eq!(vm.voices[0].note, 64);
    }
}

use serde::{Deserialize, Serialize};

/// Supported plugin formats.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum PluginFormat {
    /// CLAP (CLever Audio Plugin) — modern, open standard.
    Clap,
    /// VST3 — Steinberg's plugin format.
    Vst3,
    /// Native Rust plugin — Shruti's built-in plugin API.
    Native,
}

impl PluginFormat {
    /// File extension for this format's plugin bundles.
    pub fn extension(&self) -> &str {
        match self {
            Self::Clap => "clap",
            Self::Vst3 => "vst3",
            Self::Native => "so", // .so on Linux, .dylib on macOS, .dll on Windows
        }
    }

    /// Standard search paths for this format on the current platform.
    pub fn search_paths(&self) -> Vec<String> {
        match self {
            Self::Clap => clap_search_paths(),
            Self::Vst3 => vst3_search_paths(),
            Self::Native => native_search_paths(),
        }
    }
}

fn clap_search_paths() -> Vec<String> {
    let mut paths = Vec::new();

    #[cfg(target_os = "linux")]
    {
        if let Ok(home) = std::env::var("HOME") {
            paths.push(format!("{home}/.clap"));
        }
        paths.push("/usr/lib/clap".into());
        paths.push("/usr/local/lib/clap".into());
    }

    #[cfg(target_os = "macos")]
    {
        if let Ok(home) = std::env::var("HOME") {
            paths.push(format!("{home}/Library/Audio/Plug-Ins/CLAP"));
        }
        paths.push("/Library/Audio/Plug-Ins/CLAP".into());
    }

    #[cfg(target_os = "windows")]
    {
        if let Ok(common) = std::env::var("CommonProgramFiles") {
            paths.push(format!("{common}\\CLAP"));
        }
        if let Ok(local) = std::env::var("LOCALAPPDATA") {
            paths.push(format!("{local}\\Programs\\Common\\CLAP"));
        }
    }

    paths
}

fn vst3_search_paths() -> Vec<String> {
    let mut paths = Vec::new();

    #[cfg(target_os = "linux")]
    {
        if let Ok(home) = std::env::var("HOME") {
            paths.push(format!("{home}/.vst3"));
        }
        paths.push("/usr/lib/vst3".into());
        paths.push("/usr/local/lib/vst3".into());
    }

    #[cfg(target_os = "macos")]
    {
        if let Ok(home) = std::env::var("HOME") {
            paths.push(format!("{home}/Library/Audio/Plug-Ins/VST3"));
        }
