        }
    }

    paths
}

fn native_search_paths() -> Vec<String> {
    let mut paths = Vec::new();

    #[cfg(target_os = "linux")]
    {
        if let Ok(home) = std::env::var("HOME") {
            paths.push(format!("{home}/.shruti/plugins"));
        }
