/// An editing command that can be applied and undone.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum EditCommand {
    /// Add a region to a track.
    AddRegion { track_id: TrackId, region: Region },
    /// Remove a region from a track.
    RemoveRegion {
        track_id: TrackId,
        region_id: RegionId,
        /// The removed region, stored for undo.
        region: Option<Region>,
    },
    /// Move a region to a new timeline position.
    MoveRegion {
        track_id: TrackId,
        region_id: RegionId,
        old_pos: u64,
        new_pos: u64,
    },
    /// Move a region from one track to another.
    MoveRegionToTrack {
        from_track: TrackId,
        to_track: TrackId,
        region_id: RegionId,
        old_pos: u64,
        new_pos: u64,
        /// Stored for undo.
        region: Option<Region>,
    },
    /// Split a region at a frame position, replacing it with two new regions.
    SplitRegion {
        track_id: TrackId,
        region_id: RegionId,
        split_frame: u64,
        /// The original region before split, stored for undo.
        original: Option<Region>,
        /// The two resulting regions after split.
        left_id: Option<RegionId>,
        right_id: Option<RegionId>,
    },
    /// Trim the start of a region.
    TrimStart {
        track_id: TrackId,
        region_id: RegionId,
        old_start: u64,
        old_offset: u64,
        old_duration: u64,
        new_start: u64,
    },
    /// Trim the end of a region.
    TrimEnd {
        track_id: TrackId,
        region_id: RegionId,
        old_duration: u64,
        new_end: u64,
    },
    /// Set fade-in duration on a region.
    SetFadeIn {
        track_id: TrackId,
        region_id: RegionId,
        old_fade: u64,
        new_fade: u64,
    },
    /// Set fade-out duration on a region.
    SetFadeOut {
        track_id: TrackId,
        region_id: RegionId,
        old_fade: u64,
        new_fade: u64,
    },
    /// Set region gain.
    SetRegionGain {
        track_id: TrackId,
        region_id: RegionId,
        old_gain: f32,
        new_gain: f32,
    },
    /// Set track gain.
    SetTrackGain {
        track_id: TrackId,
        old_gain: f32,
        new_gain: f32,
    },
    /// Set track pan.
    SetTrackPan {
        track_id: TrackId,
        old_pan: f32,
        new_pan: f32,
    },
    /// Toggle track mute.
    ToggleTrackMute { track_id: TrackId },
    /// Toggle track solo.
    ToggleTrackSolo { track_id: TrackId },
    /// Move a track from one index to another.
    MoveTrack { from_index: usize, to_index: usize },
    /// Set an instrument parameter on a track by index.
    SetInstrumentParam {
        track_id: TrackId,
        param_index: usize,
        old_value: f32,
        new_value: f32,
    },
    /// Compound command (multiple edits as one undoable action).
    Compound { commands: Vec<EditCommand> },
}

use std::fmt;

/// Errors that can occur in session management.
#[derive(Debug)]
pub enum SessionError {
    /// File I/O error.
    Io(std::io::Error),
    /// Database error.
    Database(String),
    /// Serialization/deserialization error.
    Serialization(String),
    /// Track not found.
    TrackNotFound(String),
    /// Region not found.
    RegionNotFound(String),
    /// Invalid operation.
    InvalidOperation(String),
    /// Audio processing error.
    Audio(String),
}

impl fmt::Display for SessionError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            SessionError::Io(e) => write!(f, "I/O error: {e}"),
            SessionError::Database(msg) => write!(f, "database error: {msg}"),
            SessionError::Serialization(msg) => write!(f, "serialization error: {msg}"),
            SessionError::TrackNotFound(name) => write!(f, "track not found: {name}"),
            SessionError::RegionNotFound(id) => write!(f, "region not found: {id}"),
            SessionError::InvalidOperation(msg) => write!(f, "invalid operation: {msg}"),
            SessionError::Audio(msg) => write!(f, "audio error: {msg}"),
        }
    }
}

impl std::error::Error for SessionError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            SessionError::Io(e) => Some(e),
            _ => None,
        }
    }
}

impl From<std::io::Error> for SessionError {
    fn from(e: std::io::Error) -> Self {
        SessionError::Io(e)
    }
}

impl From<rusqlite::Error> for SessionError {
    fn from(e: rusqlite::Error) -> Self {
        SessionError::Database(e.to_string())
    }
}

impl From<serde_json::Error> for SessionError {
    fn from(e: serde_json::Error) -> Self {
        SessionError::Serialization(e.to_string())
    }
}

