/// A single MIDI note event on a track.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NoteEvent {
    /// Start position in frames.
    pub position: u64,
    /// Duration in frames.
    pub duration: u64,
    /// MIDI note number (0-127).
    pub note: u8,
    /// Velocity (0-127).
    pub velocity: u8,
    /// MIDI channel (0-15).
    pub channel: u8,
}

/// A MIDI control change event.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ControlChange {
    /// Position in frames.
    pub position: u64,
    /// CC number (0-127).
    pub controller: u8,
    /// CC value (0-127).
    pub value: u8,
    /// MIDI channel (0-15).
    pub channel: u8,
}

/// A MIDI clip containing note and CC events.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MidiClip {
    /// Clip name.
    pub name: String,
    /// Note events in this clip.
    pub notes: Vec<NoteEvent>,
    /// Control change events.
    pub control_changes: Vec<ControlChange>,
    /// Position on the timeline in frames.
    pub timeline_pos: u64,
    /// Duration of the clip in frames.
    pub duration: u64,
}

impl MidiClip {
    pub fn new(name: impl Into<String>, timeline_pos: u64, duration: u64) -> Self {
        Self {
            name: name.into(),
            notes: Vec::new(),
            control_changes: Vec::new(),
            timeline_pos,
            duration,
        }
    }

    /// Add a note event.
    pub fn add_note(&mut self, position: u64, duration: u64, note: u8, velocity: u8, channel: u8) {
        self.notes.push(NoteEvent {
            position,
            duration,
            note,
            velocity,
            channel,
        });
    }

    /// Add a control change event.
    pub fn add_cc(&mut self, position: u64, controller: u8, value: u8, channel: u8) {
        self.control_changes.push(ControlChange {
            position,
            controller,
            value,
            channel,
        });
    }

    /// Get the end position on the timeline.
    pub fn end_pos(&self) -> u64 {
        self.timeline_pos + self.duration
    }

    /// Get notes active at a given frame position.
    pub fn notes_at(&self, frame: u64) -> Vec<&NoteEvent> {
        self.notes
            .iter()
            .filter(|n| {
                let abs_pos = self.timeline_pos + n.position;
                frame >= abs_pos && frame < abs_pos + n.duration
            })
            .collect()
    }

    /// Get note-on events at exactly the given frame.
    pub fn note_ons_at(&self, frame: u64) -> Vec<&NoteEvent> {
        self.notes
            .iter()
            .filter(|n| self.timeline_pos + n.position == frame)
            .collect()
    }

    /// Get note-off events at exactly the given frame.
    pub fn note_offs_at(&self, frame: u64) -> Vec<&NoteEvent> {
        self.notes
            .iter()
            .filter(|n| self.timeline_pos + n.position + n.duration == frame)
            .collect()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_midi_clip_creation() {
        let mut clip = MidiClip::new("Chorus", 0, 48000);
        clip.add_note(0, 12000, 60, 100, 0);
        clip.add_note(12000, 12000, 64, 90, 0);
        clip.add_cc(0, 1, 64, 0);

        assert_eq!(clip.name, "Chorus");
        assert_eq!(clip.notes.len(), 2);
        assert_eq!(clip.control_changes.len(), 1);
        assert_eq!(clip.notes[0].note, 60);
        assert_eq!(clip.notes[0].velocity, 100);
        assert_eq!(clip.notes[1].note, 64);
        assert_eq!(clip.control_changes[0].controller, 1);
        assert_eq!(clip.control_changes[0].value, 64);
        assert_eq!(clip.end_pos(), 48000);
    }

    #[test]
    fn test_notes_at() {
        let mut clip = MidiClip::new("Test", 1000, 48000);
        // Note at relative position 0, duration 500 -> absolute 1000..1500
        clip.add_note(0, 500, 60, 100, 0);
        // Note at relative position 200, duration 300 -> absolute 1200..1500
        clip.add_note(200, 300, 64, 80, 0);

        // Frame 1000: only note 60 is active (starts at 1000)
        let active = clip.notes_at(1000);
        assert_eq!(active.len(), 1);
        assert_eq!(active[0].note, 60);

        // Frame 1200: both notes active
        let active = clip.notes_at(1200);
        assert_eq!(active.len(), 2);

        // Frame 1500: neither active (end is exclusive)
        let active = clip.notes_at(1500);
        assert_eq!(active.len(), 0);

        // Frame 999: nothing active yet
        let active = clip.notes_at(999);
        assert_eq!(active.len(), 0);
    }

    #[test]
    fn test_note_ons_offs() {
        let mut clip = MidiClip::new("Test", 0, 48000);
        clip.add_note(100, 400, 60, 100, 0);
        clip.add_note(100, 200, 64, 80, 0);
        clip.add_note(500, 100, 67, 90, 0);

        // Note-ons at frame 100: notes 60 and 64
        let ons = clip.note_ons_at(100);
        assert_eq!(ons.len(), 2);

        // Note-ons at frame 500: note 67
        let ons = clip.note_ons_at(500);
        assert_eq!(ons.len(), 1);
        assert_eq!(ons[0].note, 67);

        // Note-offs at frame 300: note 64 (100 + 200)
        let offs = clip.note_offs_at(300);
        assert_eq!(offs.len(), 1);
        assert_eq!(offs[0].note, 64);

        // Note-offs at frame 500: note 60 (100 + 400)
        let offs = clip.note_offs_at(500);
        assert_eq!(offs.len(), 1);
        assert_eq!(offs[0].note, 60);

        // Note-offs at frame 600: note 67 (500 + 100)
        let offs = clip.note_offs_at(600);
        assert_eq!(offs.len(), 1);
        assert_eq!(offs[0].note, 67);
    }
}

use serde::{Deserialize, Serialize};
use std::path::{Path, PathBuf};

/// Recording configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RecordingConfig {
    /// Recording sample rate in Hz (e.g. 44100, 48000, 88200, 96000, 176400, 192000).
    pub sample_rate: u32,
    /// Number of recording channels (1 = mono, 2 = stereo, up to 8).
    pub channels: u16,
    /// Maximum recording duration in seconds (0 = unlimited up to memory cap).
    pub max_duration_secs: u32,
    /// Recording buffer size in frames (for the input stream callback).
    pub buffer_size: u32,
    /// Preferred input device name (None = system default).
    pub input_device: Option<String>,
}

impl RecordingConfig {
    /// Standard recording rates supported.
    pub const SUPPORTED_RATES: &[u32] = &[44100, 48000, 88200, 96000, 176400, 192000];

    /// Maximum allowed channels.
    pub const MAX_CHANNELS: u16 = 8;

    /// Calculate the maximum number of samples this config allows in the buffer.
    /// Returns the cap in total interleaved samples (frames * channels).
    pub fn max_buffer_samples(&self) -> usize {
        let duration = if self.max_duration_secs == 0 {
            1800 // Default 30 min if unlimited
        } else {
            self.max_duration_secs as usize
        };
        self.sample_rate as usize * self.channels as usize * duration
    }

    /// Validate the config, clamping values to safe ranges.
    pub fn validated(mut self) -> Self {
        if !Self::SUPPORTED_RATES.contains(&self.sample_rate) {
            // Snap to nearest supported rate
            self.sample_rate = *Self::SUPPORTED_RATES
                .iter()
                .min_by_key(|&&r| (r as i64 - self.sample_rate as i64).unsigned_abs())
                .unwrap_or(&48000);
        }
        self.channels = self.channels.clamp(1, Self::MAX_CHANNELS);
        self.buffer_size = self.buffer_size.clamp(64, 4096);
        self
    }
}

impl Default for RecordingConfig {
    fn default() -> Self {
        Self {
            sample_rate: 48000,
            channels: 2,
            max_duration_secs: 1800, // 30 minutes
            buffer_size: 256,
            input_device: None,
        }
    }
}

/// Application preferences persisted between sessions.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Preferences {
    /// Preferred audio device name (None = system default).
    pub audio_device: Option<String>,
    /// Sample rate in Hz.
    pub sample_rate: u32,
    /// Buffer size in frames.
    pub buffer_size: u32,
    /// Default project directory.
    pub project_dir: Option<PathBuf>,
    /// Recently opened session paths (most recent first).
    pub recent_sessions: Vec<PathBuf>,
    /// Maximum number of recent sessions to remember.
    pub max_recent: usize,
    /// UI scale factor (1.0 = 100%).
    pub ui_scale: f32,
    /// Theme file path (None = default theme).
    pub theme_path: Option<PathBuf>,
    /// Auto-save interval in seconds (0 = disabled).
    pub auto_save_interval: u32,
    /// Recording configuration.
    #[serde(default)]
    pub recording: RecordingConfig,
}

impl Default for Preferences {
    fn default() -> Self {
        Self {
            audio_device: None,
            sample_rate: 48000,
            buffer_size: 256,
            project_dir: None,
            recent_sessions: Vec::new(),
            max_recent: 10,
            ui_scale: 1.0,
            theme_path: None,
            auto_save_interval: 60,
            recording: RecordingConfig::default(),
        }
    }
}

impl Preferences {
    /// Load preferences from a JSON file.
    pub fn load(path: &Path) -> Result<Self, Box<dyn std::error::Error>> {
        let data = std::fs::read_to_string(path)?;
        let prefs = serde_json::from_str(&data)?;
        Ok(prefs)
    }

    /// Save preferences to a JSON file.
    pub fn save(&self, path: &Path) -> Result<(), Box<dyn std::error::Error>> {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let data = serde_json::to_string_pretty(self)?;
        std::fs::write(path, data)?;
        Ok(())
    }

    /// Get the default preferences file path.
    pub fn default_path() -> PathBuf {
        let config_dir = dirs_or_fallback();
        config_dir.join("shruti").join("preferences.json")
    }

    /// Load from default path, or return defaults if not found.
    pub fn load_or_default() -> Self {
        let path = Self::default_path();
        Self::load(&path).unwrap_or_default()
    }

    /// Add a path to recent sessions.
    pub fn add_recent(&mut self, path: PathBuf) {
        // Remove if already present
        self.recent_sessions.retain(|p| p != &path);
        // Add to front
        self.recent_sessions.insert(0, path);
        // Trim
        self.recent_sessions.truncate(self.max_recent);
    }
}

fn dirs_or_fallback() -> PathBuf {
    // Use XDG_CONFIG_HOME on Linux, fallback to ~/.config
    if let Ok(xdg) = std::env::var("XDG_CONFIG_HOME") {
        return PathBuf::from(xdg);
    }
    if let Ok(home) = std::env::var("HOME") {
        return PathBuf::from(home).join(".config");
    }
    PathBuf::from(".")
}

