use serde::{Deserialize, Serialize};
use uuid::Uuid;

/// Unique identifier for a region.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct RegionId(pub Uuid);

impl RegionId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }
}

impl Default for RegionId {
    fn default() -> Self {
        Self::new()
    }
}

/// A region is a non-destructive reference to a segment of audio.
///
/// Regions point into the audio pool (by file ID) and define which portion
/// of the source audio to play and where to place it on the timeline.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Region {
    pub id: RegionId,
    /// ID of the source audio file in the audio pool.
    pub audio_file_id: String,
    /// Position on the timeline in frames (where the region starts playing).
    pub timeline_pos: u64,
    /// Offset into the source audio in frames (where to start reading).
    pub source_offset: u64,
    /// Duration of the region in frames.
    pub duration: u64,
    /// Gain applied to this region (linear, 1.0 = unity).
    pub gain: f32,
    /// Fade-in duration in frames.
    pub fade_in: u64,
    /// Fade-out duration in frames.
    pub fade_out: u64,
    /// Whether this region is muted.
    pub muted: bool,
}

impl Region {
    pub fn new(
        audio_file_id: String,
        timeline_pos: u64,
        source_offset: u64,
        duration: u64,
    ) -> Self {
        Self {
            id: RegionId::new(),
            audio_file_id,
            timeline_pos,
            source_offset,
            duration,
            gain: 1.0,
            fade_in: 0,
            fade_out: 0,
            muted: false,
        }
    }

    /// The frame where this region ends on the timeline.
    pub fn end_pos(&self) -> u64 {
        self.timeline_pos + self.duration
    }

    /// Check if a timeline frame falls within this region.
    pub fn contains_frame(&self, frame: u64) -> bool {
        frame >= self.timeline_pos && frame < self.end_pos()
    }

    /// Given a timeline frame, return the corresponding source audio frame.
    pub fn source_frame_at(&self, timeline_frame: u64) -> Option<u64> {
        if !self.contains_frame(timeline_frame) {
            return None;
        }
        Some(self.source_offset + (timeline_frame - self.timeline_pos))
    }

    /// Calculate the fade gain at a given position within the region.
    pub fn fade_gain_at(&self, timeline_frame: u64) -> f32 {
        if !self.contains_frame(timeline_frame) {
            return 0.0;
        }

        let local = timeline_frame - self.timeline_pos;
        let mut gain = self.gain;

        // Fade in
        if self.fade_in > 0 && local < self.fade_in {
            gain *= local as f32 / self.fade_in as f32;
        }

        // Fade out
        if self.fade_out > 0 {
            let remaining = self.duration - local;
            if remaining < self.fade_out {
                gain *= remaining as f32 / self.fade_out as f32;
            }
        }

        gain
    }

    /// Split this region at the given timeline frame, returning (left, right).
    /// Returns None if the split point is outside the region.
    pub fn split_at(&self, frame: u64) -> Option<(Region, Region)> {
        if frame <= self.timeline_pos || frame >= self.end_pos() {
            return None;
        }

        let left_duration = frame - self.timeline_pos;
        let right_duration = self.duration - left_duration;
        let right_source_offset = self.source_offset + left_duration;

        let left = Region {
            id: RegionId::new(),
            audio_file_id: self.audio_file_id.clone(),
            timeline_pos: self.timeline_pos,
            source_offset: self.source_offset,
            duration: left_duration,
            gain: self.gain,
            fade_in: self.fade_in.min(left_duration),
            fade_out: 0,
            muted: self.muted,
        };

        let right = Region {
            id: RegionId::new(),
            audio_file_id: self.audio_file_id.clone(),
            timeline_pos: frame,
            source_offset: right_source_offset,
            duration: right_duration,
            gain: self.gain,
            fade_in: 0,
            fade_out: self.fade_out.min(right_duration),
            muted: self.muted,
        };

        Some((left, right))
    }

    /// Trim the start of the region by moving it forward.
    pub fn trim_start(&mut self, new_start: u64) {
        if new_start > self.timeline_pos && new_start < self.end_pos() {
            let delta = new_start - self.timeline_pos;
            self.source_offset += delta;
            self.duration -= delta;
            self.timeline_pos = new_start;
        }
    }

    /// Trim the end of the region.
    pub fn trim_end(&mut self, new_end: u64) {
        if new_end > self.timeline_pos && new_end < self.end_pos() {
            self.duration = new_end - self.timeline_pos;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_region_contains() {
        let r = Region::new("file1".into(), 100, 0, 500);
        assert!(!r.contains_frame(99));
        assert!(r.contains_frame(100));
        assert!(r.contains_frame(599));
        assert!(!r.contains_frame(600));
    }

    #[test]
    fn test_region_source_frame() {
        let r = Region::new("file1".into(), 100, 50, 500);
        assert_eq!(r.source_frame_at(100), Some(50));
        assert_eq!(r.source_frame_at(200), Some(150));
        assert_eq!(r.source_frame_at(50), None);
    }

    #[test]
    fn test_region_split() {
        let r = Region::new("file1".into(), 100, 0, 500);
        let (left, right) = r.split_at(300).unwrap();

        assert_eq!(left.timeline_pos, 100);
        assert_eq!(left.duration, 200);
        assert_eq!(left.source_offset, 0);

        assert_eq!(right.timeline_pos, 300);
        assert_eq!(right.duration, 300);
        assert_eq!(right.source_offset, 200);
    }

    #[test]
    fn test_region_trim() {
        let mut r = Region::new("file1".into(), 100, 0, 500);

        r.trim_start(200);
        assert_eq!(r.timeline_pos, 200);
        assert_eq!(r.source_offset, 100);
        assert_eq!(r.duration, 400);

        r.trim_end(500);
        assert_eq!(r.duration, 300);
    }

    #[test]
    fn test_fade_gain() {
        let mut r = Region::new("file1".into(), 0, 0, 1000);
        r.fade_in = 100;
        r.fade_out = 100;

        assert!((r.fade_gain_at(0) - 0.0).abs() < 1e-6);
        assert!((r.fade_gain_at(50) - 0.5).abs() < 1e-6);
        assert!((r.fade_gain_at(100) - 1.0).abs() < 1e-6);
        assert!((r.fade_gain_at(500) - 1.0).abs() < 1e-6);
        assert!((r.fade_gain_at(950) - 0.5).abs() < 1e-6);
    }
}

use serde::{Deserialize, Serialize};

use crate::audio_pool::AudioPool;
use crate::timeline::Timeline;
use crate::track::{Send, SendPosition, Track, TrackId, TrackKind};
use crate::transport::Transport;

/// A session is the top-level project container.
#[derive(Serialize, Deserialize)]
pub struct Session {
    pub name: String,
    pub sample_rate: u32,
    pub buffer_size: u32,
    /// Preferred audio device name (None = system default).
    #[serde(default)]
    pub audio_device_name: Option<String>,
    pub tracks: Vec<Track>,
    pub transport: Transport,
    /// Whether the session has unsaved changes.
    #[serde(skip)]
    pub dirty: bool,
    /// Audio pool (not serialized — audio files are stored on disk).
    #[serde(skip)]
    pub audio_pool: AudioPool,
    /// Timeline renderer (not serialized — runtime only).
    #[serde(skip)]
    pub timeline: Option<Timeline>,
}

impl Session {
    pub fn new(name: impl Into<String>, sample_rate: u32, buffer_size: u32) -> Self {
        let mut session = Self {
            name: name.into(),
            sample_rate,
            buffer_size,
            audio_device_name: None,
            tracks: Vec::new(),
            transport: Transport::new(sample_rate),
            dirty: false,
            audio_pool: AudioPool::new(),
            timeline: Some(Timeline::new(2, buffer_size)),
        };

        // Every session has a master bus
        session.tracks.push(Track::new_master());
        session
    }

    /// Add a new audio track, returning its ID.
    pub fn add_audio_track(&mut self, name: impl Into<String>) -> TrackId {
        let track = Track::new_audio(name);
        let id = track.id;
        // Insert before master (master is always last)
        let master_idx = self
            .tracks
            .iter()
            .position(|t| t.kind == TrackKind::Master)
            .unwrap_or(self.tracks.len());
        self.tracks.insert(master_idx, track);
        self.dirty = true;
        id
    }

    /// Add a new MIDI track, returning its ID.
    pub fn add_midi_track(&mut self, name: impl Into<String>) -> TrackId {
        let track = Track::new_midi(name);
        let id = track.id;
        let master_idx = self
            .tracks
            .iter()
            .position(|t| t.kind == TrackKind::Master)
            .unwrap_or(self.tracks.len());
        self.tracks.insert(master_idx, track);
        self.dirty = true;
        id
    }

    /// Add a new bus track, returning its ID.
    pub fn add_bus_track(&mut self, name: impl Into<String>) -> TrackId {
        let track = Track::new_bus(name);
        let id = track.id;
        let master_idx = self
            .tracks
            .iter()
            .position(|t| t.kind == TrackKind::Master)
            .unwrap_or(self.tracks.len());
        self.tracks.insert(master_idx, track);
        self.dirty = true;
        id
    }

    /// Add a new instrument track, returning its ID.
    pub fn add_instrument_track(
        &mut self,
        name: impl Into<String>,
        instrument_type: Option<String>,
    ) -> TrackId {
        let track = Track::new_instrument(name, instrument_type);
        let id = track.id;
        let master_idx = self
            .tracks
            .iter()
            .position(|t| t.kind == TrackKind::Master)
            .unwrap_or(self.tracks.len());
        self.tracks.insert(master_idx, track);
        self.dirty = true;
        id
    }

    /// Get instrument tracks.
    pub fn instrument_tracks(&self) -> Vec<&Track> {
        self.tracks
            .iter()
            .filter(|t| matches!(t.kind, TrackKind::Instrument { .. }))
            .collect()
    }

    /// Remove a track by ID. Cannot remove the master bus.
    pub fn remove_track(&mut self, id: TrackId) -> Option<Track> {
        let pos = self.tracks.iter().position(|t| t.id == id)?;
        if self.tracks[pos].kind == TrackKind::Master {
            return None;
        }
        self.dirty = true;
        Some(self.tracks.remove(pos))
    }

    /// Get a track by ID.
    pub fn track(&self, id: TrackId) -> Option<&Track> {
        self.tracks.iter().find(|t| t.id == id)
    }

    /// Get a mutable track by ID.
    pub fn track_mut(&mut self, id: TrackId) -> Option<&mut Track> {
        self.tracks.iter_mut().find(|t| t.id == id)
    }

    /// Get the master track.
    pub fn master(&self) -> Option<&Track> {
        self.tracks.iter().find(|t| t.kind == TrackKind::Master)
    }

    /// Get audio tracks (excludes bus, MIDI, and master).
    pub fn audio_tracks(&self) -> Vec<&Track> {
        self.tracks
            .iter()
            .filter(|t| t.kind == TrackKind::Audio)
            .collect()
    }

    /// Get MIDI tracks.
    pub fn midi_tracks(&self) -> Vec<&Track> {
        self.tracks
            .iter()
            .filter(|t| t.kind == TrackKind::Midi)
            .collect()
    }

    /// Move a track from one index to another. Master track cannot be moved.
    pub fn move_track(&mut self, from: usize, to: usize) -> bool {
        let len = self.tracks.len();
        if from >= len || to >= len {
            return false;
        }
        // Don't allow moving the master track (always last)
        if self.tracks[from].kind == TrackKind::Master
            || to >= len - 1
                && self
                    .tracks
                    .last()
                    .is_some_and(|t| t.kind == TrackKind::Master)
        {
            // Prevent moving anything past master
            let master_idx = self.tracks.iter().position(|t| t.kind == TrackKind::Master);
            if let Some(mi) = master_idx
                && (from == mi || to >= mi)
            {
                return false;
            }
        }
        let track = self.tracks.remove(from);
        self.tracks.insert(to, track);
        self.dirty = true;
        true
    }

    /// Swap two tracks by index. Neither can be the master track.
    pub fn swap_tracks(&mut self, a: usize, b: usize) -> bool {
        let len = self.tracks.len();
        if a >= len || b >= len || a == b {
            return false;
        }
        if self.tracks[a].kind == TrackKind::Master || self.tracks[b].kind == TrackKind::Master {
            return false;
        }
        self.tracks.swap(a, b);
        self.dirty = true;
        true
    }

    /// Add a send from one track to a bus track.
    pub fn add_send(
        &mut self,
        from_track: TrackId,
        to_bus: TrackId,
        level: f32,
        position: SendPosition,
    ) -> bool {
        // Verify target is a bus track
        let is_bus = self
            .tracks
            .iter()
            .any(|t| t.id == to_bus && t.kind == TrackKind::Bus);
        if !is_bus {
            return false;
        }
        if let Some(track) = self.tracks.iter_mut().find(|t| t.id == from_track) {
            track.sends.push(Send {
                target: to_bus,
                level,
                position,
                enabled: true,
            });
            self.dirty = true;
            return true;
        }
        false
    }

    /// Remove a send by index from a track.
    pub fn remove_send(&mut self, track_id: TrackId, send_index: usize) -> bool {
        if let Some(track) = self.tracks.iter_mut().find(|t| t.id == track_id)
            && send_index < track.sends.len()
        {
            track.sends.remove(send_index);
            self.dirty = true;
            return true;
        }
        false
    }

    /// Total number of tracks (including master).
    pub fn track_count(&self) -> usize {
        self.tracks.len()
    }

    /// Find the end position of the last region or MIDI clip across all tracks.
    pub fn session_length(&self) -> u64 {
        let audio_end = self
            .tracks
            .iter()
            .flat_map(|t| t.regions.iter())
            .map(|r| r.end_pos())
            .max()
            .unwrap_or(0);
        let midi_end = self
            .tracks
            .iter()
            .flat_map(|t| t.midi_clips.iter())
            .map(|c| c.end_pos())
            .max()
            .unwrap_or(0);
        audio_end.max(midi_end)
    }
}

