use crate::audio_pool::AudioPool;
use crate::automation::AutomationTarget;
use crate::region::Region;
use crate::track::{SendPosition, Track, TrackId, TrackKind};
use crate::transport::Transport;
use shruti_dsp::AudioBuffer;
use shruti_dsp::effects::StereoPanner;

/// Maximum number of bus tracks supported for pre-allocated buffers.
const MAX_BUS_TRACKS: usize = 16;
/// Maximum number of source tracks supported for pre-allocated buffers.
const MAX_SOURCE_TRACKS: usize = 64;

/// The timeline manages multi-track playback and rendering.
pub struct Timeline {
    /// Per-track scratch buffer.
    track_buffer: AudioBuffer,
    /// Pre-allocated bus accumulation buffers (reused across render calls).
    bus_buffers: Vec<AudioBuffer>,
    /// TrackIds corresponding to each bus buffer slot.
    bus_ids: Vec<TrackId>,
    /// Pre-allocated source track buffers (reused across render calls).
    source_buffers: Vec<AudioBuffer>,
    /// Number of active source buffers in the current render pass.
    source_count: usize,
}

impl Timeline {
    pub fn new(channels: u16, buffer_size: u32) -> Self {
        Self {
            track_buffer: AudioBuffer::new(channels, buffer_size),
            bus_buffers: (0..MAX_BUS_TRACKS)
                .map(|_| AudioBuffer::new(channels, buffer_size))
                .collect(),
            bus_ids: Vec::with_capacity(MAX_BUS_TRACKS),
            source_buffers: (0..MAX_SOURCE_TRACKS)
                .map(|_| AudioBuffer::new(channels, buffer_size))
                .collect(),
            source_count: 0,
        }
    }

    /// Render one buffer of audio from all tracks at the current transport position.
    ///
    /// Rendering happens in multiple passes:
    /// 1. Render all non-bus, non-master tracks into per-track buffers and process sends.
    /// 2. Mix bus track accumulated audio (from sends) into the output.
    /// 3. Mix all non-bus, non-master track audio into the output.
    pub fn render(
        &mut self,
        tracks: &[Track],
        transport: &Transport,
        audio_pool: &AudioPool,
        output: &mut AudioBuffer,
    ) {
        let frames = output.frames();
        let channels = output.channels();
        let position = transport.position;

        output.clear();

        // Determine if any track is soloed
        let has_solo = tracks.iter().any(|t| t.solo);

        // Map bus tracks to pre-allocated bus buffers (no HashMap allocation)
        self.bus_ids.clear();
        let mut bus_count = 0;
        for track in tracks {
            if track.kind == TrackKind::Bus && bus_count < MAX_BUS_TRACKS {
                // Ensure the pre-allocated buffer matches the current frame size
                if self.bus_buffers[bus_count].frames() != frames {
                    self.bus_buffers[bus_count] = AudioBuffer::new(channels, frames);
                }
                self.bus_buffers[bus_count].clear();
                self.bus_ids.push(track.id);
                bus_count += 1;
            }
        }

        self.source_count = 0;

        // First pass: render source tracks (Audio, MIDI) and route sends
        for track in tracks {
            if track.kind == TrackKind::Bus || track.kind == TrackKind::Master {
                continue;
            }
            if track.muted {
                continue;
            }
            if has_solo && !track.solo {
                continue;
            }

            self.track_buffer.clear();
            self.render_track(track, position, frames, channels, audio_pool);

            // Apply automation overrides for this buffer position
            let mut gain = track.gain;
            let mut pan = track.pan;
            for lane in &track.automation {
                if !lane.enabled {
                    continue;
                }
                if let Some(value) = lane.value_at(position) {
                    match &lane.target {
                        AutomationTarget::TrackGain => gain = value,
                        AutomationTarget::TrackPan => pan = value,
                        _ => {}
                    }
                }
            }

            // Process pre-fader sends before applying gain/pan
            for send in &track.sends {
                if !send.enabled {
                    continue;
                }
                if send.position == SendPosition::PreFader
                    && let Some(bus_idx) = self.bus_ids.iter().position(|id| *id == send.target)
                {
                    for frame in 0..frames {
                        for ch in 0..channels {
                            let sample = self.track_buffer.get(frame, ch) * send.level;
                            let existing = self.bus_buffers[bus_idx].get(frame, ch);
                            self.bus_buffers[bus_idx].set(frame, ch, existing + sample);
                        }
                    }
                }
            }

            // Apply track gain
            self.track_buffer.apply_gain(gain);

            // Apply panning (stereo only)
            if self.track_buffer.channels() >= 2 {
                let mut panner = StereoPanner::new(pan);
                panner.process(&mut self.track_buffer);
            }

            // Process post-fader sends after applying gain/pan
            for send in &track.sends {
                if !send.enabled {
                    continue;
                }
                if send.position == SendPosition::PostFader
                    && let Some(bus_idx) = self.bus_ids.iter().position(|id| *id == send.target)
                {
                    for frame in 0..frames {
                        for ch in 0..channels {
                            let sample = self.track_buffer.get(frame, ch) * send.level;
                            let existing = self.bus_buffers[bus_idx].get(frame, ch);
                            self.bus_buffers[bus_idx].set(frame, ch, existing + sample);
                        }
                    }
                }
            }

            // Save post-fader buffer into pre-allocated source buffer
            if self.source_count < MAX_SOURCE_TRACKS {
                if self.source_buffers[self.source_count].frames() != frames {
                    self.source_buffers[self.source_count] = AudioBuffer::new(channels, frames);
                }
                self.source_buffers[self.source_count].clear();
                self.source_buffers[self.source_count].mix_from(&self.track_buffer);
                self.source_count += 1;
            }
        }

        // Second pass: process bus tracks — apply bus gain/pan, then mix into output
        for track in tracks {
            if track.kind != TrackKind::Bus {
                continue;
            }
            if track.muted {
                continue;
            }
            if has_solo && !track.solo {
                continue;
            }

            if let Some(bus_idx) = self.bus_ids.iter().position(|id| *id == track.id) {
                // Apply bus track gain
                self.bus_buffers[bus_idx].apply_gain(track.gain);

                // Apply bus panning
                if self.bus_buffers[bus_idx].channels() >= 2 {
                    let mut panner = StereoPanner::new(track.pan);
                    panner.process(&mut self.bus_buffers[bus_idx]);
                }

                output.mix_from(&self.bus_buffers[bus_idx]);
            }
        }

        // Third pass: mix source track buffers into output
        for i in 0..self.source_count {
            output.mix_from(&self.source_buffers[i]);
        }
    }

    fn render_track(
        &mut self,
        track: &Track,
        position: u64,
        frames: u32,
        channels: u16,
        audio_pool: &AudioPool,
    ) {
        let end = position + frames as u64;
        let active_regions = track.regions_in_range(position, end);

        for region in active_regions {
            if let Some(source) = audio_pool.get(&region.audio_file_id) {
                self.render_region(region, source, position, frames, channels);
            }
        }
    }

    fn render_region(
        &mut self,
        region: &Region,
        source: &AudioBuffer,
        position: u64,
        frames: u32,
        channels: u16,
    ) {
        let src_channels = source.channels().min(channels);

        for frame_offset in 0..frames {
            let timeline_frame = position + frame_offset as u64;

            if let Some(source_frame) = region.source_frame_at(timeline_frame) {
                if source_frame >= source.frames() as u64 {
                    continue;
                }

                let fade_gain = region.fade_gain_at(timeline_frame);

                for ch in 0..src_channels {
                    let sample = source.get(source_frame as u32, ch) * fade_gain;
                    let existing = self.track_buffer.get(frame_offset, ch);
                    self.track_buffer.set(frame_offset, ch, existing + sample);
                }
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::region::Region;
    use crate::track::Send;

    #[test]
    fn test_timeline_render_single_track() {
        let mut pool = AudioPool::new();
        let source = AudioBuffer::from_interleaved(vec![0.5, -0.5, 0.3, -0.3, 0.1, -0.1], 2);
        pool.insert("file1".into(), source);

        let mut track = Track::new_audio("Track 1");
        track.add_region(Region::new("file1".into(), 0, 0, 3));

        let transport = Transport::new(48000);

        let mut timeline = Timeline::new(2, 3);
        let mut output = AudioBuffer::new(2, 3);

        timeline.render(&[track], &transport, &pool, &mut output);

        assert!((output.get(0, 0) - 0.5).abs() < 1e-6);
        assert!((output.get(0, 1) - -0.5).abs() < 1e-6);
        assert!((output.get(2, 0) - 0.1).abs() < 1e-6);
    }

    #[test]
    fn test_timeline_render_offset_region() {
        let mut pool = AudioPool::new();
        let source = AudioBuffer::from_interleaved(vec![1.0, 1.0, 0.5, 0.5, 0.25, 0.25], 2);
        pool.insert("file1".into(), source);

        let mut track = Track::new_audio("Track 1");
        // Region starts at frame 2 on timeline, reads from source offset 1
        track.add_region(Region::new("file1".into(), 2, 1, 2));

        let mut transport = Transport::new(48000);
        transport.position = 2;

        let mut timeline = Timeline::new(2, 2);
        let mut output = AudioBuffer::new(2, 2);

        timeline.render(&[track], &transport, &pool, &mut output);

        // Should read source frames 1 and 2 (values 0.5 and 0.25)
        assert!((output.get(0, 0) - 0.5).abs() < 1e-6);
        assert!((output.get(1, 0) - 0.25).abs() < 1e-6);
    }

    #[test]
    fn test_send_routes_audio_to_bus() {
        // Create an audio track and a bus track
        let mut pool = AudioPool::new();
        let samples: Vec<f32> = (0..1024).map(|i| (i as f32 * 0.01).sin() * 0.8).collect();
        let buf = AudioBuffer::from_interleaved(samples, 2);
        pool.insert("drums_audio".to_string(), buf);

        let mut audio_track = Track::new_audio("Drums");
        let _audio_id = audio_track.id;
        audio_track.add_region(Region::new("drums_audio".to_string(), 0, 0, 512));

        let bus_track = Track::new_bus("Reverb Bus");
        let bus_id = bus_track.id;

        // Add a send from drums to reverb bus at 50% level
        audio_track.sends.push(Send {
            target: bus_id,
            level: 0.5,
            position: SendPosition::PostFader,
            enabled: true,
        });

        let tracks = vec![audio_track, bus_track];

        // Render
        let mut tl = Timeline::new(2, 512);
        let transport = Transport::new(48000);
        let mut output = AudioBuffer::new(2, 512);
        tl.render(&tracks, &transport, &pool, &mut output);

        // Output should contain audio (both direct track audio and bus contribution)
        let has_audio = output.as_interleaved().iter().any(|&s| s.abs() > 0.001);
        assert!(has_audio, "expected audio output with send routing");

        // The output should be louder than just the direct signal because the bus
        // also contributes. With a 0.5 send, total gain at some samples should be ~1.5x
        // (1.0 direct + 0.5 send through bus).
        // Verify the bus actually contributed by checking the output is larger than
        // the source signal alone.
        let direct_only_max = (0..512)
            .map(|i| ((i as f32 * 0.01).sin() * 0.8).abs())
            .fold(0.0f32, f32::max);
        let output_max = output
            .as_interleaved()
            .iter()
            .copied()
            .fold(0.0f32, |a, b| a.max(b.abs()));
        assert!(
            output_max > direct_only_max,
            "bus send should add to the output: output_max={output_max}, direct_max={direct_only_max}"
        );
    }

    #[test]
    fn test_pre_fader_send_ignores_track_gain() {
        let mut pool = AudioPool::new();
        // Constant 0.5 on both channels for 4 frames
        let samples: Vec<f32> = vec![0.5; 8];
        let buf = AudioBuffer::from_interleaved(samples, 2);
        pool.insert("src".to_string(), buf);

        let mut audio_track = Track::new_audio("Src");
        audio_track.gain = 0.0; // Mute the track gain
        audio_track.add_region(Region::new("src".to_string(), 0, 0, 4));

        let bus_track = Track::new_bus("Bus");
        let bus_id = bus_track.id;

        // Pre-fader send at full level
        audio_track.sends.push(Send {
            target: bus_id,
            level: 1.0,
            position: SendPosition::PreFader,
            enabled: true,
        });

        let tracks = vec![audio_track, bus_track];

        let mut tl = Timeline::new(2, 4);
        let transport = Transport::new(48000);
        let mut output = AudioBuffer::new(2, 4);
        tl.render(&tracks, &transport, &pool, &mut output);

        // Even though the track gain is 0, the pre-fader send should have routed
        // the original audio to the bus, so we should hear the bus output.
        let has_audio = output.as_interleaved().iter().any(|&s| s.abs() > 0.001);
        assert!(
            has_audio,
            "pre-fader send should route audio even when track gain is zero"
        );

        // The output should be approximately 0.5 (from bus only, direct track is silent)
        assert!(
            (output.get(0, 0) - 0.5).abs() < 1e-4,
            "bus should carry pre-fader signal: got {}",
            output.get(0, 0)
        );
    }

    #[test]
    fn test_muted_track_send_still_routes() {
        // Based on the render code: muted tracks are skipped entirely,
        // so sends from muted tracks do NOT route audio.
        let mut pool = AudioPool::new();
        let samples: Vec<f32> = vec![0.5; 8];
        let buf = AudioBuffer::from_interleaved(samples, 2);
        pool.insert("src".to_string(), buf);

        let mut audio_track = Track::new_audio("Src");
        audio_track.muted = true; // mute the track
        audio_track.add_region(Region::new("src".to_string(), 0, 0, 4));

        let bus_track = Track::new_bus("Bus");
        let bus_id = bus_track.id;

        audio_track.sends.push(Send {
            target: bus_id,
            level: 1.0,
            position: SendPosition::PostFader,
            enabled: true,
        });

        let tracks = vec![audio_track, bus_track];

        let mut tl = Timeline::new(2, 4);
        let transport = Transport::new(48000);
        let mut output = AudioBuffer::new(2, 4);
        tl.render(&tracks, &transport, &pool, &mut output);

        // Muted tracks are skipped, so output should be silent
        let all_silent = output.as_interleaved().iter().all(|&s| s.abs() < 1e-6);
        assert!(
            all_silent,
            "muted track should not route audio through sends"
        );
    }

    #[test]
    fn test_multiple_sends_to_same_bus() {
        let mut pool = AudioPool::new();
        // Two different audio sources
        let buf1 = AudioBuffer::from_interleaved(vec![0.4; 8], 2);
        let buf2 = AudioBuffer::from_interleaved(vec![0.3; 8], 2);
        pool.insert("src1".to_string(), buf1);
        pool.insert("src2".to_string(), buf2);

        let bus_track = Track::new_bus("FX Bus");
        let bus_id = bus_track.id;

        let mut track1 = Track::new_audio("Track1");
        track1.add_region(Region::new("src1".to_string(), 0, 0, 4));
        track1.sends.push(Send {
            target: bus_id,
            level: 1.0,
            position: SendPosition::PostFader,
            enabled: true,
        });

        let mut track2 = Track::new_audio("Track2");
        track2.add_region(Region::new("src2".to_string(), 0, 0, 4));
        track2.sends.push(Send {
            target: bus_id,
            level: 1.0,
            position: SendPosition::PostFader,
            enabled: true,
        });

        let tracks = vec![track1, track2, bus_track];

        let mut tl = Timeline::new(2, 4);
        let transport = Transport::new(48000);
        let mut output = AudioBuffer::new(2, 4);
        tl.render(&tracks, &transport, &pool, &mut output);

        // Output should have both direct tracks (0.4 + 0.3) and bus contribution
        // (0.4 + 0.3 from bus). Total per channel ~1.4.
        let sample = output.get(0, 0);
        assert!(
            sample > 0.6,
            "multiple sends to same bus should sum: got {sample}"
        );
    }

    #[test]
    fn test_bus_gain_affects_send_output() {
        let mut pool = AudioPool::new();
        let buf = AudioBuffer::from_interleaved(vec![0.8; 8], 2);
        pool.insert("src".to_string(), buf);

        let mut bus_track = Track::new_bus("FX Bus");
        bus_track.gain = 0.5; // bus gain at 50%
        let bus_id = bus_track.id;

        let mut audio_track = Track::new_audio("Src");
        audio_track.add_region(Region::new("src".to_string(), 0, 0, 4));
        audio_track.sends.push(Send {
            target: bus_id,
            level: 1.0,
            position: SendPosition::PostFader,
            enabled: true,
        });

        let tracks = vec![audio_track, bus_track];

        let mut tl = Timeline::new(2, 4);
        let transport = Transport::new(48000);
        let mut output = AudioBuffer::new(2, 4);
        tl.render(&tracks, &transport, &pool, &mut output);

        // Direct signal: 0.8, bus contribution: 0.8 * 1.0 (send) * 0.5 (bus gain) = 0.4
        // Total: 0.8 + 0.4 = 1.2
        let sample = output.get(0, 0);
        assert!(
            (sample - 1.2).abs() < 0.05,
            "bus gain should scale send output: expected ~1.2, got {sample}"
        );
    }

    #[test]
    fn test_empty_bus_no_crash() {
        // A bus with no incoming sends should render without error
        let pool = AudioPool::new();
        let bus_track = Track::new_bus("Empty Bus");

        let tracks = vec![bus_track];

        let mut tl = Timeline::new(2, 64);
        let transport = Transport::new(48000);
        let mut output = AudioBuffer::new(2, 64);
        tl.render(&tracks, &transport, &pool, &mut output);

        // Output should be all zeros (silence)
        let all_silent = output.as_interleaved().iter().all(|&s| s.abs() < 1e-6);
        assert!(all_silent, "empty bus should produce silence");
    }
}

use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::automation::AutomationLane;
use crate::midi::MidiClip;
use crate::region::{Region, RegionId};

/// Unique identifier for a track.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct TrackId(pub Uuid);

impl TrackId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }
}

impl Default for TrackId {
    fn default() -> Self {
        Self::new()
    }
}

/// The kind of track.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum TrackKind {
    /// Audio track with regions on the timeline.
    Audio,
    /// Bus track for routing and grouping.
    Bus,
    /// MIDI track with MIDI clips.
    Midi,
    /// Master output bus.
    Master,
    /// Instrument track — hosts a virtual instrument identified by type name.
    Instrument {
        /// The instrument type loaded on this track (e.g. "SubtractiveSynth").
        /// `None` means no instrument is loaded yet.
        #[serde(default)]
        instrument_type: Option<String>,
    },
}

/// Pre/post fader send position.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum SendPosition {
    PreFader,
    PostFader,
}

/// A send from one track to a bus.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Send {
    /// Target bus track.
    pub target: TrackId,
    /// Send level (linear gain, 0.0 to 1.0).
    pub level: f32,
    /// Pre or post fader.
    pub position: SendPosition,
    /// Whether this send is enabled.
    pub enabled: bool,
}

/// A track in the session.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Track {
    pub id: TrackId,
    pub name: String,
    pub kind: TrackKind,
    /// Regions placed on this track's timeline.
    pub regions: Vec<Region>,
    /// Track gain (linear, 1.0 = unity).
    pub gain: f32,
    /// Track pan (-1.0 = full left, 0.0 = center, 1.0 = full right).
    pub pan: f32,
    /// Track is muted.
    pub muted: bool,
    /// Track is soloed.
    pub solo: bool,
    /// Track is armed for recording.
    pub armed: bool,
    /// Number of channels (typically 2 for stereo).
    pub channels: u16,
    /// Aux sends to bus tracks.
    pub sends: Vec<Send>,
    /// Automation lanes for this track.
    pub automation: Vec<AutomationLane>,
    /// MIDI clips on this track (only used for Midi tracks).
    pub midi_clips: Vec<MidiClip>,
    /// Instrument parameter values for Instrument tracks (indexed by param position).
    #[serde(default)]
    pub instrument_params: Vec<f32>,
}

impl Track {
    pub fn new_audio(name: impl Into<String>) -> Self {
        Self {
            id: TrackId::new(),
            name: name.into(),
            kind: TrackKind::Audio,
            regions: Vec::new(),
            gain: 1.0,
            pan: 0.0,
            muted: false,
            solo: false,
            armed: false,
            channels: 2,
            sends: Vec::new(),
            automation: Vec::new(),
            midi_clips: Vec::new(),
            instrument_params: Vec::new(),
        }
    }

    pub fn new_bus(name: impl Into<String>) -> Self {
        Self {
            id: TrackId::new(),
            name: name.into(),
            kind: TrackKind::Bus,
            regions: Vec::new(),
            gain: 1.0,
            pan: 0.0,
            muted: false,
            solo: false,
            armed: false,
            channels: 2,
            sends: Vec::new(),
            automation: Vec::new(),
            midi_clips: Vec::new(),
            instrument_params: Vec::new(),
        }
    }

    pub fn new_midi(name: impl Into<String>) -> Self {
        Self {
            id: TrackId::new(),
            name: name.into(),
            kind: TrackKind::Midi,
            regions: Vec::new(),
            gain: 1.0,
            pan: 0.0,
            muted: false,
            solo: false,
            armed: false,
            channels: 2,
            sends: Vec::new(),
            automation: Vec::new(),
            midi_clips: Vec::new(),
            instrument_params: Vec::new(),
        }
    }

    pub fn new_instrument(name: impl Into<String>, instrument_type: Option<String>) -> Self {
        Self {
            id: TrackId::new(),
            name: name.into(),
            kind: TrackKind::Instrument { instrument_type },
            regions: Vec::new(),
            gain: 1.0,
            pan: 0.0,
            muted: false,
            solo: false,
            armed: false,
            channels: 2,
            sends: Vec::new(),
            automation: Vec::new(),
            midi_clips: Vec::new(),
            instrument_params: Vec::new(),
        }
    }

    pub fn new_master() -> Self {
        Self {
            id: TrackId::new(),
            name: "Master".into(),
            kind: TrackKind::Master,
            regions: Vec::new(),
            gain: 1.0,
            pan: 0.0,
            muted: false,
            solo: false,
            armed: false,
            channels: 2,
            sends: Vec::new(),
            automation: Vec::new(),
            midi_clips: Vec::new(),
            instrument_params: Vec::new(),
        }
    }

    /// Add a region to this track.
    pub fn add_region(&mut self, region: Region) {
        self.regions.push(region);
    }

    /// Remove a region by ID, returning it if found.
    pub fn remove_region(&mut self, id: RegionId) -> Option<Region> {
        if let Some(pos) = self.regions.iter().position(|r| r.id == id) {
            Some(self.regions.remove(pos))
        } else {
            None
        }
    }

    /// Get a region by ID.
    pub fn region(&self, id: RegionId) -> Option<&Region> {
        self.regions.iter().find(|r| r.id == id)
    }

    /// Get a mutable region by ID.
    pub fn region_mut(&mut self, id: RegionId) -> Option<&mut Region> {
        self.regions.iter_mut().find(|r| r.id == id)
    }

    /// Get all regions that overlap with the given frame range.
    pub fn regions_in_range(&self, start: u64, end: u64) -> Vec<&Region> {
        self.regions
            .iter()
            .filter(|r| !r.muted && r.timeline_pos < end && r.end_pos() > start)
            .collect()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_track_regions() {
        let mut track = Track::new_audio("Track 1");
        let r1 = Region::new("file1".into(), 0, 0, 1000);
        let r2 = Region::new("file2".into(), 2000, 0, 500);
        let r1_id = r1.id;

        track.add_region(r1);
        track.add_region(r2);
        assert_eq!(track.regions.len(), 2);

        // Range query
        let in_range = track.regions_in_range(500, 1500);
        assert_eq!(in_range.len(), 1);

        let in_range = track.regions_in_range(0, 3000);
        assert_eq!(in_range.len(), 2);

        // Remove
        let removed = track.remove_region(r1_id).unwrap();
        assert_eq!(removed.id, r1_id);
        assert_eq!(track.regions.len(), 1);
    }

    #[test]
    fn test_instrument_track_creation() {
        let track = Track::new_instrument("Synth Lead", Some("SubtractiveSynth".to_string()));
        assert_eq!(
            track.kind,
            TrackKind::Instrument {
                instrument_type: Some("SubtractiveSynth".to_string())
            }
        );
        assert_eq!(track.name, "Synth Lead");
        assert!(track.midi_clips.is_empty());
        assert!(track.regions.is_empty());
    }

    #[test]
    fn test_instrument_track_no_instrument() {
        let track = Track::new_instrument("Empty Inst", None);
        assert_eq!(
            track.kind,
            TrackKind::Instrument {
                instrument_type: None
            }
        );
    }

    #[test]
    fn test_list_tracks_by_kind() {
        let tracks = [
            Track::new_audio("Audio 1"),
            Track::new_instrument("Synth", Some("SubtractiveSynth".to_string())),
            Track::new_midi("MIDI 1"),
            Track::new_instrument("Drums", Some("DrumMachine".to_string())),
            Track::new_master(),
        ];
        let instrument_count = tracks
            .iter()
            .filter(|t| matches!(t.kind, TrackKind::Instrument { .. }))
            .count();
        assert_eq!(instrument_count, 2);
    }

    #[test]
    fn test_instrument_track_serde_roundtrip() {
        let track = Track::new_instrument("Synth", Some("SubtractiveSynth".to_string()));
        let json = serde_json::to_string(&track).unwrap();
        let restored: Track = serde_json::from_str(&json).unwrap();
        assert_eq!(restored.kind, track.kind);
        assert_eq!(restored.name, "Synth");
    }

    #[test]
    fn test_midi_track() {
        let mut track = Track::new_midi("Synth Lead");
        assert_eq!(track.kind, TrackKind::Midi);
        assert!(track.midi_clips.is_empty());

        let mut clip = crate::midi::MidiClip::new("Intro", 0, 48000);
        clip.add_note(0, 12000, 60, 100, 0);
        clip.add_note(12000, 12000, 64, 90, 0);
        clip.add_cc(0, 1, 64, 0);

        track.midi_clips.push(clip);
        assert_eq!(track.midi_clips.len(), 1);
        assert_eq!(track.midi_clips[0].notes.len(), 2);
        assert_eq!(track.midi_clips[0].control_changes.len(), 1);
    }
}

use serde::{Deserialize, Serialize};

/// Transport playback state.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum TransportState {
    Stopped,
    Playing,
    Paused,
    Recording,
}

/// Transport controls: playback position, tempo, time signature, loop region.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Transport {
    pub state: TransportState,
    /// Current playback position in frames (sample-accurate).
    pub position: u64,
    /// Tempo in BPM.
    pub bpm: f64,
    /// Time signature numerator (e.g. 4 in 4/4).
    pub time_sig_num: u8,
    /// Time signature denominator (e.g. 4 in 4/4).
    pub time_sig_den: u8,
    /// Sample rate of the session.
    pub sample_rate: u32,
    /// Loop enabled.
    pub loop_enabled: bool,
    /// Loop start position in frames.
    pub loop_start: u64,
    /// Loop end position in frames.
    pub loop_end: u64,
}

impl Transport {
    pub fn new(sample_rate: u32) -> Self {
        Self {
            state: TransportState::Stopped,
            position: 0,
            bpm: 120.0,
            time_sig_num: 4,
            time_sig_den: 4,
            sample_rate,
            loop_enabled: false,
            loop_start: 0,
            loop_end: 0,
        }
    }

    pub fn play(&mut self) {
        self.state = TransportState::Playing;
    }

    pub fn stop(&mut self) {
        self.state = TransportState::Stopped;
        self.position = 0;
    }

    pub fn pause(&mut self) {
        self.state = TransportState::Stopped;
    }

    pub fn seek(&mut self, position: u64) {
        self.position = position;
    }

    /// Advance the transport by `frames` and return the actual range processed,
    /// handling loop boundaries.
    pub fn advance(&mut self, frames: u32) -> (u64, u64) {
        let start = self.position;

        if self.loop_enabled && self.loop_end > self.loop_start {
            let end = start + frames as u64;
            if end >= self.loop_end {
                let loop_length = self.loop_end - self.loop_start;
                let overshoot = end - self.loop_end;
                self.position = self.loop_start + (overshoot % loop_length);
            } else {
                self.position = end;
            }
        } else {
            self.position += frames as u64;
        }

        (start, self.position)
    }

    /// Convert a frame position to seconds.
    pub fn frames_to_secs(&self, frames: u64) -> f64 {
        frames as f64 / self.sample_rate as f64
    }

    /// Convert seconds to frame position.
    pub fn secs_to_frames(&self, secs: f64) -> u64 {
        (secs * self.sample_rate as f64) as u64
    }

    /// Convert a frame position to beats.
    pub fn frames_to_beats(&self, frames: u64) -> f64 {
        let secs = self.frames_to_secs(frames);
        secs * self.bpm / 60.0
    }

    /// Convert beats to frame position.
    pub fn beats_to_frames(&self, beats: f64) -> u64 {
        let secs = beats * 60.0 / self.bpm;
        self.secs_to_frames(secs)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_transport_advance() {
        let mut t = Transport::new(48000);
        t.play();
        let (start, end) = t.advance(256);
        assert_eq!(start, 0);
        assert_eq!(end, 256);
        assert_eq!(t.position, 256);
    }

    #[test]
    fn test_transport_loop() {
        let mut t = Transport::new(48000);
        t.loop_enabled = true;
        t.loop_start = 0;
        t.loop_end = 1000;
        t.position = 900;
        t.play();

        let (start, _end) = t.advance(256);
        assert_eq!(start, 900);
        // 900 + 256 = 1156, wraps to 1156 - 1000 = 156
        assert_eq!(t.position, 156);
    }

    #[test]
    fn test_time_conversions() {
        let t = Transport::new(48000);
        assert_eq!(t.frames_to_secs(48000), 1.0);
        assert_eq!(t.secs_to_frames(1.0), 48000);

        // At 120 BPM: 1 beat = 0.5 seconds = 24000 frames
        assert!((t.frames_to_beats(24000) - 1.0).abs() < 1e-10);
        assert_eq!(t.beats_to_frames(1.0), 24000);
    }

    #[test]
    fn test_transport_loop_multi_overshoot() {
        // Advance far past loop_end (multiple loop lengths)
        let mut t = Transport::new(48000);
        t.loop_enabled = true;
        t.loop_start = 100;
        t.loop_end = 200; // loop_length = 100
        t.position = 190;
        t.play();

        // 190 + 256 = 446, overshoot = 446 - 200 = 246, 246 % 100 = 46
        // position = 100 + 46 = 146
        t.advance(256);
        assert_eq!(t.position, 146);
    }

    #[test]
    fn test_transport_loop_exact_boundary() {
        let mut t = Transport::new(48000);
        t.loop_enabled = true;
        t.loop_start = 0;
        t.loop_end = 256;
        t.position = 0;
        t.play();

        // Advance exactly to loop_end
        t.advance(256);
        assert_eq!(t.position, 0);
    }
}

use crate::edit::EditCommand;
use crate::session::Session;

/// Manages undo/redo history using the command pattern.
pub struct UndoManager {
    undo_stack: Vec<EditCommand>,
    redo_stack: Vec<EditCommand>,
    max_history: usize,
}

impl UndoManager {
    pub fn new(max_history: usize) -> Self {
        Self {
            undo_stack: Vec::new(),
            redo_stack: Vec::new(),
            max_history,
        }
    }

    /// Execute a command, pushing it onto the undo stack.
    pub fn execute(&mut self, mut cmd: EditCommand, session: &mut Session) {
        apply_command(&mut cmd, session);
        self.undo_stack.push(cmd);
        self.redo_stack.clear();

        if self.undo_stack.len() > self.max_history {
            self.undo_stack.remove(0);
        }
    }

    /// Undo the last command.
    pub fn undo(&mut self, session: &mut Session) -> bool {
        if let Some(cmd) = self.undo_stack.pop() {
            reverse_command(&cmd, session);
            self.redo_stack.push(cmd);
            true
        } else {
            false
        }
    }

    /// Redo the last undone command.
    pub fn redo(&mut self, session: &mut Session) -> bool {
        if let Some(mut cmd) = self.redo_stack.pop() {
            apply_command(&mut cmd, session);
            self.undo_stack.push(cmd);
            true
        } else {
            false
        }
    }

    pub fn can_undo(&self) -> bool {
        !self.undo_stack.is_empty()
    }

    pub fn can_redo(&self) -> bool {
        !self.redo_stack.is_empty()
    }

    pub fn undo_count(&self) -> usize {
        self.undo_stack.len()
    }

    pub fn redo_count(&self) -> usize {
        self.redo_stack.len()
    }

    pub fn clear(&mut self) {
        self.undo_stack.clear();
        self.redo_stack.clear();
    }
}

impl Default for UndoManager {
    fn default() -> Self {
        Self::new(1000)
    }
}

fn apply_command(cmd: &mut EditCommand, session: &mut Session) {
    match cmd {
        EditCommand::AddRegion { track_id, region } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.add_region(region.clone());
            }
        }
        EditCommand::RemoveRegion {
            track_id,
            region_id,
            region,
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                *region = track.remove_region(*region_id);
            }
        }
        EditCommand::MoveRegion {
            track_id,
            region_id,
            new_pos,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.timeline_pos = *new_pos;
            }
        }
        EditCommand::MoveRegionToTrack {
            from_track,
            to_track,
            region_id,
            new_pos,
            region,
            ..
        } => {
            if let Some(track) = session.track_mut(*from_track) {
                *region = track.remove_region(*region_id);
            }
            if let Some(mut r) = region.clone() {
                r.timeline_pos = *new_pos;
                if let Some(track) = session.track_mut(*to_track) {
                    track.add_region(r);
                }
            }
        }
        EditCommand::SplitRegion {
            track_id,
            region_id,
            split_frame,
            original,
            left_id,
            right_id,
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region(*region_id)
            {
                let r_clone = r.clone();
                if let Some((left, right)) = r_clone.split_at(*split_frame) {
                    *left_id = Some(left.id);
                    *right_id = Some(right.id);
                    *original = track.remove_region(*region_id);
                    track.add_region(left);
                    track.add_region(right);
                }
            }
        }
        EditCommand::TrimStart {
            track_id,
            region_id,
            new_start,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.trim_start(*new_start);
            }
        }
        EditCommand::TrimEnd {
            track_id,
            region_id,
            new_end,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.trim_end(*new_end);
            }
        }
        EditCommand::SetFadeIn {
            track_id,
            region_id,
            new_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_in = *new_fade;
            }
        }
        EditCommand::SetFadeOut {
            track_id,
            region_id,
            new_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_out = *new_fade;
            }
        }
        EditCommand::SetRegionGain {
            track_id,
            region_id,
            new_gain,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.gain = *new_gain;
            }
        }
        EditCommand::SetTrackGain {
            track_id, new_gain, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.gain = *new_gain;
            }
        }
        EditCommand::SetTrackPan {
            track_id, new_pan, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.pan = *new_pan;
            }
        }
        EditCommand::ToggleTrackMute { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.muted = !track.muted;
            }
        }
        EditCommand::ToggleTrackSolo { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.solo = !track.solo;
            }
        }
        EditCommand::MoveTrack {
            from_index,
            to_index,
        } => {
            if *from_index < session.tracks.len() {
                let track = session.tracks.remove(*from_index);
                let actual_to = (*to_index).min(session.tracks.len());
                session.tracks.insert(actual_to, track);
            }
        }
        EditCommand::SetInstrumentParam {
            track_id,
            param_index,
            new_value,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(val) = track.instrument_params.get_mut(*param_index)
            {
                *val = *new_value;
            }
        }
        EditCommand::Compound { commands } => {
            for sub in commands.iter_mut() {
                apply_command(sub, session);
            }
        }
    }
}

fn reverse_command(cmd: &EditCommand, session: &mut Session) {
    match cmd {
        EditCommand::AddRegion { track_id, region } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.remove_region(region.id);
            }
        }
        EditCommand::RemoveRegion {
            track_id, region, ..
        } => {
            if let Some(r) = region
                && let Some(track) = session.track_mut(*track_id)
            {
                track.add_region(r.clone());
            }
        }
        EditCommand::MoveRegion {
            track_id,
            region_id,
            old_pos,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.timeline_pos = *old_pos;
            }
        }
        EditCommand::MoveRegionToTrack {
            from_track,
            to_track,
            region_id,
            old_pos,
            region,
            ..
        } => {
            if let Some(track) = session.track_mut(*to_track) {
                track.remove_region(*region_id);
            }
            if let Some(mut r) = region.clone() {
                r.timeline_pos = *old_pos;
                if let Some(track) = session.track_mut(*from_track) {
                    track.add_region(r);
                }
            }
        }
        EditCommand::SplitRegion {
            track_id,
            original,
            left_id,
            right_id,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                if let Some(lid) = left_id {
                    track.remove_region(*lid);
                }
                if let Some(rid) = right_id {
                    track.remove_region(*rid);
                }
                if let Some(orig) = original {
                    track.add_region(orig.clone());
                }
            }
        }
        EditCommand::TrimStart {
            track_id,
            region_id,
            old_start,
            old_offset,
            old_duration,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.timeline_pos = *old_start;
                r.source_offset = *old_offset;
                r.duration = *old_duration;
            }
        }
        EditCommand::TrimEnd {
            track_id,
            region_id,
            old_duration,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.duration = *old_duration;
            }
        }
        EditCommand::SetFadeIn {
            track_id,
            region_id,
            old_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_in = *old_fade;
            }
        }
        EditCommand::SetFadeOut {
            track_id,
            region_id,
            old_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_out = *old_fade;
            }
        }
        EditCommand::SetRegionGain {
            track_id,
            region_id,
            old_gain,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.gain = *old_gain;
            }
        }
        EditCommand::SetTrackGain {
            track_id, old_gain, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.gain = *old_gain;
            }
        }
        EditCommand::SetTrackPan {
            track_id, old_pan, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.pan = *old_pan;
            }
        }
        EditCommand::ToggleTrackMute { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.muted = !track.muted;
            }
        }
        EditCommand::ToggleTrackSolo { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.solo = !track.solo;
            }
        }
        EditCommand::MoveTrack {
            from_index,
            to_index,
        } => {
            // Reverse: move from to_index back to from_index
            let actual_to = (*to_index).min(session.tracks.len().saturating_sub(1));
            if actual_to < session.tracks.len() {
                let track = session.tracks.remove(actual_to);
                let actual_from = (*from_index).min(session.tracks.len());
                session.tracks.insert(actual_from, track);
            }
        }
        EditCommand::SetInstrumentParam {
            track_id,
            param_index,
            old_value,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(val) = track.instrument_params.get_mut(*param_index)
            {
                *val = *old_value;
            }
        }
        EditCommand::Compound { commands } => {
            for sub in commands.iter().rev() {
                reverse_command(sub, session);
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::edit::EditCommand;
    use crate::region::Region;
    use crate::session::Session;

    fn make_session_with_track() -> (Session, crate::track::TrackId) {
        let mut session = Session::new("Test", 48000, 256);
        let track_id = session.add_audio_track("Track 1");
        (session, track_id)
    }

    fn make_region(pos: u64, duration: u64) -> Region {
        Region::new("audio.wav".into(), pos, 0, duration)
    }

    // ---------------------------------------------------------------
    // 1. UndoManager creation and default state
    // ---------------------------------------------------------------

    #[test]
    fn test_new_undo_manager() {
        let um = UndoManager::new(50);
        assert!(!um.can_undo());
        assert!(!um.can_redo());
        assert_eq!(um.undo_count(), 0);
        assert_eq!(um.redo_count(), 0);
    }

    #[test]
    fn test_default_undo_manager() {
        let um = UndoManager::default();
        assert!(!um.can_undo());
        assert!(!um.can_redo());
        assert_eq!(um.max_history, 1000);
    }

    // ---------------------------------------------------------------
    // 2. Execute a command and undo it
    // ---------------------------------------------------------------

    #[test]
    fn test_execute_add_region_then_undo() {
        let (mut session, track_id) = make_session_with_track();
        let mut um = UndoManager::new(100);

        let region = make_region(0, 48000);
        let region_id = region.id;

        um.execute(
            EditCommand::AddRegion {
                track_id,
                region: region.clone(),
            },
            &mut session,
        );

        assert!(um.can_undo());
        assert_eq!(um.undo_count(), 1);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 1);

        // Undo: region should be removed
        assert!(um.undo(&mut session));
        assert!(!um.can_undo());
        assert!(um.can_redo());
        assert!(session.track(track_id).unwrap().region(region_id).is_none());
        assert_eq!(session.track(track_id).unwrap().regions.len(), 0);
    }

    // ---------------------------------------------------------------
    // 3. Execute multiple commands and undo/redo cycle
    // ---------------------------------------------------------------

    #[test]
    fn test_multiple_undo_redo_cycle() {
        let (mut session, track_id) = make_session_with_track();
        let mut um = UndoManager::new(100);

        let r1 = make_region(0, 1000);
        let r2 = make_region(2000, 500);
        let r1_id = r1.id;
        let r2_id = r2.id;

        um.execute(
            EditCommand::AddRegion {
                track_id,
                region: r1,
            },
            &mut session,
        );
        um.execute(
            EditCommand::AddRegion {
                track_id,
                region: r2,
            },
            &mut session,
        );

        assert_eq!(um.undo_count(), 2);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 2);

        // Undo second add
        um.undo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 1);
        assert!(session.track(track_id).unwrap().region(r2_id).is_none());

        // Undo first add
        um.undo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 0);

        // Redo first add
        um.redo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 1);
        assert!(session.track(track_id).unwrap().region(r1_id).is_some());

        // Redo second add
        um.redo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 2);
    }

    // ---------------------------------------------------------------
    // 4. Redo after undo
    // ---------------------------------------------------------------

    #[test]
    fn test_redo_restores_state() {
        let (mut session, track_id) = make_session_with_track();
        let mut um = UndoManager::new(100);

        let region = make_region(100, 500);
        let region_id = region.id;

        um.execute(
            EditCommand::AddRegion {
                track_id,
                region: region.clone(),
            },
            &mut session,
        );

        um.undo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 0);

        um.redo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 1);
        assert!(session.track(track_id).unwrap().region(region_id).is_some());
    }

    #[test]
    fn test_redo_returns_false_when_empty() {
        let (mut session, _) = make_session_with_track();
        let mut um = UndoManager::new(100);
        assert!(!um.redo(&mut session));
    }

    #[test]
    fn test_undo_returns_false_when_empty() {
        let (mut session, _) = make_session_with_track();
        let mut um = UndoManager::new(100);
        assert!(!um.undo(&mut session));
    }

    // ---------------------------------------------------------------
    // 5. Redo stack cleared after new command
    // ---------------------------------------------------------------

    #[test]
    fn test_redo_stack_cleared_on_new_command() {
        let (mut session, track_id) = make_session_with_track();
        let mut um = UndoManager::new(100);

        let r1 = make_region(0, 1000);
        um.execute(
            EditCommand::AddRegion {
                track_id,
                region: r1,
            },
            &mut session,
        );

        um.undo(&mut session);
        assert!(um.can_redo());

        // Execute a new command -- should clear redo stack
        let r2 = make_region(5000, 1000);
        um.execute(
            EditCommand::AddRegion {
                track_id,
                region: r2,
            },
            &mut session,
        );

        assert!(!um.can_redo());
        assert_eq!(um.redo_count(), 0);
    }

    // ---------------------------------------------------------------
    // 6. EditCommand variants
    // ---------------------------------------------------------------

    #[test]
    fn test_remove_region_command() {
        let (mut session, track_id) = make_session_with_track();
        let mut um = UndoManager::new(100);

        let region = make_region(0, 1000);
        let region_id = region.id;
        session.track_mut(track_id).unwrap().add_region(region);

        um.execute(
            EditCommand::RemoveRegion {
                track_id,
                region_id,
                region: None,
            },
            &mut session,
        );

        assert_eq!(session.track(track_id).unwrap().regions.len(), 0);

        // Undo: region should reappear
        um.undo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 1);
        assert!(session.track(track_id).unwrap().region(region_id).is_some());

        // Redo: remove again
        um.redo(&mut session);
        assert_eq!(session.track(track_id).unwrap().regions.len(), 0);
    }

    #[test]
    fn test_move_region_command() {
        let (mut session, track_id) = make_session_with_track();
        let mut um = UndoManager::new(100);

        let region = make_region(100, 500);
        let region_id = region.id;
        session.track_mut(track_id).unwrap().add_region(region);

        um.execute(
            EditCommand::MoveRegion {
                track_id,
                region_id,
                old_pos: 100,
                new_pos: 5000,
            },
            &mut session,
        );

        assert_eq!(
            session
                .track(track_id)
                .unwrap()
                .region(region_id)
                .unwrap()
                .timeline_pos,
            5000
        );

        // Undo
        um.undo(&mut session);
        assert_eq!(
            session
                .track(track_id)
                .unwrap()
                .region(region_id)
                .unwrap()
                .timeline_pos,
            100
        );

        // Redo
        um.redo(&mut session);
        assert_eq!(
            session
                .track(track_id)
                .unwrap()
                .region(region_id)
                .unwrap()
                .timeline_pos,
            5000
        );
    }

    #[test]
    fn test_move_region_to_track_command() {
        let mut session = Session::new("Test", 48000, 256);
        let track_a = session.add_audio_track("Track A");
        let track_b = session.add_audio_track("Track B");
        let mut um = UndoManager::new(100);

        let region = make_region(100, 500);
        let region_id = region.id;
        session.track_mut(track_a).unwrap().add_region(region);

        um.execute(
            EditCommand::MoveRegionToTrack {
                from_track: track_a,
                to_track: track_b,
                region_id,
                old_pos: 100,
                new_pos: 2000,
                region: None,
            },
            &mut session,
        );

        // Region should now be on track B at position 2000
        assert_eq!(session.track(track_a).unwrap().regions.len(), 0);
        assert_eq!(session.track(track_b).unwrap().regions.len(), 1);
        assert_eq!(
            session
                .track(track_b)
                .unwrap()
                .region(region_id)
                .unwrap()
                .timeline_pos,
            2000
        );

        // Undo: region back on track A at original position
        um.undo(&mut session);
        assert_eq!(session.track(track_a).unwrap().regions.len(), 1);
        assert_eq!(session.track(track_b).unwrap().regions.len(), 0);
        assert_eq!(
