use eframe::Frame;
use egui::{CentralPanel, Context, TopBottomPanel};

use crate::engine::AudioEngine;
use crate::input::{Action, ShortcutRegistry, default_keymap};
use crate::state::{UiState, ViewMode};
use crate::theme::{Theme, apply_theme};
use crate::views::settings::DeviceCache;
use crate::views::{arrangement, browser, mixer, settings, transport};

/// The main Shruti application.
pub struct ShrutiApp {
    state: UiState,
    theme: Theme,
    shortcuts: ShortcutRegistry,
    engine: Option<AudioEngine>,
    device_cache: DeviceCache,
}

impl ShrutiApp {
    pub fn new(state: UiState) -> Self {
        Self {
            state,
            theme: Theme::default(),
            shortcuts: default_keymap(),
            engine: None,
            device_cache: DeviceCache::new(),
        }
    }

    pub fn with_theme(mut self, theme: Theme) -> Self {
        self.theme = theme;
        self
    }

    fn handle_action(&mut self, action: Action) {
        use shruti_session::TransportState;

        match action {
            Action::Play => {
                self.state.session.transport.state = TransportState::Playing;
            }
            Action::Stop => {
                self.state.session.transport.state = TransportState::Stopped;
                self.state.recording = false;
            }
            Action::Pause => {
                self.state.session.transport.state = TransportState::Paused;
            }
            Action::Record => {
                if self.state.recording {
                    // Stop recording
                    self.state.recording = false;
                    if let Some(engine) = &mut self.engine
                        && let Some(samples) = engine.stop_recording()
                    {
                        let position = self.state.session.transport.position;
                        let channels = engine.recording_channels();
                        let frames = samples.len() / channels as usize;

                        if frames > 0 {
                            let buf = shruti_dsp::AudioBuffer::from_interleaved(samples, channels);
                            let recording_id = format!("recording_{}", uuid::Uuid::new_v4());
                            self.state
                                .session
                                .audio_pool
                                .insert(recording_id.clone(), buf);

                            // Add region to the first armed track
                            for track in &mut self.state.session.tracks {
                                if track.armed {
                                    let region = shruti_session::Region::new(
                                        recording_id.clone(),
                                        position,
                                        0,
                                        frames as u64,
                                    );
                                    track.add_region(region);
                                    break;
                                }
                            }
                        }
                    }
                } else {
                    // Start recording
                    if let Some(engine) = &mut self.engine
                        && engine.start_recording().is_ok()
                    {
                        self.state.recording = true;
                    }
                }
            }
            Action::ToggleLoop => {
                self.state.session.transport.loop_enabled =
                    !self.state.session.transport.loop_enabled;
            }
            Action::Rewind | Action::GoToStart => {
                self.state.session.transport.position = 0;
            }
            Action::GoToEnd => {
                self.state.session.transport.position = self.state.session.session_length();
            }
            Action::ToggleArrangement => {
                self.state.view_mode = ViewMode::Arrangement;
            }
            Action::ToggleMixer => {
                self.state.view_mode = ViewMode::Mixer;
            }
            Action::ToggleBrowser => {
                self.state.show_browser = !self.state.show_browser;
            }
            Action::ZoomIn => {
                self.state.pixels_per_frame *= 1.3;
            }
            Action::ZoomOut => {
                self.state.pixels_per_frame = (self.state.pixels_per_frame / 1.3).max(0.0001);
            }
            Action::NewAudioTrack => {
                let count = self.state.session.audio_tracks().len() + 1;
                self.state.session.add_audio_track(format!("Audio {count}"));
            }
            Action::ToggleMute => {
                if let Some(idx) = self.state.selected_track
                    && idx < self.state.session.tracks.len()
                {
                    self.state.session.tracks[idx].muted = !self.state.session.tracks[idx].muted;
                }
            }
            Action::ToggleSolo => {
                if let Some(idx) = self.state.selected_track
                    && idx < self.state.session.tracks.len()
                {
                    self.state.session.tracks[idx].solo = !self.state.session.tracks[idx].solo;
                }
            }
            Action::Undo => {
                self.state.undo.undo(&mut self.state.session);
            }
            Action::Redo => {
                self.state.undo.redo(&mut self.state.session);
            }
            Action::Delete => {
                if let (Some(track_idx), Some(region_id)) =
                    (self.state.selected_track, self.state.selected_region)
                    && track_idx < self.state.session.tracks.len()
                {
                    self.state.session.tracks[track_idx].remove_region(region_id);
                    self.state.selected_region = None;
                }
            }
            Action::NewBusTrack => {
                let count = self
                    .state
                    .session
                    .tracks
                    .iter()
                    .filter(|t| t.kind == shruti_session::TrackKind::Bus)
                    .count()
                    + 1;
                self.state.session.add_bus_track(format!("Bus {count}"));
            }
            Action::ToggleArm => {
                if let Some(idx) = self.state.selected_track
                    && idx < self.state.session.tracks.len()
                {
                    self.state.session.tracks[idx].armed = !self.state.session.tracks[idx].armed;
                }
            }
            Action::ZoomToFit => {
                let length = self.state.session.session_length();
                if length > 0 {
                    // Approximate with 1000px available width
                    self.state.pixels_per_frame = 1000.0 / length as f64;
                    self.state.scroll_x = 0.0;
                }
            }
            Action::FastForward => {
                let frames_per_beat = (self.state.session.sample_rate as f64 * 60.0)
                    / self.state.session.transport.bpm;
                let frames_per_bar =
                    frames_per_beat * self.state.session.transport.time_sig_num as f64;
                self.state.session.transport.position += frames_per_bar as u64;
            }
            Action::SplitAtPlayhead => {
                if let (Some(track_idx), Some(region_id)) =
                    (self.state.selected_track, self.state.selected_region)
                    && track_idx < self.state.session.tracks.len()
                {
                    let playhead = self.state.session.transport.position;
                    let track = &mut self.state.session.tracks[track_idx];
                    if let Some(region) = track.region(region_id).cloned()
                        && let Some((left, right)) = region.split_at(playhead)
                    {
                        track.remove_region(region_id);
                        track.add_region(left);
                        track.add_region(right);
                        self.state.selected_region = None;
                    }
                }
            }
            Action::Duplicate => {
                if let (Some(track_idx), Some(region_id)) =
                    (self.state.selected_track, self.state.selected_region)
                    && track_idx < self.state.session.tracks.len()
                {
                    let track = &self.state.session.tracks[track_idx];
                    if let Some(region) = track.region(region_id) {
                        let mut dup = region.clone();
                        dup.id = shruti_session::RegionId::new();
                        dup.timeline_pos = region.end_pos();
                        self.state.session.tracks[track_idx].add_region(dup);
                    }
                }
            }
            Action::NewSession => {
                self.state.session = shruti_session::Session::new("Untitled", 48000, 256);
                self.state.selected_track = None;
                self.state.selected_region = None;
            }
            Action::SaveSession => {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("Shruti Session", &["shruti"])
                    .save_file()
                {
                    let _ = shruti_session::store::SessionStore::create(&path, &self.state.session);
                }
            }
            Action::OpenSession => {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("Shruti Session", &["shruti"])
                    .pick_file()
                    && let Ok((_store, session)) = shruti_session::store::SessionStore::open(&path)
                {
                    self.state.session = session;
                    self.state.selected_track = None;
                    self.state.selected_region = None;
                }
            }
            Action::ExportAudio => {
                if let Some(path) = rfd::FileDialog::new()
                    .add_filter("WAV", &["wav"])
                    .save_file()
                {
                    let length = self.state.session.session_length();
                    if length > 0 {
                        let channels = 2u16;
                        let mut output = shruti_dsp::AudioBuffer::new(channels, length as u32);
                        let mut tl = shruti_session::Timeline::new(channels, length as u32);
                        tl.render(
                            &self.state.session.tracks,
                            &self.state.session.transport,
                            &self.state.session.audio_pool,
                            &mut output,
                        );
                        let format = shruti_dsp::AudioFormat::new(
                            self.state.session.sample_rate,
                            channels,
                            0,
                        );
                        let _ = shruti_dsp::io::write_wav_file(&path, &output, &format);
                    }
                }
            }
            Action::Cut => {
                if let (Some(track_idx), Some(region_id)) =
                    (self.state.selected_track, self.state.selected_region)
                    && track_idx < self.state.session.tracks.len()
                    && let Some(region) =
                        self.state.session.tracks[track_idx].remove_region(region_id)
                {
                    self.state.clipboard_region = Some(region);
                    self.state.selected_region = None;
                }
            }
            Action::Copy => {
                if let (Some(track_idx), Some(region_id)) =
                    (self.state.selected_track, self.state.selected_region)
                    && track_idx < self.state.session.tracks.len()
                    && let Some(region) = self.state.session.tracks[track_idx].region(region_id)
                {
                    let mut copy = region.clone();
                    copy.id = shruti_session::RegionId::new();
                    self.state.clipboard_region = Some(copy);
                }
            }
            Action::Paste => {
                if let Some(track_idx) = self.state.selected_track
                    && track_idx < self.state.session.tracks.len()
                    && let Some(ref clip) = self.state.clipboard_region
                {
                    let mut pasted = clip.clone();
                    pasted.id = shruti_session::RegionId::new();
                    pasted.timeline_pos = self.state.session.transport.position;
                    self.state.session.tracks[track_idx].add_region(pasted);
                }
            }
            Action::SelectAll => {
                if let Some(track_idx) = self.state.selected_track
                    && track_idx < self.state.session.tracks.len()
                    && let Some(first) = self.state.session.tracks[track_idx].regions.first()
                {
                    self.state.selected_region = Some(first.id);
                }
            }
        }
    }
}

impl eframe::App for ShrutiApp {
    fn update(&mut self, ctx: &Context, _frame: &mut Frame) {
        // Apply theme once
        if !self.state.theme_applied {
            apply_theme(ctx, &self.theme.colors);
            self.state.theme_applied = true;
        }

        // Handle keyboard shortcuts
        if let Some(action) = self.shortcuts.check_input(ctx) {
            self.handle_action(action);
        }

        // Handle scroll zoom in arrangement
        if self.state.view_mode == ViewMode::Arrangement {
            ctx.input(|input| {
                if input.modifiers.ctrl {
                    let scroll = input.raw_scroll_delta.y;
                    if scroll != 0.0 {
                        let factor = if scroll > 0.0 { 1.1 } else { 1.0 / 1.1 };
                        self.state.pixels_per_frame =
                            (self.state.pixels_per_frame * factor).clamp(0.00001, 1.0);
                    }
                } else {
                    // Horizontal scroll with shift or trackpad
                    let scroll_x = input.raw_scroll_delta.x - input.raw_scroll_delta.y;
                    self.state.scroll_x = (self.state.scroll_x - scroll_x as f64).max(0.0);
                }
            });
        }

        // Request continuous repaint during playback
        if self.state.session.transport.state == shruti_session::TransportState::Playing {
            ctx.request_repaint();
        }

        // Sync meter levels from the audio engine
        if let Some(ref engine) = self.engine {
            let peaks = engine.read_meters();
            self.state
                .meter_levels
                .resize(self.state.session.tracks.len(), ([0.0; 2], [0.0; 2]));
            for (i, level) in self.state.meter_levels.iter_mut().enumerate() {
                if let Some(&peak) = peaks.get(i) {
                    level.0 = peak; // peak L/R
                    level.1 = peak; // use peak as RMS approximation
                }
            }
        }

        let colors = self.theme.colors.clone();

        // Top: Transport bar
        TopBottomPanel::top("transport")
            .min_height(36.0)
            .show(ctx, |ui| {
                transport::transport_bar(ui, &mut self.state, &colors);
            });

        // Bottom: Browser (toggleable)
        if self.state.show_browser {
            TopBottomPanel::bottom("browser")
                .resizable(true)
                .default_height(180.0)
                .min_height(100.0)
                .show(ctx, |ui| {
                    browser::browser_panel(ui, &mut self.state, &colors);
                });
        }

        // Center: Arrangement or Mixer
        CentralPanel::default().show(ctx, |ui| {
            // View switcher bar
            ui.horizontal(|ui| {
                ui.spacing_mut().item_spacing.x = 2.0;

                if ui
                    .selectable_label(self.state.view_mode == ViewMode::Arrangement, "Arrangement")
                    .clicked()
                {
                    self.state.view_mode = ViewMode::Arrangement;
                }
                if ui
                    .selectable_label(self.state.view_mode == ViewMode::Mixer, "Mixer")
                    .clicked()
                {
                    self.state.view_mode = ViewMode::Mixer;
                }
                if ui
                    .selectable_label(self.state.view_mode == ViewMode::Settings, "Settings")
                    .clicked()
                {
                    self.state.view_mode = ViewMode::Settings;
                }

                ui.separator();

                // Quick-add track button
                if ui.small_button("+ Track").clicked() {
                    let count = self.state.session.audio_tracks().len() + 1;
                    self.state.session.add_audio_track(format!("Audio {count}"));
                }
            });

            ui.separator();

            match self.state.view_mode {
                ViewMode::Arrangement => {
                    arrangement::arrangement_view(ui, &mut self.state, &colors);
                }
                ViewMode::Mixer => {
                    mixer::mixer_view(ui, &mut self.state, &colors);
                }
                ViewMode::Settings => {
                    settings::settings_view(ui, &mut self.state, &colors, &mut self.device_cache);
                }
            }
        });
    }
}

use std::sync::{
    Arc, Mutex,
    atomic::{AtomicBool, AtomicU64, Ordering},
};

use shruti_dsp::{AudioBuffer, AudioFormat};

/// Type alias for the audio output callback closure.
type AudioCallback = Box<dyn FnMut(&mut [f32]) + Send + 'static>;
use shruti_engine::AudioStream;
use shruti_engine::backend::{AudioHost, CpalBackend};
use shruti_session::RecordingConfig;
use shruti_session::audio_pool::AudioPool;
use shruti_session::track::Track;
use shruti_session::{Session, Timeline, Transport};

/// Shared state between UI and audio thread via atomics.
pub struct SharedTransport {
    /// Current playback position in frames.
    pub position: AtomicU64,
    /// Whether playback is active.
    pub playing: AtomicBool,
    /// Whether recording is active.
    pub recording: AtomicBool,
}

impl Default for SharedTransport {
    fn default() -> Self {
        Self::new()
    }
}

impl SharedTransport {
    pub fn new() -> Self {
        Self {
            position: AtomicU64::new(0),
            playing: AtomicBool::new(false),
            recording: AtomicBool::new(false),
        }
    }
}

/// Shared session data for the audio thread.
/// The UI thread updates this; the audio thread reads it via `try_lock`.
pub struct SharedSessionData {
    pub tracks: Vec<Track>,
    pub audio_pool: Arc<AudioPool>,
    pub sample_rate: u32,
}

/// Audio engine controller — bridges the UI to real-time audio output.
///
/// Opens a cpal output stream and runs a `Timeline` renderer in the audio
/// callback.  Transport state (position, playing, recording) is shared with
/// the audio thread through lock-free atomics.  Session data (tracks and
/// audio pool) is shared through a `Mutex` that the audio thread only
/// `try_lock`s so it never blocks the real-time path.
pub struct AudioEngine {
    pub transport: Arc<SharedTransport>,
    session_data: Arc<Mutex<SharedSessionData>>,
    _output_stream: Option<Box<dyn AudioStream>>,
    _input_stream: Option<Box<dyn AudioStream>>,
    /// Peak levels: Vec of (peak_left, peak_right) per track slot.
    /// The last slot is the master / mixed output.
    pub meter_levels: Arc<Mutex<Vec<[f32; 2]>>>,
    /// Accumulates incoming audio from the input callback during recording.
    record_buffer: Arc<Mutex<Vec<f32>>>,
    /// Sample rate used by this engine instance.
    sample_rate: u32,
    /// Recording configuration (sample rate, channels, max duration).
    recording_config: RecordingConfig,
}

impl AudioEngine {
    /// Create a new `AudioEngine` and start the output stream.
    ///
    /// Returns `Err` if the audio backend cannot be initialised (e.g. no
    /// audio device available — common in CI).
    pub fn new(
        session: &Session,
        audio_pool: Arc<AudioPool>,
    ) -> Result<Self, Box<dyn std::error::Error>> {
        let transport = Arc::new(SharedTransport::new());
        let meter_levels: Arc<Mutex<Vec<[f32; 2]>>> =
            Arc::new(Mutex::new(vec![[0.0; 2]; session.tracks.len() + 1]));

        let session_data = Arc::new(Mutex::new(SharedSessionData {
            tracks: session.tracks.clone(),
            audio_pool,
            sample_rate: session.sample_rate,
        }));

        let backend = CpalBackend::new();
        let format = AudioFormat::new(session.sample_rate, 2, session.buffer_size);

        let transport_cb = Arc::clone(&transport);
        let session_data_cb = Arc::clone(&session_data);
        let meter_levels_cb = Arc::clone(&meter_levels);

        let callback = Self::build_callback(transport_cb, session_data_cb, meter_levels_cb);

        let stream = backend.open_output_stream(None, format, callback)?;
        stream.start()?;

        Ok(Self {
            transport,
            session_data,
            _output_stream: Some(stream),
            _input_stream: None,
            meter_levels,
            record_buffer: Arc::new(Mutex::new(Vec::new())),
            sample_rate: session.sample_rate,
            recording_config: RecordingConfig::default(),
        })
    }

    /// Build the audio output callback closure.
    fn build_callback(
        transport: Arc<SharedTransport>,
        session_data: Arc<Mutex<SharedSessionData>>,
        meter_levels: Arc<Mutex<Vec<[f32; 2]>>>,
    ) -> AudioCallback {
        // Per-callback scratch state — lives inside the closure, no locking needed.
        let mut timeline: Option<Timeline> = None;
        let mut render_buf: Option<AudioBuffer> = None;

        Box::new(move |output: &mut [f32]| {
            let is_playing = transport.playing.load(Ordering::Acquire);

            if !is_playing {
                output.fill(0.0);
                return;
            }

            let position = transport.position.load(Ordering::Acquire);
            let channels: u16 = 2;
            let frames = (output.len() / channels as usize) as u32;

            // Try to lock session data — if the UI thread holds the lock, output silence
            // rather than blocking the audio thread.
            let Ok(data) = session_data.try_lock() else {
                output.fill(0.0);
                return;
            };

            // Lazily initialise (or resize) scratch buffers.
            let tl = timeline.get_or_insert_with(|| Timeline::new(channels, frames));
            let buf = render_buf.get_or_insert_with(|| AudioBuffer::new(channels, frames));

            // Recreate if frame count changed (cpal may call us with varying sizes).
            if buf.frames() != frames {
                *tl = Timeline::new(channels, frames);
                *buf = AudioBuffer::new(channels, frames);
            }

            // Build a temporary transport snapshot for the renderer.
            let mut render_transport = Transport::new(data.sample_rate);
            render_transport.position = position;

            tl.render(&data.tracks, &render_transport, &data.audio_pool, buf);

            // Copy rendered audio into the output slice.
            let interleaved = buf.as_interleaved();
            let copy_len = output.len().min(interleaved.len());
            output[..copy_len].copy_from_slice(&interleaved[..copy_len]);
            if copy_len < output.len() {
                output[copy_len..].fill(0.0);
            }

            // Compute master peak levels from the mixed output.
            if let Ok(mut levels) = meter_levels.try_lock() {
                let mut peak_l: f32 = 0.0;
                let mut peak_r: f32 = 0.0;
                for i in (0..copy_len).step_by(channels as usize) {
                    peak_l = peak_l.max(output[i].abs());
                    if i + 1 < copy_len {
                        peak_r = peak_r.max(output[i + 1].abs());
                    }
                }
                if let Some(last) = levels.last_mut() {
                    *last = [peak_l, peak_r];
                }
            }

            // Advance playback position.
            let new_pos = position + frames as u64;
            transport.position.store(new_pos, Ordering::Release);
        })
    }

    // -- Transport controls ---------------------------------------------------

    /// Start playback from the current position.
    pub fn play(&self) {
        self.transport.playing.store(true, Ordering::Release);
    }

    /// Stop playback and reset position to zero.
    pub fn stop(&self) {
        self.transport.position.store(0, Ordering::Release);
        self.transport.playing.store(false, Ordering::Release);
    }

    /// Pause playback (keeps the current position).
    pub fn pause(&self) {
        self.transport.playing.store(false, Ordering::Release);
    }

    /// Seek to a frame position.
    pub fn seek(&self, position: u64) {
        self.transport.position.store(position, Ordering::Release);
    }

    /// Current playback position in frames.
    pub fn position(&self) -> u64 {
        self.transport.position.load(Ordering::Acquire)
    }

    /// Whether playback is currently active.
    pub fn is_playing(&self) -> bool {
        self.transport.playing.load(Ordering::Acquire)
    }

    // -- Session data updates -------------------------------------------------

    /// Push updated track/pool data to the audio thread.
    ///
    /// Call this after any change to tracks or the audio pool.
    pub fn update_session(&self, session: &Session, audio_pool: Arc<AudioPool>) {
        let new_track_count = session.tracks.len();
        if let Ok(mut data) = self.session_data.lock() {
            data.tracks = session.tracks.clone();
            data.audio_pool = audio_pool;
            data.sample_rate = session.sample_rate;
            // Resize meter levels while still holding session_data lock so the
            // audio thread never sees mismatched track count vs meter slots.
            if let Ok(mut levels) = self.meter_levels.lock() {
                levels.resize(new_track_count + 1, [0.0; 2]);
            }
        }
    }

    // -- Metering -------------------------------------------------------------

    /// Read current peak meter levels.
    ///
    /// Returns a `Vec` with one `[left, right]` pair per track; the last
    /// entry is the master output.
    pub fn read_meters(&self) -> Vec<[f32; 2]> {
        self.meter_levels
            .lock()
            .map(|l| l.clone())
            .unwrap_or_default()
    }

    // -- Recording ------------------------------------------------------------

    /// The sample rate this engine was initialised with.
    pub fn sample_rate(&self) -> u32 {
        self.sample_rate
    }

    /// Set the recording configuration.
    ///
    /// Must be called before `start_recording()`. Values are validated
    /// (clamped to supported ranges) on assignment.
    pub fn set_recording_config(&mut self, config: RecordingConfig) {
        self.recording_config = config.validated();
    }

    /// Get the current recording configuration.
    pub fn recording_config(&self) -> &RecordingConfig {
        &self.recording_config
    }

    /// The recording sample rate (may differ from playback sample rate).
    pub fn recording_sample_rate(&self) -> u32 {
        self.recording_config.sample_rate
    }

    /// The number of recording channels.
    pub fn recording_channels(&self) -> u16 {
        self.recording_config.channels
    }

    /// Start capturing audio from the configured input device.
    ///
    /// Uses the recording config for sample rate, channel count, and buffer
    /// limits. Clears the internal record buffer and opens an input stream
    /// whose callback appends incoming samples.
    pub fn start_recording(&mut self) -> Result<(), Box<dyn std::error::Error>> {
        self.transport.recording.store(true, Ordering::Release);

        let max_samples = self.recording_config.max_buffer_samples();
        let rec_channels = self.recording_config.channels;
        let rec_sample_rate = self.recording_config.sample_rate;
        let rec_buffer_size = self.recording_config.buffer_size;

        // Pre-allocate buffer for ~10 seconds to reduce early reallocations
        let pre_alloc = (rec_sample_rate as usize * rec_channels as usize * 10).min(max_samples);
        if let Ok(mut buf) = self.record_buffer.lock() {
            buf.clear();
            buf.reserve(pre_alloc);
        }

        let record_buf = Arc::clone(&self.record_buffer);
        let backend = CpalBackend::new();
        let format = AudioFormat::new(rec_sample_rate, rec_channels, rec_buffer_size);
        let device_name = self.recording_config.input_device.clone();

        let callback: shruti_engine::backend::InputCallback = Box::new(move |data: &[f32]| {
            if let Ok(mut buf) = record_buf.try_lock() {
                let remaining = max_samples.saturating_sub(buf.len());
                let to_copy = data.len().min(remaining);
                if to_copy > 0 {
                    buf.extend_from_slice(&data[..to_copy]);
                }
            }
        });

        let stream = backend.open_input_stream(device_name.as_deref(), format, callback)?;
        stream.start()?;
        self._input_stream = Some(stream);

        Ok(())
    }

    /// Stop recording and return the captured audio samples.
    ///
    /// Drops the input stream and drains the record buffer. Returns `None`
    /// if no samples were captured. The caller should use
    /// `recording_channels()` and `recording_sample_rate()` to interpret
    /// the returned interleaved sample data.
    pub fn stop_recording(&mut self) -> Option<Vec<f32>> {
        self.transport.recording.store(false, Ordering::Release);
        self._input_stream = None; // Drop the stream, stopping capture

        if let Ok(mut buf) = self.record_buffer.lock() {
            if buf.is_empty() {
                return None;
            }
            Some(std::mem::take(&mut *buf))
        } else {
            None
        }
    }
}

