        assert_eq!(reg.lookup(&Shortcut::key(Key::Space)), Some(Action::Stop));
    }

    #[test]
    fn multiple_bindings() {
        let mut reg = ShortcutRegistry::new();
        reg.bind(Shortcut::key(Key::Space), Action::Play);
        reg.bind(Shortcut::key(Key::Enter), Action::Stop);
        reg.bind(Shortcut::ctrl(Key::Z), Action::Undo);

        assert_eq!(reg.lookup(&Shortcut::key(Key::Space)), Some(Action::Play));
        assert_eq!(reg.lookup(&Shortcut::key(Key::Enter)), Some(Action::Stop));
        assert_eq!(reg.lookup(&Shortcut::ctrl(Key::Z)), Some(Action::Undo));
    }
}

//! GPU-accelerated DAW interface for Shruti.
//!
//! Built on egui + eframe (wgpu + winit), providing a cross-platform
//! immediate-mode UI with custom-painted DAW widgets.

pub mod app;
pub mod engine;
pub mod input;
pub mod state;
pub mod theme;
pub mod views;
pub mod widgets;

pub use app::ShrutiApp;
pub use state::UiState;
pub use theme::Theme;

/// Launch the Shruti GUI.
pub fn run(session: shruti_session::Session) -> Result<(), eframe::Error> {
    let options = eframe::NativeOptions {
        viewport: egui::ViewportBuilder::default()
            .with_title("Shruti")
            .with_inner_size([1280.0, 800.0])
            .with_min_inner_size([800.0, 500.0]),
        ..Default::default()
    };

    eframe::run_native(
        "Shruti",
        options,
        Box::new(|_cc| {
            let state = UiState::new(session);
            Ok(Box::new(ShrutiApp::new(state)))
        }),
    )
}

/// Launch the Shruti GUI with a custom theme.
pub fn run_with_theme(session: shruti_session::Session, theme: Theme) -> Result<(), eframe::Error> {
    let options = eframe::NativeOptions {
        viewport: egui::ViewportBuilder::default()
            .with_title("Shruti")
            .with_inner_size([1280.0, 800.0])
            .with_min_inner_size([800.0, 500.0]),
        ..Default::default()
    };

    eframe::run_native(
        "Shruti",
        options,
        Box::new(move |_cc| {
            let state = UiState::new(session);
            Ok(Box::new(ShrutiApp::new(state).with_theme(theme)))
        }),
    )
}

use shruti_session::undo::UndoManager;
use shruti_session::{Region, RegionId, Session};

use crate::views::browser::BrowserTab;

/// Describes an active drag operation in the arrangement view.
#[derive(Debug, Clone)]
pub enum ArrangementDrag {
    /// Dragging a region to a new timeline position (and possibly a different track).
    MoveRegion {
        region_id: RegionId,
        track_index: usize,
        start_frame: u64,
        /// X offset from region left edge to mouse position at drag start.
        grab_offset_px: f32,
    },
    /// Resizing a region from the left edge (trim start).
    TrimStart {
        region_id: RegionId,
        track_index: usize,
        original_pos: u64,
        original_offset: u64,
        original_duration: u64,
    },
    /// Resizing a region from the right edge (trim end).
    TrimEnd {
        region_id: RegionId,
        track_index: usize,
        original_duration: u64,
    },
    /// Dragging a track header to reorder.
    ReorderTrack {
        from_index: usize,
        current_index: usize,
    },
}

/// Represents a scanned plugin in the browser.
#[derive(Debug, Clone)]
pub struct PluginEntry {
    pub name: String,
    pub format: String,
    pub path: String,
}

/// Which main view is active.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ViewMode {
    Arrangement,
    Mixer,
    Settings,
}

/// All mutable UI state bridging the session/engine to the views.
pub struct UiState {
    /// The current session being edited.
    pub session: Session,

    // View state
    pub view_mode: ViewMode,
    pub show_browser: bool,
    pub browser_tab: BrowserTab,

    // Arrangement state
    pub scroll_x: f64,
    pub pixels_per_frame: f64,
    pub selected_track: Option<usize>,
    pub selected_region: Option<RegionId>,
    /// Active drag operation in the arrangement view.
    pub drag: Option<ArrangementDrag>,

    // Transport
    pub recording: bool,

    // Meter data (from engine): (peak_lr, rms_lr) per track
    pub meter_levels: Vec<([f32; 2], [f32; 2])>,

    // Browser state
    pub file_entries: Vec<String>,
    pub plugin_entries: Vec<PluginEntry>,
    pub plugin_search: String,

    /// Whether the theme has been applied.
    pub theme_applied: bool,

    /// Undo/redo manager.
    pub undo: UndoManager,

    /// Clipboard for cut/copy/paste of regions.
    pub clipboard_region: Option<Region>,
}

impl UiState {
    pub fn new(session: Session) -> Self {
        let track_count = session.tracks.len();
        Self {
            session,
            view_mode: ViewMode::Arrangement,
            show_browser: true,
            browser_tab: BrowserTab::Files,
            scroll_x: 0.0,
            pixels_per_frame: 0.01, // ~480 pixels per second at 48kHz
            selected_track: None,
            selected_region: None,
            drag: None,
            recording: false,
            meter_levels: vec![([0.0; 2], [0.0; 2]); track_count],
            file_entries: Vec::new(),
            plugin_entries: Vec::new(),
            plugin_search: String::new(),
            theme_applied: false,
            undo: UndoManager::default(),
            clipboard_region: None,
        }
    }
}

