use egui::{CornerRadius, Ui, vec2};

use crate::theme::ThemeColors;

/// A plugin slot in a channel strip or track inspector.
pub struct PluginSlotState {
    pub name: String,
    pub bypassed: bool,
}

pub struct PluginSlotResponse {
    pub clicked: bool,
    pub bypass_toggled: bool,
}

/// Draw a plugin slot widget.
pub fn plugin_slot_ui(
    ui: &mut Ui,
    state: &PluginSlotState,
    colors: &ThemeColors,
) -> PluginSlotResponse {
    let mut response = PluginSlotResponse {
        clicked: false,
        bypass_toggled: false,
    };

    ui.horizontal(|ui| {
        // Bypass indicator
        let bypass_color = if state.bypassed {
            colors.mute_orange()
        } else {
            colors.transport_active()
        };
        let bypass_btn = ui.add(
            egui::Button::new(
                egui::RichText::new(if state.bypassed { "○" } else { "●" })
                    .size(10.0)
                    .color(bypass_color),
            )
            .fill(colors.surface())
            .corner_radius(CornerRadius::same(2))
            .min_size(vec2(16.0, 16.0)),
        );
        if bypass_btn.clicked() {
            response.bypass_toggled = true;
        }

        // Plugin name button
        let name_btn = ui.add(
            egui::Button::new(egui::RichText::new(&state.name).size(10.0).color(
                if state.bypassed {
                    colors.text_secondary()
                } else {
                    colors.text_primary()
                },
            ))
            .fill(colors.surface())
            .corner_radius(CornerRadius::same(2))
            .min_size(vec2(80.0, 16.0)),
        );
        if name_btn.clicked() {
            response.clicked = true;
        }
    });

    response
}

use egui::{CornerRadius, Rect, Stroke, Ui, pos2, vec2};

use crate::theme::ThemeColors;
use crate::widgets::track_header::track_color;

/// Draw a region/clip rectangle on the timeline.
pub fn draw_region(
    ui: &mut Ui,
    rect: Rect,
    name: &str,
    color_index: usize,
    selected: bool,
    colors: &ThemeColors,
) {
    if rect.width() < 1.0 {
        return;
    }

    let painter = ui.painter_at(rect);
    let rounding = CornerRadius::same(3);

    // Region background
    let base_color = track_color(color_index);
    let bg = if selected {
        colors.region_selected()
    } else {
        base_color.linear_multiply(0.3)
    };
    painter.rect_filled(rect, rounding, bg);

    // Border
    let border_color = if selected {
        colors.accent()
    } else {
        base_color.linear_multiply(0.6)
    };
    painter.rect_stroke(
        rect,
        rounding,
        Stroke::new(1.0, border_color),
        egui::StrokeKind::Outside,
    );

    // Top accent bar
    let top_bar = Rect::from_min_size(rect.min, vec2(rect.width(), 2.0));
    painter.rect_filled(top_bar, CornerRadius::ZERO, base_color.linear_multiply(0.7));

    // Name label (clipped to region bounds)
    if rect.width() > 30.0 {
        let text_rect = rect.shrink2(vec2(4.0, 2.0));
        let text_pos = pos2(text_rect.left(), text_rect.top() + 2.0);
        painter.text(
            text_pos,
            egui::Align2::LEFT_TOP,
            name,
            egui::FontId::new(9.0, egui::FontFamily::Proportional),
            colors.text_primary(),
        );
    }
}

use egui::{Rect, Stroke, Ui, pos2};

use crate::theme::ThemeColors;

/// Draw a timeline ruler showing bars/beats or time.
pub fn draw_ruler(
    ui: &mut Ui,
    rect: Rect,
    scroll_offset: f64,
    pixels_per_frame: f64,
    sample_rate: u32,
    bpm: f64,
    colors: &ThemeColors,
) {
    let painter = ui.painter_at(rect);

    // Background
    painter.rect_filled(rect, 0.0, colors.bg_secondary());

    // Bottom border
    painter.line_segment(
        [rect.left_bottom(), rect.right_bottom()],
        Stroke::new(1.0, colors.separator()),
    );

    let frames_per_beat = (sample_rate as f64 * 60.0) / bpm;
    let frames_per_bar = frames_per_beat * 4.0; // Assuming 4/4
    let pixels_per_bar = frames_per_bar * pixels_per_frame;

    // Determine tick spacing based on zoom
    let (major_interval, minor_interval, label_fn): (f64, f64, Box<dyn Fn(i64) -> String>) =
        if pixels_per_bar > 200.0 {
            // Show beats
            (
                frames_per_bar,
                frames_per_beat,
                Box::new(move |frame: i64| {
                    let bar = (frame as f64 / frames_per_bar).floor() as i64 + 1;
                    format!("{bar}")
                }),
            )
        } else if pixels_per_bar > 40.0 {
            // Show bars
            (
                frames_per_bar,
                frames_per_bar,
                Box::new(move |frame: i64| {
                    let bar = (frame as f64 / frames_per_bar).floor() as i64 + 1;
                    format!("{bar}")
                }),
            )
        } else {
            // Show every N bars
            let bar_skip = (80.0 / pixels_per_bar).ceil() as i64;
            let major = frames_per_bar * bar_skip as f64;
            (
                major,
                frames_per_bar,
                Box::new(move |frame: i64| {
                    let bar = (frame as f64 / frames_per_bar).floor() as i64 + 1;
                    format!("{bar}")
                }),
            )
        };

    // Visible frame range
    let start_frame = (scroll_offset / pixels_per_frame) as i64;
    let end_frame = start_frame + (rect.width() as f64 / pixels_per_frame) as i64;

    // Minor ticks
    let minor_start = (start_frame as f64 / minor_interval).floor() as i64;
    let minor_end = (end_frame as f64 / minor_interval).ceil() as i64;

    for i in minor_start..=minor_end {
        let frame = (i as f64 * minor_interval) as i64;
        let x = rect.left() + (frame as f64 * pixels_per_frame - scroll_offset) as f32;
        if x >= rect.left() && x <= rect.right() {
            painter.line_segment(
                [pos2(x, rect.bottom() - 4.0), pos2(x, rect.bottom())],
                Stroke::new(0.5, colors.text_secondary()),
            );
        }
    }

    // Major ticks with labels
    let major_start = (start_frame as f64 / major_interval).floor() as i64;
    let major_end = (end_frame as f64 / major_interval).ceil() as i64;

    for i in major_start..=major_end {
        let frame = (i as f64 * major_interval) as i64;
        let x = rect.left() + (frame as f64 * pixels_per_frame - scroll_offset) as f32;
        if x >= rect.left() && x <= rect.right() {
            painter.line_segment(
                [pos2(x, rect.bottom() - 10.0), pos2(x, rect.bottom())],
                Stroke::new(1.0, colors.text_secondary()),
            );

            let label = label_fn(frame);
            painter.text(
                pos2(x + 3.0, rect.top() + 2.0),
                egui::Align2::LEFT_TOP,
                label,
                egui::FontId::new(9.0, egui::FontFamily::Proportional),
                colors.text_secondary(),
            );
        }
    }
}

use egui::{Color32, CornerRadius, Layout, Ui, vec2};

use crate::theme::ThemeColors;

/// Track header state for the UI.
pub struct TrackHeaderState {
    pub name: String,
    pub muted: bool,
    pub solo: bool,
    pub armed: bool,
    pub selected: bool,
    pub color_index: usize,
}

/// Track color palette (10 colors, cycling).
const TRACK_COLORS: [Color32; 10] = [
    Color32::from_rgb(70, 130, 210),  // Blue
    Color32::from_rgb(80, 180, 100),  // Green
    Color32::from_rgb(200, 100, 60),  // Orange
    Color32::from_rgb(170, 80, 190),  // Purple
    Color32::from_rgb(200, 180, 50),  // Yellow
    Color32::from_rgb(80, 190, 190),  // Cyan
    Color32::from_rgb(210, 80, 100),  // Red
    Color32::from_rgb(130, 180, 70),  // Lime
    Color32::from_rgb(180, 130, 80),  // Tan
    Color32::from_rgb(120, 100, 200), // Indigo
];

pub fn track_color(index: usize) -> Color32 {
    TRACK_COLORS[index % TRACK_COLORS.len()]
}

/// Draw a track header, returning which buttons were clicked.
#[derive(Default)]
pub struct TrackHeaderResponse {
    pub mute_clicked: bool,
    pub solo_clicked: bool,
    pub arm_clicked: bool,
    pub selected: bool,
}

impl TrackHeaderState {
    /// Create a new track header state with defaults.
    pub fn new(name: impl Into<String>, color_index: usize) -> Self {
        Self {
            name: name.into(),
            muted: false,
            solo: false,
            armed: false,
            selected: false,
            color_index,
        }
    }
}

pub fn track_header_ui(
    ui: &mut Ui,
    state: &TrackHeaderState,
    colors: &ThemeColors,
    width: f32,
) -> TrackHeaderResponse {
    let mut response = TrackHeaderResponse {
        mute_clicked: false,
        solo_clicked: false,
        arm_clicked: false,
        selected: false,
    };

    let height = 60.0;
    let (rect, click_response) = ui.allocate_exact_size(vec2(width, height), egui::Sense::click());

    if click_response.clicked() {
        response.selected = true;
    }

    if ui.is_rect_visible(rect) {
        let painter = ui.painter_at(rect);

        // Background
        let bg = if state.selected {
            colors.accent().linear_multiply(0.15)
        } else {
            colors.track_header()
        };
        painter.rect_filled(rect, 0.0, bg);

        // Color strip on left edge
        let strip_rect = rect.with_max_x(rect.left() + 4.0);
        painter.rect_filled(strip_rect, 0.0, track_color(state.color_index));

        // Bottom separator
        painter.line_segment(
            [rect.left_bottom(), rect.right_bottom()],
            egui::Stroke::new(0.5, colors.separator()),
        );
    }

    // UI inside the header
    let inner_rect = rect.shrink2(vec2(8.0, 4.0));
    let mut child_ui = ui.new_child(egui::UiBuilder::new().max_rect(inner_rect));

    child_ui.with_layout(Layout::top_down(egui::Align::LEFT), |ui| {
        // Track name
        ui.label(
            egui::RichText::new(&state.name)
                .size(11.0)
                .color(colors.text_primary()),
        );

        ui.add_space(2.0);

        // M S R buttons
        ui.horizontal(|ui| {
            ui.spacing_mut().item_spacing.x = 2.0;

            // Mute button
            let mute_color = if state.muted {
                colors.mute_orange()
            } else {
                colors.surface()
            };
            let mute_btn = ui.add(
                egui::Button::new(egui::RichText::new("M").size(10.0).color(if state.muted {
                    Color32::WHITE
                } else {
                    colors.text_secondary()
                }))
                .fill(mute_color)
                .corner_radius(CornerRadius::same(2))
                .min_size(vec2(20.0, 16.0)),
            );
            if mute_btn.clicked() {
                response.mute_clicked = true;
            }

            // Solo button
            let solo_color = if state.solo {
                colors.solo_yellow()
            } else {
                colors.surface()
            };
            let solo_btn = ui.add(
                egui::Button::new(egui::RichText::new("S").size(10.0).color(if state.solo {
                    Color32::BLACK
                } else {
                    colors.text_secondary()
                }))
                .fill(solo_color)
                .corner_radius(CornerRadius::same(2))
                .min_size(vec2(20.0, 16.0)),
            );
            if solo_btn.clicked() {
                response.solo_clicked = true;
            }

            // Record arm button
            let arm_color = if state.armed {
                colors.record_red()
            } else {
                colors.surface()
            };
            let arm_btn = ui.add(
                egui::Button::new(egui::RichText::new("R").size(10.0).color(if state.armed {
                    Color32::WHITE
                } else {
                    colors.text_secondary()
                }))
                .fill(arm_color)
                .corner_radius(CornerRadius::same(2))
                .min_size(vec2(20.0, 16.0)),
            );
            if arm_btn.clicked() {
                response.arm_clicked = true;
            }
        });
    });

    response
}

